INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Million Dollar Chicken Casserole','million-dollar-chicken-casserole','A rich and creamy baked chicken casserole loaded with cream cheese and buttery crackers. It tastes like a million bucks with minimal effort.','Creamy chicken casserole topped with crunchy buttery crackers baked to golden perfection.','American','Easy',15,35,50,6,520,34,22,34,1,'[{"amount":3,"unit":"cups","item":"shredded rotisserie chicken","group":"main"},{"amount":8,"unit":"oz","item":"cream cheese softened","group":"filling"},{"amount":1,"unit":"cup","item":"sour cream","group":"filling"},{"amount":1,"unit":"can","item":"cream of chicken soup","group":"filling"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"onion powder","group":"seasoning"},{"amount":1.5,"unit":"cups","item":"crushed buttery crackers","group":"topping"},{"amount":4,"unit":"tbsp","item":"melted butter","group":"topping"}]','[{"title":"Preheat and Prep","text":"Preheat oven to 350 degrees F. Grease a 9x13 inch baking dish with nonstick spray.","timer":0},{"title":"Make the Filling","text":"In a large bowl mix together cream cheese, sour cream, cream of chicken soup, garlic powder, and onion powder until smooth.","timer":0},{"title":"Add Chicken","text":"Fold the shredded chicken into the creamy mixture until evenly coated. Spread into the prepared baking dish.","timer":0},{"title":"Add Topping","text":"Combine crushed crackers with melted butter in a small bowl. Sprinkle evenly over the chicken mixture.","timer":0},{"title":"Bake","text":"Bake uncovered for 30 to 35 minutes until bubbly around the edges and the cracker topping is golden brown.","timer":2100}]','[{"original":"sour cream","swap":"plain Greek yogurt"},{"original":"buttery crackers","swap":"panko breadcrumbs mixed with butter"},{"original":"cream of chicken soup","swap":"cream of mushroom soup"}]','["Using cold cream cheese causes lumpy filling so always soften it first","Covering the dish while baking makes the cracker topping soggy","Skipping the greased dish causes the casserole to stick and fall apart"]','["casserole","chicken","comfort food","easy dinner","creamy"]','["gluten-free optional"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Neiman Marcus Chicken','neiman-marcus-chicken','A legendary baked chicken dish layered with crispy bacon, a creamy cheesy topping, and a touch of sweetness. This upscale comfort food lives up to its fancy name.','Baked chicken breasts topped with a luscious mixture of cream cheese, bacon, and cheddar.','American','Easy',10,30,40,4,610,48,4,45,0,'[{"amount":4,"unit":"pieces","item":"boneless skinless chicken breasts","group":"main"},{"amount":8,"unit":"oz","item":"cream cheese softened","group":"topping"},{"amount":1,"unit":"cup","item":"shredded cheddar cheese","group":"topping"},{"amount":6,"unit":"strips","item":"bacon cooked and crumbled","group":"topping"},{"amount":0.5,"unit":"cup","item":"mayonnaise","group":"topping"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Preheat Oven","text":"Preheat oven to 375 degrees F. Lightly grease a baking dish large enough to hold all four chicken breasts in a single layer.","timer":0},{"title":"Season Chicken","text":"Season chicken breasts on both sides with salt, pepper, and garlic powder. Place into the prepared baking dish.","timer":0},{"title":"Make the Topping","text":"In a bowl stir together softened cream cheese, mayonnaise, shredded cheddar, and crumbled bacon until well combined.","timer":0},{"title":"Top the Chicken","text":"Spread the cream cheese mixture generously over each chicken breast, covering the tops completely.","timer":0},{"title":"Bake Until Done","text":"Bake for 25 to 30 minutes until chicken reaches an internal temperature of 165 degrees F and the topping is golden and bubbling.","timer":1800}]','[{"original":"cheddar cheese","swap":"Monterey Jack or Colby cheese"},{"original":"mayonnaise","swap":"sour cream for a tangier flavor"},{"original":"bacon","swap":"turkey bacon for a lighter option"}]','["Using chicken breasts straight from the fridge leads to uneven cooking so bring them to room temperature first","Spreading too thin a layer of topping results in dry chicken without the signature richness","Overbaking dries out the chicken so always use a meat thermometer to check doneness"]','["chicken","baked","bacon","cream cheese","keto friendly","easy"]','["keto","low-carb","gluten-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cowboy Butter Spaghetti','cowboy-butter-spaghetti','A bold and buttery pasta dish loaded with garlic, herbs, lemon, and a hint of heat inspired by classic cowboy butter sauce. It comes together in under 30 minutes for a weeknight dinner that packs serious flavor.','Garlicky herbed butter sauce tossed with spaghetti for a fast and flavor-packed pasta dinner.','American','Easy',10,15,25,4,540,14,68,24,3,'[{"amount":12,"unit":"oz","item":"spaghetti","group":"main"},{"amount":6,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":5,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"red pepper flakes","group":"sauce"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice","group":"sauce"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"},{"amount":1,"unit":"tsp","item":"Dijon mustard","group":"sauce"},{"amount":0.5,"unit":"cup","item":"reserved pasta water","group":"sauce"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of salted water to a boil. Cook spaghetti according to package directions until al dente. Reserve half a cup of pasta water before draining.","timer":600},{"title":"Make the Cowboy Butter","text":"In a large skillet melt butter over medium heat. Add minced garlic and red pepper flakes and cook for 1 to 2 minutes until fragrant but do not let the garlic brown.","timer":120},{"title":"Build the Sauce","text":"Stir in Dijon mustard and lemon juice into the butter mixture. Add reserved pasta water a splash at a time to create a silky emulsified sauce.","timer":60},{"title":"Toss the Pasta","text":"Add drained spaghetti directly into the skillet. Toss vigorously with tongs to coat every strand evenly with the cowboy butter sauce.","timer":0},{"title":"Garnish and Serve","text":"Remove from heat and top with fresh chopped parsley. Serve immediately with extra lemon wedges and parmesan if desired.","timer":0}]','[{"original":"spaghetti","swap":"linguine or fettuccine"},{"original":"fresh lemon juice","swap":"white wine for a deeper flavor"},{"original":"red pepper flakes","swap":"cayenne pepper for more intense heat"}]','["Draining all the pasta water leaves the sauce too thick and unable to coat the noodles properly","Browning the garlic instead of gently softening it creates a bitter flavor in the final dish","Skipping the Dijon mustard removes the emulsifying agent that keeps the butter sauce smooth"]','["pasta","butter sauce","quick dinner","garlic","spicy","weeknight"]','["vegetarian"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Tuscan Chicken Pasta','creamy-tuscan-chicken-pasta','Sun-dried tomatoes, spinach, and garlic swim in a rich parmesan cream sauce alongside tender chicken and penne pasta. This Italian-inspired dish feels restaurant quality but is easy enough for any home cook.','Tender chicken and penne tossed in a rich sun-dried tomato and spinach cream sauce.','Italian-American','Medium',10,25,35,4,680,42,58,28,4,'[{"amount":12,"unit":"oz","item":"penne pasta","group":"main"},{"amount":2,"unit":"pieces","item":"boneless skinless chicken breasts sliced thin","group":"main"},{"amount":1,"unit":"cup","item":"heavy cream","group":"sauce"},{"amount":0.5,"unit":"cup","item":"grated parmesan cheese","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":0.5,"unit":"cup","item":"sun-dried tomatoes in oil drained and chopped","group":"sauce"},{"amount":2,"unit":"cups","item":"fresh baby spinach","group":"sauce"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"sauce"}]','[{"title":"Cook the Pasta","text":"Cook penne in heavily salted boiling water until al dente. Reserve one cup of pasta water then drain and set aside.","timer":600},{"title":"Sear the Chicken","text":"Heat olive oil in a large skillet over medium-high heat. Season chicken slices with salt and pepper and cook for 3 to 4 minutes per side until golden. Remove and set aside.","timer":480},{"title":"Build the Sauce","text":"In the same skillet reduce heat to medium and add garlic. Cook for 30 seconds then stir in sun-dried tomatoes and heavy cream. Simmer for 3 minutes.","timer":180},{"title":"Finish the Sauce","text":"Add parmesan and stir until melted and smooth. Fold in spinach and let it wilt for about 1 minute. Return chicken to the skillet and stir to combine.","timer":60},{"title":"Combine and Serve","text":"Add drained penne to the skillet and toss everything together. Use reserved pasta water to loosen the sauce if needed. Serve hot with extra parmesan on top.","timer":0}]','[{"original":"heavy cream","swap":"half and half for a lighter sauce"},{"original":"penne pasta","swap":"rigatoni or farfalle"},{"original":"fresh spinach","swap":"frozen spinach thawed and squeezed dry"}]','["Cooking the cream sauce on high heat causes it to break and become greasy rather than velvety","Not reserving pasta water means you cannot adjust the sauce consistency at the end","Overcooking the chicken before adding it back to the sauce makes it rubbery and dry"]','["pasta","chicken","creamy","tuscan","sun-dried tomatoes","spinach"]','["gluten-free optional"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Butter Shrimp','honey-garlic-butter-shrimp','Plump shrimp are coated in a sticky sweet and savory honey garlic butter glaze that comes together in just 15 minutes. Serve over rice or noodles for a complete meal that the whole family will love.','Juicy shrimp glazed in a quick honey garlic butter sauce ready in 15 minutes.','Asian-American','Easy',5,10,15,4,310,28,18,14,1,'[{"amount":1.5,"unit":"lbs","item":"large shrimp peeled and deveined","group":"main"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":3,"unit":"tbsp","item":"honey","group":"sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"fresh lemon juice","group":"sauce"},{"amount":1,"unit":"tsp","item":"red pepper flakes","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"chopped fresh parsley","group":"garnish"}]','[{"title":"Pat Shrimp Dry","text":"Pat shrimp thoroughly dry with paper towels. This step is critical for getting a good sear rather than steaming the shrimp.","timer":0},{"title":"Sear the Shrimp","text":"Melt 2 tablespoons of butter in a large skillet over medium-high heat. Add shrimp in a single layer and cook for 1 minute per side until pink. Remove and set aside.","timer":120},{"title":"Make the Sauce","text":"In the same skillet melt remaining butter over medium heat. Add garlic and red pepper flakes and cook for 30 seconds. Stir in honey, soy sauce, and lemon juice.","timer":60},{"title":"Glaze the Shrimp","text":"Return shrimp to the skillet and toss to coat in the honey garlic sauce. Cook for 1 additional minute until the sauce thickens slightly and clings to the shrimp.","timer":60},{"title":"Garnish and Serve","text":"Remove from heat and sprinkle with fresh parsley. Serve immediately over steamed rice or noodles for a complete meal.","timer":0}]','[{"original":"honey","swap":"maple syrup for a slightly different sweetness"},{"original":"soy sauce","swap":"coconut aminos for a gluten-free option"},{"original":"fresh lemon juice","swap":"rice vinegar for an Asian-style tang"}]','["Skipping the step of patting shrimp dry causes them to steam instead of sear and results in rubbery texture","Overcooking shrimp even by 30 seconds makes them tough so remove them the moment they curl into a C shape","Crowding the pan drops the temperature and prevents proper caramelization of the honey glaze"]','["shrimp","quick dinner","honey garlic","seafood","weeknight","gluten-free optional"]','["gluten-free optional","dairy-free optional"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Stick of Butter Chicken and Rice','stick-of-butter-chicken-and-rice','A rich and comforting one-pan dish where a full stick of butter melts into tender chicken and fluffy rice. The butter creates a deeply savory sauce that soaks into every grain of rice.','One-pan chicken and rice cooked low and slow in a full stick of rich melted butter.','American','Easy',10,60,70,4,620,38,52,28,1,'[{"amount":4,"unit":"pieces","item":"bone-in skin-on chicken thighs","group":"main"},{"amount":1,"unit":"stick","item":"unsalted butter","group":"main"},{"amount":1.5,"unit":"cups","item":"long grain white rice","group":"main"},{"amount":2,"unit":"cups","item":"chicken broth","group":"liquid"},{"amount":1,"unit":"can","item":"cream of chicken soup","group":"sauce"},{"amount":1,"unit":"packet","item":"dry onion soup mix","group":"seasoning"},{"amount":1,"unit":"teaspoon","item":"garlic powder","group":"seasoning"},{"amount":0.5,"unit":"teaspoon","item":"black pepper","group":"seasoning"}]','[{"title":"Preheat and Prep","text":"Preheat your oven to 350 degrees F. Spread the uncooked rice evenly across the bottom of a 9x13 inch baking dish.","timer":0},{"title":"Mix the Sauce","text":"In a bowl, whisk together the chicken broth and cream of chicken soup until smooth. Pour this mixture evenly over the rice in the baking dish.","timer":0},{"title":"Season and Place Chicken","text":"Sprinkle the dry onion soup mix, garlic powder, and black pepper over the rice and broth mixture. Place the chicken thighs skin side up on top of the rice.","timer":0},{"title":"Add the Butter","text":"Slice the full stick of butter into pats and place them evenly over the chicken pieces and along the edges of the dish. Do not stir anything together.","timer":0},{"title":"Bake Covered then Uncovered","text":"Cover tightly with foil and bake for 45 minutes. Remove the foil and bake for another 15 minutes until the chicken skin is golden and the rice has absorbed all liquid.","timer":3600}]','[{"original":"cream of chicken soup","swap":"cream of mushroom soup for a deeper earthy flavor"},{"original":"bone-in chicken thighs","swap":"boneless chicken breasts but reduce cook time by 10 minutes"},{"original":"dry onion soup mix","swap":"1 teaspoon each of onion powder, salt, and dried parsley"}]','["Removing the foil too early which causes the rice to dry out before it finishes cooking","Using thin or low-sodium broth which results in bland and watery rice","Stirring the ingredients together in the pan which prevents the rice from steaming properly"]','["comfort food","one pan","baked chicken","easy dinner","family meal"]','["gluten-free adaptable"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Swamp Potatoes and Sausage','swamp-potatoes-and-sausage','A hearty Southern-inspired skillet dish loaded with tender potatoes and smoky andouille sausage cooked in a dark savory gravy. Bold Cajun spices give this dish its signature swampy depth of flavor.','Smoky andouille sausage and fork-tender potatoes smothered in a bold Cajun gravy.','Southern American','Easy',10,35,45,4,540,22,48,29,4,'[{"amount":1,"unit":"pound","item":"andouille sausage sliced into rounds","group":"protein"},{"amount":4,"unit":"medium","item":"russet potatoes cubed","group":"main"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"vegetables"},{"amount":1,"unit":"medium","item":"green bell pepper diced","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"cups","item":"chicken broth","group":"liquid"},{"amount":2,"unit":"tablespoons","item":"Cajun seasoning","group":"seasoning"},{"amount":2,"unit":"tablespoons","item":"vegetable oil","group":"fat"},{"amount":1,"unit":"tablespoon","item":"Worcestershire sauce","group":"seasoning"}]','[{"title":"Brown the Sausage","text":"Heat the vegetable oil in a large deep skillet over medium-high heat. Add the andouille sausage rounds and cook for 3 to 4 minutes per side until deeply browned. Remove the sausage and set aside.","timer":480},{"title":"Saute the Vegetables","text":"In the same skillet with the rendered sausage fat, add the onion and bell pepper. Cook for 5 minutes until softened, then add the garlic and cook for 1 more minute.","timer":360},{"title":"Add Potatoes and Season","text":"Add the cubed potatoes to the skillet and sprinkle in the Cajun seasoning. Stir everything together to coat the potatoes in the spices and fat.","timer":0},{"title":"Simmer in Broth","text":"Pour in the chicken broth and Worcestershire sauce. Stir to combine, then bring to a boil. Reduce heat to medium-low, cover, and simmer for 20 minutes until the potatoes are fork tender.","timer":1200},{"title":"Return Sausage and Reduce","text":"Return the browned sausage to the skillet and stir to combine. Cook uncovered for 5 more minutes to allow the gravy to thicken slightly before serving.","timer":300}]','[{"original":"andouille sausage","swap":"smoked kielbasa for a milder less spicy version"},{"original":"russet potatoes","swap":"Yukon gold potatoes which hold their shape better during simmering"},{"original":"Cajun seasoning","swap":"Creole seasoning with a pinch of cayenne for similar heat"}]','["Cutting the potatoes too large which leads to uneven cooking and hard centers","Not browning the sausage first which causes you to miss the essential fond that builds the gravy flavor","Keeping the heat too high while simmering which breaks down the potatoes into mush"]','["Cajun","skillet meal","sausage","potatoes","one pot","Southern"]','["dairy-free","gluten-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Turkish Pasta','turkish-pasta','A bold and satisfying Turkish dish featuring pasta topped with garlicky yogurt sauce and a sizzling spiced butter drizzle. It is simple to make but delivers a complex layering of tangy, rich, and smoky flavors.','Warm pasta smothered in garlic yogurt and finished with paprika-spiced brown butter.','Turkish','Easy',10,20,30,4,480,16,58,22,2,'[{"amount":12,"unit":"ounces","item":"penne or fusilli pasta","group":"main"},{"amount":2,"unit":"cups","item":"full fat plain Greek yogurt","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":4,"unit":"tablespoons","item":"unsalted butter","group":"butter sauce"},{"amount":2,"unit":"teaspoons","item":"smoked paprika","group":"butter sauce"},{"amount":1,"unit":"teaspoon","item":"red pepper flakes","group":"butter sauce"},{"amount":1,"unit":"teaspoon","item":"salt","group":"seasoning"},{"amount":2,"unit":"tablespoons","item":"fresh mint or parsley chopped","group":"garnish"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of heavily salted water to a boil. Cook the pasta according to package directions until al dente. Reserve half a cup of pasta water before draining.","timer":900},{"title":"Prepare the Garlic Yogurt","text":"While the pasta cooks, mix the Greek yogurt with the minced garlic and salt in a large bowl. Stir well and let it sit at room temperature so it warms slightly before being used.","timer":0},{"title":"Make the Spiced Butter","text":"Melt the butter in a small saucepan over medium heat. Cook until the butter turns golden and smells nutty, about 3 minutes. Remove from heat and immediately stir in the smoked paprika and red pepper flakes.","timer":180},{"title":"Combine Pasta and Yogurt","text":"Add the hot drained pasta to the yogurt mixture and toss quickly to coat. If the mixture seems too thick, add a splash of the reserved pasta water and toss again.","timer":0},{"title":"Plate and Drizzle","text":"Divide the yogurt pasta into bowls. Spoon the hot spiced butter generously over the top of each bowl and garnish with fresh mint or parsley. Serve immediately.","timer":0}]','[{"original":"Greek yogurt","swap":"full fat regular plain yogurt strained through a cheesecloth for 30 minutes"},{"original":"penne pasta","swap":"rigatoni or any short ridged pasta that holds the yogurt sauce well"},{"original":"smoked paprika","swap":"sweet paprika plus a small pinch of cumin for a similar warm flavor"}]','["Using cold yogurt straight from the fridge which causes it to curdle when mixed with hot pasta","Skipping the reserved pasta water which is essential for loosening the thick yogurt coating","Letting the spiced butter sit too long before drizzling which causes the paprika to burn and turn bitter"]','["Turkish","pasta","yogurt","vegetarian","quick dinner","Mediterranean"]','["vegetarian"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Shrimp Pasta','garlic-butter-shrimp-pasta','A classic and elegant dish of plump shrimp tossed with spaghetti in a silky garlic butter white wine sauce. It comes together in under 30 minutes and tastes like a restaurant meal made at home.','Juicy shrimp and spaghetti in a quick silky garlic butter and white wine sauce.','Italian American','Easy',10,15,25,4,520,32,54,18,2,'[{"amount":1,"unit":"pound","item":"large shrimp peeled and deveined","group":"protein"},{"amount":12,"unit":"ounces","item":"spaghetti","group":"main"},{"amount":5,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":4,"unit":"tablespoons","item":"unsalted butter","group":"fat"},{"amount":0.5,"unit":"cup","item":"dry white wine","group":"liquid"},{"amount":0.5,"unit":"cup","item":"pasta cooking water","group":"liquid"},{"amount":1,"unit":"teaspoon","item":"red pepper flakes","group":"seasoning"},{"amount":0.25,"unit":"cup","item":"fresh parsley chopped","group":"garnish"},{"amount":0.5,"unit":"cup","item":"grated Parmesan cheese","group":"garnish"}]','[{"title":"Cook the Pasta","text":"Cook the spaghetti in a large pot of salted boiling water until al dente according to package directions. Reserve one cup of pasta water and drain the rest.","timer":900},{"title":"Saute the Garlic","text":"In a large skillet over medium heat, melt 2 tablespoons of butter. Add the minced garlic and red pepper flakes and cook for 1 to 2 minutes until fragrant. Do not let the garlic brown.","timer":120},{"title":"Cook the Shrimp","text":"Increase the heat to medium-high and add the shrimp in a single layer. Cook for 1 to 2 minutes per side until pink and curled. Remove the shrimp from the pan and set aside.","timer":240},{"title":"Build the Sauce","text":"Pour the white wine into the pan and scrape up any browned bits from the bottom. Let it simmer for 2 minutes, then add the remaining butter and half a cup of the reserved pasta water. Stir until a silky emulsified sauce forms.","timer":120},{"title":"Toss and Serve","text":"Add the cooked pasta and shrimp back to the pan and toss everything together over low heat. Add more pasta water as needed to loosen the sauce. Finish with Parmesan and fresh parsley before serving.","timer":0}]','[{"original":"dry white wine","swap":"additional pasta water plus a squeeze of fresh lemon juice for acidity"},{"original":"spaghetti","swap":"linguine or bucatini which pair equally well with seafood sauces"},{"original":"Parmesan cheese","swap":"Pecorino Romano for a saltier and sharper finish"}]','["Overcooking the shrimp by leaving them in the pan too long which makes them rubbery and tough","Discarding all the pasta water before reserving some which is critical for emulsifying the butter sauce","Cooking the garlic on heat that is too high which causes it to burn and turn the whole dish bitter"]','["pasta","shrimp","seafood","garlic butter","quick dinner","Italian American"]','["pescatarian"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Sriracha Glazed Meatballs','honey-sriracha-glazed-meatballs','Tender baked meatballs coated in a sweet and spicy honey Sriracha glaze that caramelizes into a sticky irresistible finish. These work equally well as an appetizer or served over rice for a complete meal.','Juicy baked meatballs tossed in a sticky sweet and spicy honey Sriracha glaze.','Asian American','Medium',15,25,40,4,460,28,38,20,1,'[{"amount":1,"unit":"pound","item":"ground pork or beef","group":"protein"},{"amount":0.5,"unit":"cup","item":"panko breadcrumbs","group":"binder"},{"amount":1,"unit":"large","item":"egg","group":"binder"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":0.33,"unit":"cup","item":"honey","group":"glaze"},{"amount":3,"unit":"tablespoons","item":"Sriracha sauce","group":"glaze"},{"amount":2,"unit":"tablespoons","item":"soy sauce","group":"glaze"},{"amount":1,"unit":"tablespoon","item":"rice vinegar","group":"glaze"},{"amount":2,"unit":"teaspoons","item":"sesame seeds","group":"garnish"}]','[{"title":"Make the Meatball Mixture","text":"Preheat the oven to 400 degrees F and line a baking sheet with parchment paper. In a large bowl, combine the ground meat, panko, egg, garlic, and a pinch of salt. Mix until just combined and do not overwork the meat.","timer":0},{"title":"Form and Bake","text":"Roll the mixture into 1.5 inch meatballs and place them evenly spaced on the prepared baking sheet. Bake for 18 to 20 minutes until cooked through and lightly browned on the outside.","timer":1200},{"title":"Make the Glaze","text":"While the meatballs bake, combine the honey, Sriracha, soy sauce, and rice vinegar in a small saucepan over medium heat. Stir and simmer for 3 to 4 minutes until the glaze thickens slightly.","timer":240},{"title":"Coat the Meatballs","text":"Transfer the hot baked meatballs into a large bowl. Pour the warm glaze over the meatballs and toss gently until every meatball is fully coated in the sticky sauce.","timer":0},{"title":"Garnish and Serve","text":"Transfer the glazed meatballs to a serving platter and sprinkle with sesame seeds and sliced green onion if desired. Serve immediately over steamed rice or as an appetizer with toothpicks.","timer":0}]','[{"original":"Sriracha sauce","swap":"sambal oelek for a chunkier less sweet heat"},{"original":"ground pork","swap":"ground chicken or turkey for a lighter lower fat version"},{"original":"panko breadcrumbs","swap":"regular plain breadcrumbs though the texture will be slightly denser"}]','["Overmixing the meat mixture which compresses the proteins and results in dense chewy meatballs","Making the meatballs too large which causes the outside to overbrown before the inside is fully cooked","Adding the glaze while the meatballs are still on the baking sheet which causes the sugar to burn on the hot pan"]','["meatballs","appetizer","sweet and spicy","Asian fusion","party food","meal prep"]','["dairy-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sheet Pan Gnocchi with Sausage','sheet-pan-gnocchi-with-sausage','Crispy baked gnocchi roasted alongside savory Italian sausage and colorful vegetables on a single pan. This effortless weeknight dinner delivers bold flavors with minimal cleanup.','One-pan roasted gnocchi with Italian sausage and vegetables ready in 40 minutes.','Italian-American','Easy',10,30,40,4,520,22,58,24,4,'[{"amount":16,"unit":"oz","item":"shelf-stable potato gnocchi","group":"Main"},{"amount":12,"unit":"oz","item":"Italian sausage links sliced","group":"Main"},{"amount":1,"unit":"pint","item":"cherry tomatoes","group":"Vegetables"},{"amount":1,"unit":"medium","item":"zucchini diced","group":"Vegetables"},{"amount":1,"unit":"medium","item":"red bell pepper sliced","group":"Vegetables"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"Seasoning"}]','[{"title":"Preheat and Prep","text":"Preheat your oven to 425 degrees F. Line a large rimmed sheet pan with parchment paper or lightly grease it with cooking spray.","timer":0},{"title":"Combine Ingredients","text":"Add the gnocchi, sliced sausage, cherry tomatoes, zucchini, and bell pepper to the sheet pan. Drizzle with olive oil and sprinkle with Italian seasoning, garlic powder, salt, and pepper. Toss everything together until evenly coated.","timer":0},{"title":"Spread and Roast","text":"Spread the mixture into a single even layer across the sheet pan, making sure the gnocchi are not overlapping. Place in the preheated oven and roast for 15 minutes.","timer":900},{"title":"Flip and Continue Roasting","text":"Remove the pan from the oven and use a spatula to toss and flip everything. Return to the oven and roast for another 12 to 15 minutes until the gnocchi are golden and crispy and the sausage is cooked through.","timer":840},{"title":"Serve","text":"Remove from the oven and let cool for 2 minutes. Garnish with fresh basil or grated Parmesan if desired and serve directly from the pan.","timer":120}]','[{"original":"Italian sausage","swap":"chicken sausage or plant-based sausage"},{"original":"zucchini","swap":"yellow squash or asparagus"},{"original":"shelf-stable gnocchi","swap":"refrigerated fresh gnocchi"}]','["Overcrowding the pan which causes the gnocchi to steam instead of crisp","Skipping the flip halfway through which results in uneven browning","Using fresh gnocchi without patting it dry which leads to soggy results"]','["sheet pan","weeknight dinner","sausage","gnocchi","one pan"]','["dairy-free option"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Butter Shrimp Skillet','lemon-butter-shrimp-skillet','Plump shrimp seared in a rich lemon butter sauce with garlic and fresh herbs in one skillet. This elegant yet simple dish comes together in under 20 minutes.','Garlicky lemon butter shrimp cooked in one skillet in just 15 minutes.','American','Easy',5,10,15,4,280,28,4,17,0,'[{"amount":1.5,"unit":"lbs","item":"large shrimp peeled and deveined","group":"Main"},{"amount":4,"unit":"tbsp","item":"unsalted butter divided","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"whole","item":"lemon zested and juiced","group":"Sauce"},{"amount":0.25,"unit":"cup","item":"dry white wine or chicken broth","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"Garnish"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"Seasoning"}]','[{"title":"Season the Shrimp","text":"Pat the shrimp dry with paper towels and season with salt, black pepper, and red pepper flakes. Dry shrimp sear much better than wet shrimp.","timer":0},{"title":"Sear the Shrimp","text":"Heat 2 tablespoons of butter in a large skillet over medium-high heat until foamy. Add the shrimp in a single layer and cook for 1 to 2 minutes per side until pink and just opaque. Do not overcook. Remove shrimp and set aside.","timer":120},{"title":"Build the Sauce","text":"Reduce heat to medium and add the remaining 2 tablespoons of butter to the same skillet. Add the minced garlic and cook for 30 seconds until fragrant. Pour in the white wine or broth and lemon juice, scraping up any browned bits from the pan.","timer":90},{"title":"Simmer and Combine","text":"Let the sauce simmer for 2 to 3 minutes until it reduces slightly. Add the lemon zest and stir to combine. Return the shrimp to the pan and toss to coat in the sauce for 30 seconds.","timer":180},{"title":"Garnish and Serve","text":"Remove from heat and sprinkle with fresh parsley. Serve immediately over rice, pasta, or with crusty bread to soak up the sauce.","timer":0}]','[{"original":"dry white wine","swap":"chicken broth or vegetable broth"},{"original":"fresh parsley","swap":"fresh chives or basil"},{"original":"unsalted butter","swap":"ghee or dairy-free butter"}]','["Cooking wet shrimp which causes steaming instead of searing","Overcooking the shrimp past the point when they curl into a C shape","Adding garlic to a very hot pan which causes it to burn and turn bitter"]','["shrimp","skillet","quick dinner","seafood","lemon butter"]','["gluten-free","low-carb"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Beef and Broccoli Stir Fry','beef-and-broccoli-stir-fry','Tender sliced beef and crisp broccoli florets tossed in a savory umami-rich sauce better than takeout. This classic Chinese-American dish is ready in 30 minutes from start to finish.','Classic beef and broccoli stir fry in a savory sauce ready in 30 minutes.','Chinese-American','Medium',15,15,30,4,380,32,22,18,3,'[{"amount":1.25,"unit":"lbs","item":"flank steak thinly sliced against the grain","group":"Main"},{"amount":4,"unit":"cups","item":"broccoli florets","group":"Vegetables"},{"amount":0.33,"unit":"cup","item":"low-sodium soy sauce","group":"Sauce"},{"amount":3,"unit":"tbsp","item":"oyster sauce","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"cornstarch divided","group":"Thickener"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"Aromatics"},{"amount":2,"unit":"tbsp","item":"sesame oil","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"vegetable oil","group":"Cooking"},{"amount":0.5,"unit":"cup","item":"beef broth","group":"Sauce"}]','[{"title":"Marinate the Beef","text":"In a bowl, combine the sliced beef with 1 tablespoon cornstarch, 1 tablespoon soy sauce, and 1 tablespoon sesame oil. Toss to coat and let marinate for 10 minutes while you prep the other ingredients.","timer":600},{"title":"Make the Sauce","text":"In a small bowl, whisk together the remaining soy sauce, oyster sauce, beef broth, remaining cornstarch, and remaining sesame oil. Set aside. This sauce goes in fast so having it ready is important.","timer":0},{"title":"Cook the Broccoli","text":"Heat 1 tablespoon vegetable oil in a large wok or skillet over high heat. Add the broccoli and stir fry for 3 to 4 minutes until bright green and slightly tender. Remove and set aside.","timer":240},{"title":"Sear the Beef","text":"Add the remaining oil to the wok and heat until smoking. Add the beef in a single layer and sear without stirring for 1 minute. Add garlic and ginger, then stir fry everything together for another 1 to 2 minutes until beef is browned.","timer":180},{"title":"Combine and Finish","text":"Return the broccoli to the wok and pour the sauce over everything. Toss and stir fry for 1 to 2 minutes until the sauce thickens and coats all the ingredients. Serve immediately over steamed white rice.","timer":120}]','[{"original":"flank steak","swap":"sirloin steak or skirt steak"},{"original":"oyster sauce","swap":"hoisin sauce for a slightly sweeter flavor"},{"original":"broccoli","swap":"broccolini or snap peas"}]','["Slicing the beef with the grain instead of against it which makes it chewy","Using a pan that is not hot enough which steams the beef instead of searing it","Skipping the cornstarch marinade step which helps tenderize the beef through velveting"]','["stir fry","beef","broccoli","Chinese","takeout at home"]','["dairy-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Margherita Pizza','classic-margherita-pizza','A traditional Neapolitan-style pizza topped with crushed tomatoes, fresh mozzarella, and fragrant basil on a crisp homemade dough. Simple quality ingredients make this a timeless favorite.','Homemade Margherita pizza with fresh mozzarella and basil baked to perfection.','Italian','Medium',20,15,35,4,420,18,52,16,3,'[{"amount":1,"unit":"lb","item":"store-bought or homemade pizza dough","group":"Base"},{"amount":0.75,"unit":"cup","item":"crushed San Marzano tomatoes","group":"Sauce"},{"amount":8,"unit":"oz","item":"fresh mozzarella cheese sliced","group":"Toppings"},{"amount":0.25,"unit":"cup","item":"fresh basil leaves","group":"Toppings"},{"amount":2,"unit":"tbsp","item":"extra virgin olive oil divided","group":"Seasoning"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":0.5,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.25,"unit":"tsp","item":"dried oregano","group":"Seasoning"}]','[{"title":"Preheat the Oven","text":"Place a pizza stone or inverted baking sheet in the oven and preheat to 500 degrees F for at least 30 minutes. A very hot oven is essential for a crispy crust.","timer":1800},{"title":"Prepare the Sauce","text":"In a small bowl, mix the crushed tomatoes with the minced garlic, 1 tablespoon olive oil, salt, and dried oregano. Stir to combine and set aside. Do not cook the sauce as it will cook on the pizza.","timer":0},{"title":"Shape the Dough","text":"On a lightly floured surface, stretch or roll the pizza dough into a 12-inch round. Transfer to a piece of parchment paper. Work gently and do not use a rolling pin if you want an airy crust.","timer":0},{"title":"Top the Pizza","text":"Spread the tomato sauce evenly over the dough leaving a 1-inch border. Arrange the fresh mozzarella slices over the sauce. Drizzle with the remaining olive oil.","timer":0},{"title":"Bake and Finish","text":"Slide the pizza on its parchment onto the hot stone or pan. Bake for 12 to 15 minutes until the crust is golden and the cheese is bubbling. Remove from oven and immediately top with fresh basil leaves before serving.","timer":840}]','[{"original":"fresh mozzarella","swap":"low-moisture shredded mozzarella for a less wet result"},{"original":"San Marzano tomatoes","swap":"any good quality crushed tomatoes"},{"original":"store-bought dough","swap":"flatbread or naan for a quick shortcut"}]','["Not preheating the oven and stone long enough which results in a pale and doughy crust","Adding too much sauce which makes the center of the pizza soggy","Adding fresh basil before baking which causes it to burn and turn black"]','["pizza","Italian","vegetarian","baking","margherita"]','["vegetarian"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Tuscan White Bean Soup','creamy-tuscan-white-bean-soup','A hearty and comforting Italian-inspired soup packed with white beans, wilted spinach, and sun-dried tomatoes in a savory broth. This nourishing bowl is ready in under 35 minutes and deeply satisfying.','Rich and creamy Tuscan white bean soup with spinach and sun-dried tomatoes in 35 minutes.','Italian','Easy',10,25,35,6,310,14,42,10,11,'[{"amount":2,"unit":"cans","item":"cannellini beans drained and rinsed","group":"Main"},{"amount":3,"unit":"cups","item":"fresh baby spinach","group":"Vegetables"},{"amount":0.33,"unit":"cup","item":"sun-dried tomatoes in oil chopped","group":"Vegetables"},{"amount":4,"unit":"cups","item":"vegetable or chicken broth","group":"Base"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"Aromatics"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":0.5,"unit":"cup","item":"heavy cream or coconut cream","group":"Creaminess"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"Cooking"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"salt and pepper to taste","group":"Seasoning"}]','[{"title":"Saute the Aromatics","text":"Heat olive oil in a large pot over medium heat. Add the diced onion and cook for 4 to 5 minutes until softened and translucent. Add the minced garlic and cook for another 30 seconds until fragrant.","timer":330},{"title":"Add Tomatoes and Seasoning","text":"Stir in the chopped sun-dried tomatoes and Italian seasoning. Cook for 2 minutes to allow the flavors to bloom and the tomato oil to coat the aromatics.","timer":120},{"title":"Add Beans and Broth","text":"Pour in the broth and add the drained cannellini beans. Stir everything together and bring to a gentle boil. Reduce heat and simmer for 12 to 15 minutes.","timer":840},{"title":"Blend and Cream","text":"Use an immersion blender to partially blend the soup, pureeing about one third of it to create a creamy thick texture while leaving chunks. Stir in the heavy cream and season with salt and pepper.","timer":0},{"title":"Add Spinach and Serve","text":"Add the baby spinach and stir until wilted, about 1 to 2 minutes. Ladle into bowls and serve with crusty bread. Garnish with Parmesan and a drizzle of olive oil if desired.","timer":120}]','[{"original":"cannellini beans","swap":"great northern beans or navy beans"},{"original":"heavy cream","swap":"coconut cream for a dairy-free version"},{"original":"baby spinach","swap":"chopped kale or Swiss chard"}]','["Blending the entire soup instead of just part of it which removes all the texture","Skipping the partial blend step and ending up with a thin brothy soup instead of creamy","Adding the spinach too early and cooking it down to mush instead of a bright wilted texture"]','["soup","white bean","Tuscan","vegetarian option","comfort food"]','["vegetarian","gluten-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('One Pot Creamy Sun Dried Tomato Pasta','one-pot-creamy-sun-dried-tomato-pasta','A rich and satisfying pasta dish made entirely in one pot with sun dried tomatoes and a velvety cream sauce. It comes together in under 30 minutes with minimal cleanup.','Creamy one pot pasta with sun dried tomatoes ready in 30 minutes.','Italian','Easy',5,20,25,4,520,16,62,24,4,'[{"amount":12,"unit":"oz","item":"penne pasta","group":"pasta"},{"amount":3,"unit":"cups","item":"chicken broth","group":"liquid"},{"amount":1,"unit":"cup","item":"heavy cream","group":"liquid"},{"amount":0.5,"unit":"cup","item":"sun dried tomatoes in oil, drained and chopped","group":"produce"},{"amount":4,"unit":"cloves","item":"garlic, minced","group":"produce"},{"amount":0.5,"unit":"cup","item":"grated parmesan cheese","group":"dairy"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"spice"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"spice"},{"amount":2,"unit":"cups","item":"fresh baby spinach","group":"produce"}]','[{"title":"Saute Garlic and Tomatoes","text":"Heat olive oil in a large pot over medium heat. Add garlic and sun dried tomatoes and cook for 2 minutes until fragrant.","timer":120},{"title":"Add Liquids and Pasta","text":"Pour in chicken broth and heavy cream. Stir in Italian seasoning and red pepper flakes. Add pasta and bring to a boil.","timer":300},{"title":"Cook the Pasta","text":"Reduce heat to medium and cook uncovered for 12 to 14 minutes, stirring frequently, until pasta is tender and sauce has thickened.","timer":840},{"title":"Add Spinach and Cheese","text":"Remove from heat and stir in spinach and parmesan cheese. The spinach will wilt from the residual heat within 1 minute.","timer":60},{"title":"Season and Serve","text":"Taste and adjust salt and pepper as needed. Serve immediately with extra parmesan on top.","timer":0}]','[{"original":"heavy cream","swap":"half and half for a lighter sauce"},{"original":"penne pasta","swap":"rigatoni or farfalle"},{"original":"chicken broth","swap":"vegetable broth to make it vegetarian"}]','["Not stirring frequently enough, which causes the pasta to stick to the bottom","Adding parmesan while still on high heat, causing it to clump","Using dry sun dried tomatoes instead of oil packed, which results in a less rich flavor"]','["one pot","pasta","creamy","sun dried tomato","quick","weeknight"]','["vegetarian"]','Pasta','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cast Iron Pizza Pie','cast-iron-pizza-pie','A thick and crispy deep dish style pizza baked in a cast iron skillet with a golden buttery crust. The skillet creates an irresistible crunchy edge that a standard pan cannot replicate.','Deep dish cast iron pizza with a crispy golden crust and melty cheese.','American','Medium',20,25,45,4,610,28,68,26,3,'[{"amount":1,"unit":"lb","item":"store bought pizza dough","group":"dough"},{"amount":0.75,"unit":"cup","item":"pizza sauce","group":"sauce"},{"amount":2,"unit":"cups","item":"shredded mozzarella cheese","group":"dairy"},{"amount":0.5,"unit":"cup","item":"sliced pepperoni","group":"meat"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"dairy"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"spice"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"spice"},{"amount":0.25,"unit":"cup","item":"grated parmesan cheese","group":"dairy"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"spice"}]','[{"title":"Preheat and Prep the Skillet","text":"Preheat oven to 450 degrees F. Place butter and olive oil in a 12 inch cast iron skillet and set over low heat until butter melts. Swirl to coat the entire surface and sides.","timer":180},{"title":"Press the Dough","text":"Stretch the pizza dough to fit the skillet. Press it in and push the edges up the sides about 1 inch to form a crust. Let it rest for 5 minutes.","timer":300},{"title":"Add Toppings","text":"Spread pizza sauce evenly over the dough. Sprinkle mozzarella cheese, then layer pepperoni on top. Dust with garlic powder, oregano, parmesan, and red pepper flakes.","timer":120},{"title":"Bake the Pizza","text":"Transfer skillet to the oven and bake for 20 to 25 minutes until the crust is deep golden brown and the cheese is bubbly with slight browning on top.","timer":1500},{"title":"Rest and Slice","text":"Remove from the oven and let the pizza rest in the skillet for 5 minutes. Run a spatula around the edge and slide onto a cutting board before slicing.","timer":300}]','[{"original":"pepperoni","swap":"sliced mushrooms and bell peppers for a vegetarian option"},{"original":"store bought pizza dough","swap":"homemade dough for a more artisan result"},{"original":"mozzarella cheese","swap":"provolone or a blend of Italian cheeses"}]','["Not letting the dough rest after pressing, which causes it to shrink back","Overloading toppings, which prevents the crust from cooking through","Removing the pizza immediately without resting, which causes the bottom crust to tear"]','["pizza","cast iron","deep dish","weeknight","comfort food","baked"]','[]','Pizza','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Greek Chicken Rice Skillet','greek-chicken-rice-skillet','A Mediterranean inspired one pan meal with juicy chicken thighs, fluffy lemon rice, olives, and feta cheese. Everything cooks together in one skillet for maximum flavor and easy cleanup.','One pan Greek chicken and rice with lemon, olives, and feta.','Greek','Medium',10,35,45,4,540,38,44,22,2,'[{"amount":4,"unit":"pieces","item":"boneless skinless chicken thighs","group":"protein"},{"amount":1.5,"unit":"cups","item":"long grain white rice","group":"grain"},{"amount":2.5,"unit":"cups","item":"chicken broth","group":"liquid"},{"amount":1,"unit":"whole","item":"lemon, juiced and zested","group":"produce"},{"amount":0.5,"unit":"cup","item":"kalamata olives, halved","group":"produce"},{"amount":0.5,"unit":"cup","item":"crumbled feta cheese","group":"dairy"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"spice"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"spice"},{"amount":0.5,"unit":"tsp","item":"paprika","group":"spice"}]','[{"title":"Season and Sear Chicken","text":"Season chicken thighs with oregano, garlic powder, paprika, salt, and pepper. Heat olive oil in a large skillet over medium high heat and sear chicken for 4 minutes per side until golden. Remove and set aside.","timer":480},{"title":"Toast the Rice","text":"In the same skillet, add rice and cook for 2 minutes, stirring often, until lightly toasted and fragrant.","timer":120},{"title":"Add Liquid and Chicken","text":"Pour in chicken broth, lemon juice, and lemon zest. Stir to combine and scrape up any browned bits from the pan. Nestle the seared chicken thighs on top of the rice.","timer":60},{"title":"Simmer Until Cooked","text":"Bring to a boil, then reduce heat to low. Cover with a lid and cook for 18 to 20 minutes until the rice is tender and the chicken is cooked through to 165 degrees F.","timer":1200},{"title":"Top and Serve","text":"Remove from heat and scatter kalamata olives and crumbled feta over the top. Let rest covered for 5 minutes before serving.","timer":300}]','[{"original":"chicken thighs","swap":"chicken breasts, but reduce cooking time to avoid dryness"},{"original":"kalamata olives","swap":"green olives or simply omit if you do not enjoy olives"},{"original":"feta cheese","swap":"goat cheese for a creamier and milder finish"}]','["Lifting the lid while the rice cooks, which releases steam and results in undercooked rice","Skipping the sear on the chicken, which eliminates depth of flavor in the dish","Using too high heat during the simmer, which burns the bottom of the rice before it finishes cooking"]','["Greek","one pan","chicken","rice","Mediterranean","skillet","weeknight"]','["gluten-free"]','Chicken','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Butter Shrimp','honey-garlic-butter-shrimp','Succulent shrimp coated in a sticky honey garlic butter sauce that comes together in under 15 minutes. It is perfect served over rice, noodles, or alongside steamed vegetables.','Quick sticky honey garlic butter shrimp ready in 15 minutes.','American','Easy',5,10,15,4,310,28,18,14,0,'[{"amount":1.5,"unit":"lbs","item":"large shrimp, peeled and deveined","group":"protein"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"dairy"},{"amount":4,"unit":"cloves","item":"garlic, minced","group":"produce"},{"amount":3,"unit":"tbsp","item":"honey","group":"sweetener"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"condiment"},{"amount":1,"unit":"tbsp","item":"lemon juice","group":"produce"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"oil"},{"amount":0.25,"unit":"tsp","item":"red pepper flakes","group":"spice"},{"amount":2,"unit":"tbsp","item":"fresh parsley, chopped","group":"produce"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"spice"}]','[{"title":"Make the Sauce","text":"In a small bowl, whisk together honey, soy sauce, and lemon juice. Set aside.","timer":60},{"title":"Cook the Shrimp","text":"Heat olive oil in a large skillet over medium high heat. Add shrimp in a single layer and cook for 1 to 2 minutes per side until pink and just opaque. Remove shrimp and set aside.","timer":240},{"title":"Saute Garlic","text":"Reduce heat to medium. Melt butter in the same skillet and add garlic and red pepper flakes. Cook for 1 minute, stirring constantly, until fragrant.","timer":60},{"title":"Build the Glaze","text":"Pour the honey soy sauce mixture into the skillet and simmer for 2 to 3 minutes until the sauce thickens and becomes glossy.","timer":180},{"title":"Toss and Serve","text":"Return shrimp to the skillet and toss to coat in the sauce. Garnish with fresh parsley and serve immediately over rice or noodles.","timer":30}]','[{"original":"soy sauce","swap":"coconut aminos for a gluten free and lower sodium option"},{"original":"honey","swap":"maple syrup for a different but equally sweet flavor"},{"original":"fresh parsley","swap":"sliced green onions for a mild onion finish"}]','["Overcrowding the pan with shrimp, which causes them to steam instead of sear","Overcooking the shrimp before adding the sauce, making them rubbery","Not watching the honey sauce closely, as it can go from perfectly thick to burnt very quickly"]','["shrimp","honey garlic","quick","15 minutes","seafood","weeknight"]','["gluten-free option","dairy-free option"]','Seafood','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Tacos','classic-beef-tacos','Perfectly seasoned ground beef tacos with fresh toppings piled into warm corn tortillas. This family favorite is on the table in 20 minutes with simple pantry spices.','Seasoned ground beef tacos with fresh toppings in 20 minutes.','Mexican','Easy',10,12,22,4,420,26,30,22,4,'[{"amount":1,"unit":"lb","item":"ground beef 80/20","group":"protein"},{"amount":8,"unit":"pieces","item":"corn tortillas","group":"grain"},{"amount":1,"unit":"tbsp","item":"chili powder","group":"spice"},{"amount":1,"unit":"tsp","item":"ground cumin","group":"spice"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"spice"},{"amount":0.5,"unit":"tsp","item":"onion powder","group":"spice"},{"amount":0.25,"unit":"cup","item":"water","group":"liquid"},{"amount":1,"unit":"cup","item":"shredded cheddar cheese","group":"dairy"},{"amount":1,"unit":"cup","item":"shredded lettuce","group":"produce"},{"amount":1,"unit":"whole","item":"tomato, diced","group":"produce"}]','[{"title":"Brown the Beef","text":"Heat a large skillet over medium high heat. Add ground beef and cook for 6 to 7 minutes, breaking it apart with a spoon, until fully browned. Drain excess fat.","timer":420},{"title":"Season the Meat","text":"Stir in chili powder, cumin, garlic powder, onion powder, salt, and water. Simmer for 3 to 4 minutes until the water is absorbed and the beef is coated in seasoning.","timer":240},{"title":"Warm the Tortillas","text":"Heat corn tortillas one at a time in a dry skillet over medium heat for 30 seconds per side, or wrap in a damp paper towel and microwave for 45 seconds.","timer":60},{"title":"Assemble the Tacos","text":"Spoon seasoned beef into each tortilla. Top with shredded cheddar cheese, lettuce, and diced tomato.","timer":120},{"title":"Add Final Toppings and Serve","text":"Add your preferred additional toppings such as sour cream, salsa, or avocado. Serve immediately while the beef is hot.","timer":0}]','[{"original":"ground beef","swap":"ground turkey or ground chicken for a leaner option"},{"original":"corn tortillas","swap":"flour tortillas for a softer and more pliable shell"},{"original":"cheddar cheese","swap":"cotija or Monterey Jack for a more authentic flavor"}]','["Not draining the fat after browning the beef, which makes the tacos greasy","Skipping warming the tortillas, which causes them to crack when folded","Adding too much water to the seasoned beef and not allowing it to simmer down, leaving watery meat"]','["tacos","beef","Mexican","quick","family friendly","weeknight"]','["gluten-free option"]','Tacos','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Grated Parmesan Crusted Potatoes','grated-parmesan-crusted-potatoes','Crispy golden potatoes coated in a savory parmesan crust that shatters with every bite. These oven-roasted beauties are the ultimate side dish for any meal.','Crispy parmesan-coated roasted potatoes that are golden and crunchy on the outside and fluffy on the inside.','American','Easy',15,45,60,4,320,12,38,14,4,'[{"amount":900,"unit":"g","item":"baby potatoes halved","group":"main"},{"amount":100,"unit":"g","item":"finely grated parmesan cheese","group":"crust"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"main"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"}]','[{"title":"Preheat and Prepare Pan","text":"Preheat your oven to 220 degrees Celsius. Drizzle 2 tablespoons of olive oil onto a large baking sheet and spread the finely grated parmesan evenly across the surface of the pan.","timer":0},{"title":"Season the Potatoes","text":"In a large bowl, toss the halved baby potatoes with the remaining olive oil, garlic powder, smoked paprika, salt, and black pepper until every potato is evenly coated.","timer":0},{"title":"Place Potatoes Cut Side Down","text":"Carefully press each potato cut-side down directly onto the parmesan layer on the baking sheet. Make sure every potato is in direct contact with the cheese for maximum crust formation.","timer":0},{"title":"Roast Until Golden","text":"Place the baking sheet in the preheated oven and roast for 40 to 45 minutes without moving the potatoes. The cheese will melt, bubble, and form a crispy golden crust underneath each potato.","timer":2700},{"title":"Release and Serve","text":"Remove from the oven and allow to cool for 2 minutes. Use a thin spatula to carefully lift each potato, keeping the parmesan crust intact. Arrange on a serving plate crust-side up and garnish with fresh parsley.","timer":120}]','[{"original":"parmesan cheese","swap":"pecorino romano for a sharper saltier crust"},{"original":"baby potatoes","swap":"yukon gold potatoes cut into chunks"},{"original":"smoked paprika","swap":"regular paprika or cayenne for extra heat"}]','["Moving the potatoes during roasting which breaks the parmesan crust before it sets","Using pre-shredded parmesan which contains anti-caking agents that prevent proper crust formation","Not spreading the parmesan thinly enough causing uneven and thick clumpy patches"]','["potatoes","parmesan","crispy","roasted","side dish","cheese"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Upside Down Puff Pastry Tarts','upside-down-puff-pastry-tarts','Elegant tarts built in reverse with caramelized toppings hidden beneath a flaky puff pastry lid that gets flipped to reveal a stunning presentation. Sweet or savory variations make these endlessly versatile.','Flipped puff pastry tarts with jammy caramelized vegetables that reveal a beautiful glossy topping when inverted.','French','Medium',20,30,50,4,410,8,42,24,3,'[{"amount":1,"unit":"sheet","item":"ready-rolled puff pastry","group":"pastry"},{"amount":3,"unit":"medium","item":"tomatoes sliced into rounds","group":"topping"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"caramel base"},{"amount":1,"unit":"tbsp","item":"balsamic glaze","group":"caramel base"},{"amount":1,"unit":"tsp","item":"caster sugar","group":"caramel base"},{"amount":2,"unit":"cloves","item":"garlic thinly sliced","group":"topping"},{"amount":4,"unit":"sprigs","item":"fresh thyme","group":"topping"},{"amount":0.5,"unit":"tsp","item":"flaky sea salt","group":"seasoning"}]','[{"title":"Preheat and Prep Muffin Tin","text":"Preheat your oven to 200 degrees Celsius. Place a small knob of butter into each cup of a 4-hole large muffin tin and put it in the oven for 2 minutes until the butter melts. Add a tiny drizzle of balsamic glaze and a pinch of sugar to each cup.","timer":120},{"title":"Layer the Toppings","text":"Arrange the tomato slices, garlic, and a sprig of thyme into each muffin cup on top of the butter mixture. Press down gently and season with flaky sea salt. The tomatoes will caramelize and become jammy during baking.","timer":0},{"title":"Cut and Top with Pastry","text":"Cut the puff pastry sheet into 4 equal circles or squares slightly larger than each muffin cup. Lay a pastry piece over each cup and tuck the edges down around the filling, creating a sealed lid.","timer":0},{"title":"Bake Until Golden","text":"Transfer the muffin tin to the oven and bake for 25 to 30 minutes until the pastry is deeply golden, puffed, and cooked through. The butter and balsamic will be bubbling around the edges.","timer":1800},{"title":"Invert and Serve","text":"Remove from the oven and allow to cool for exactly 3 minutes. Place a flat baking tray over the top of the muffin tin and in one confident motion flip the entire tin over. Lift the tin to reveal the caramelized tomato tops. Serve immediately.","timer":180}]','[{"original":"tomatoes","swap":"thinly sliced zucchini or caramelized onions for a different flavor"},{"original":"balsamic glaze","swap":"honey for a sweeter less tangy caramel base"},{"original":"fresh thyme","swap":"fresh rosemary or oregano works equally well"}]','["Waiting too long to flip the tarts causing the caramelized filling to set and stick permanently in the tin","Not sealing the pastry edges which allows the filling to bubble up through the top during baking","Using cold butter straight from the fridge which does not melt evenly across the base of the cups"]','["puff pastry","tarts","upside down","caramelized","elegant","tomato"]','["vegetarian"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Feta Crusted Fried Eggs','feta-crusted-fried-eggs','Pan-fried eggs with a crispy golden base surrounded by a ring of crumbled feta that melts and crisps into a salty savory crust. Ready in minutes and perfect on toast or with warm flatbread.','Fried eggs encircled by crispy golden crumbled feta cheese for an elevated and flavor-packed breakfast.','Mediterranean','Easy',5,6,11,2,280,16,4,22,1,'[{"amount":4,"unit":"large","item":"eggs","group":"main"},{"amount":80,"unit":"g","item":"crumbled feta cheese","group":"crust"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":0.5,"unit":"tsp","item":"red chili flakes","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"tsp","item":"fresh dill chopped","group":"garnish"},{"amount":1,"unit":"tsp","item":"honey","group":"garnish"},{"amount":2,"unit":"slices","item":"sourdough toast","group":"serving"}]','[{"title":"Heat the Pan","text":"Heat a non-stick skillet over medium heat and add the olive oil. Allow the oil to become shimmery and hot before adding any other ingredients. A properly heated pan is essential for achieving a crispy egg base.","timer":60},{"title":"Create the Feta Ring","text":"Sprinkle the crumbled feta into 2 circular mounds in the pan, creating rings large enough to contain an egg in the center of each. Allow the feta to begin sizzling in the oil for about 30 seconds before adding the eggs.","timer":30},{"title":"Crack the Eggs","text":"Carefully crack one egg into the center of each feta ring. Do not break the yolks. Season each egg with black pepper and a pinch of chili flakes. The feta will continue to crisp around the edges of the egg white.","timer":0},{"title":"Cook to Preference","text":"Cook over medium heat for 3 to 4 minutes for a runny yolk or 5 to 6 minutes for a fully set yolk. Do not cover the pan as steam will prevent the feta from crisping properly. The feta should turn golden and lacy at the edges.","timer":300},{"title":"Serve and Garnish","text":"Use a thin spatula to transfer each feta-crusted egg onto a slice of sourdough toast. Drizzle a small amount of honey over the top, scatter fresh dill, and serve immediately while the feta crust is still crispy.","timer":0}]','[{"original":"feta cheese","swap":"halloumi finely grated for a similarly salty crispy result"},{"original":"red chili flakes","swap":"za atar or dried oregano for an herby variation"},{"original":"honey","swap":"hot sauce or chili oil for a savory spicy finish instead"}]','["Adding feta to a cold pan which causes it to stick and steam rather than crisp and brown","Covering the pan with a lid which traps steam and makes the feta soggy instead of crispy","Using pre-packaged feta in brine without patting it dry which releases too much moisture into the pan"]','["eggs","feta","breakfast","crispy","quick","mediterranean"]','["vegetarian","gluten-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Roasted Carrots','honey-garlic-roasted-carrots','Tender oven-roasted carrots glazed in a sticky honey garlic sauce that caramelizes into a glossy amber coating. A simple side dish that transforms humble carrots into something extraordinary.','Sweet and sticky honey garlic glazed carrots roasted until caramelized and tender throughout.','American','Easy',10,35,45,4,185,2,32,7,5,'[{"amount":700,"unit":"g","item":"whole carrots peeled","group":"main"},{"amount":3,"unit":"tbsp","item":"honey","group":"glaze"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"glaze"},{"amount":2,"unit":"tbsp","item":"unsalted butter melted","group":"glaze"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"}]','[{"title":"Preheat Oven","text":"Preheat your oven to 210 degrees Celsius. Line a large baking sheet with parchment paper or lightly grease it with olive oil. If the carrots are thick, halve them lengthwise so they roast evenly.","timer":0},{"title":"Make the Honey Garlic Glaze","text":"In a small bowl, whisk together the honey, melted butter, minced garlic, salt, and black pepper until fully combined. The mixture should be smooth and pourable. Taste and adjust seasoning as needed.","timer":0},{"title":"Coat the Carrots","text":"Arrange the carrots in a single layer on the prepared baking sheet. Pour the honey garlic glaze over the carrots and toss to coat every surface evenly. Make sure the carrots are spread out and not overlapping.","timer":0},{"title":"Roast Until Caramelized","text":"Roast in the preheated oven for 30 to 35 minutes, flipping the carrots halfway through at the 15-minute mark. The glaze will caramelize and turn a deep amber color. The carrots should be fork-tender with slightly charred edges.","timer":2100},{"title":"Garnish and Serve","text":"Remove from the oven and transfer the carrots to a serving platter. Drizzle any remaining glaze from the baking sheet over the top. Scatter fresh parsley over the carrots and serve hot alongside your main course.","timer":0}]','[{"original":"honey","swap":"maple syrup for a vegan version with a deeper earthy sweetness"},{"original":"fresh parsley","swap":"fresh thyme or chives for a different herbal finish"},{"original":"unsalted butter","swap":"coconut oil to keep the recipe fully dairy-free"}]','["Overcrowding the baking sheet which causes the carrots to steam rather than roast and caramelize","Skipping the halfway flip which results in one side caramelizing while the other remains pale and soft","Using too high a heat which burns the honey glaze before the carrots are cooked through"]','["carrots","honey","garlic","roasted","side dish","glazed","vegetable"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Smashed Cucumber Salad','crispy-smashed-cucumber-salad','Smashed cucumbers that absorb a bold tangy sesame dressing in all their jagged crevices for maximum flavor in every bite. A refreshing and addictive salad that comes together in just minutes.','Smashed cucumbers tossed in a punchy sesame garlic dressing for a quick and intensely flavorful salad.','Asian','Easy',15,0,15,4,120,3,9,9,2,'[{"amount":4,"unit":"medium","item":"English cucumbers","group":"main"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"dressing"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"dressing"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"dressing"},{"amount":1,"unit":"tsp","item":"chili oil","group":"dressing"},{"amount":2,"unit":"cloves","item":"garlic finely grated","group":"dressing"},{"amount":1,"unit":"tsp","item":"toasted sesame seeds","group":"garnish"},{"amount":2,"unit":"stalks","item":"green onions thinly sliced","group":"garnish"}]','[{"title":"Smash the Cucumbers","text":"Place each cucumber on a cutting board. Using the flat side of a large knife or a rolling pin, firmly smash the cucumber until it cracks and splits open. Cut the smashed cucumbers into rough bite-sized pieces about 4 centimeters long.","timer":0},{"title":"Salt and Drain","text":"Place the smashed cucumber pieces in a colander and sprinkle generously with salt. Toss to coat and allow to sit for 10 minutes. This draws out excess moisture and ensures the dressing clings to the cucumbers rather than getting diluted.","timer":600},{"title":"Make the Dressing","text":"In a small bowl, whisk together the soy sauce, rice vinegar, sesame oil, chili oil, and grated garlic until fully combined. Taste and adjust the balance of salty, sour, and spicy to your preference.","timer":0},{"title":"Pat Dry and Dress","text":"Pat the drained cucumbers dry with paper towels to remove as much surface moisture as possible. Transfer to a serving bowl and pour the dressing over the top. Toss thoroughly so every jagged piece is coated in the dressing.","timer":0},{"title":"Garnish and Serve","text":"Scatter the toasted sesame seeds and sliced green onions over the dressed cucumbers. Serve immediately for the best texture, or refrigerate for up to 30 minutes to allow the flavors to meld. Do not dress too far in advance as the cucumbers will lose their crunch.","timer":0}]','[{"original":"soy sauce","swap":"tamari for a gluten-free version with the same umami depth"},{"original":"chili oil","swap":"gochujang thinned with a little water for a Korean-inspired variation"},{"original":"rice vinegar","swap":"apple cider vinegar for a similar mild acidity"}]','["Skipping the salting step which results in a watery dressing that pools at the bottom of the bowl","Dressing the salad too far in advance causing the cucumbers to become limp and soggy","Not grating the garlic finely enough leaving harsh raw garlic chunks in the finished salad"]','["cucumber","salad","sesame","asian","quick","refreshing","no cook"]','["vegan","dairy-free"]','Salad','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Smashed Potato Salad','crispy-smashed-potato-salad','Golden crispy smashed potatoes tossed in a tangy herb dressing for a warm salad with incredible texture. This dish combines the best of roasted potatoes and classic potato salad.','Crispy oven-smashed potatoes tossed in a zesty mustard herb dressing.','American','Easy',15,45,60,4,320,6,48,12,5,'[{"amount":2,"unit":"lbs","item":"baby Yukon gold potatoes","group":"main"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"main"},{"amount":2,"unit":"tbsp","item":"whole grain mustard","group":"dressing"},{"amount":2,"unit":"tbsp","item":"apple cider vinegar","group":"dressing"},{"amount":3,"unit":"stalks","item":"celery, thinly sliced","group":"mix-ins"},{"amount":4,"unit":"strips","item":"bacon, cooked and crumbled","group":"mix-ins"},{"amount":3,"unit":"tbsp","item":"fresh chives, chopped","group":"garnish"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Boil the Potatoes","text":"Place baby potatoes in a large pot and cover with cold salted water. Bring to a boil and cook until fork tender, about 20 minutes. Drain and let steam dry for 5 minutes.","timer":1500},{"title":"Smash and Season","text":"Preheat oven to 425F. Arrange potatoes on a lined baking sheet. Use the bottom of a glass or measuring cup to smash each potato flat to about half an inch thick. Drizzle with olive oil and season with salt and garlic powder.","timer":300},{"title":"Roast Until Crispy","text":"Roast smashed potatoes in the oven for 25 minutes, flipping once halfway through, until the edges are deeply golden and crispy.","timer":1500},{"title":"Make the Dressing","text":"Whisk together whole grain mustard, apple cider vinegar, and 1 tablespoon of olive oil in a small bowl. Season with a pinch of salt and pepper to taste.","timer":120},{"title":"Toss and Serve","text":"Transfer warm crispy potatoes to a large bowl. Add celery and bacon crumbles. Drizzle dressing over everything and toss gently to coat. Top with fresh chives and serve warm.","timer":60}]','[{"original":"bacon","swap":"smoked tempeh for a vegetarian version"},{"original":"apple cider vinegar","swap":"white wine vinegar or lemon juice"},{"original":"baby Yukon gold potatoes","swap":"small red potatoes work equally well"}]','["Not drying the potatoes before roasting which leads to steaming instead of crisping","Smashing the potatoes too thin so they fall apart on the baking sheet","Adding the dressing too far in advance which makes the crispy edges soggy"]','["potato salad","crispy potatoes","side dish","summer","roasted"]','["gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Chopped Italian Sandwich Bowls','chopped-italian-sandwich-bowls','All the bold flavors of a classic Italian sub chopped together into a hearty no-bread bowl. Salami, pepperoncini, and provolone make every bite punchy and satisfying.','A deconstructed Italian sub served as a chopped salad bowl with zesty dressing.','Italian-American','Easy',20,0,20,4,410,22,14,31,3,'[{"amount":4,"unit":"cups","item":"romaine lettuce, finely chopped","group":"base"},{"amount":4,"unit":"oz","item":"Genoa salami, diced","group":"protein"},{"amount":4,"unit":"oz","item":"provolone cheese, diced","group":"protein"},{"amount":1,"unit":"cup","item":"cherry tomatoes, halved","group":"vegetables"},{"amount":0.5,"unit":"cup","item":"pepperoncini peppers, sliced","group":"vegetables"},{"amount":0.5,"unit":"cup","item":"red onion, thinly sliced","group":"vegetables"},{"amount":3,"unit":"tbsp","item":"red wine vinegar","group":"dressing"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"dressing"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"seasoning"}]','[{"title":"Prep All Ingredients","text":"Finely chop the romaine lettuce and place it in a large wide bowl. Dice the salami and provolone into small even pieces. Halve the cherry tomatoes and slice the red onion and pepperoncini.","timer":600},{"title":"Make the Italian Dressing","text":"In a small jar or bowl whisk together red wine vinegar, olive oil, dried oregano, salt, and black pepper. Taste and adjust seasoning as needed.","timer":120},{"title":"Combine the Bowl","text":"Add the diced salami, provolone, cherry tomatoes, red onion, and pepperoncini to the chopped romaine. Toss everything together so the ingredients are evenly distributed.","timer":120},{"title":"Dress and Toss","text":"Pour the dressing over the chopped salad and toss vigorously to coat every ingredient evenly. The lettuce should be well dressed but not swimming in liquid.","timer":60},{"title":"Serve Immediately","text":"Divide the chopped Italian bowl into individual serving dishes. Serve right away for the best texture. Optionally top with a sprinkle of grated Parmesan and crushed red pepper flakes.","timer":30}]','[{"original":"Genoa salami","swap":"turkey pepperoni or diced ham for a lighter version"},{"original":"provolone cheese","swap":"fresh mozzarella for a softer texture"},{"original":"red wine vinegar","swap":"lemon juice for a brighter citrus dressing"}]','["Chopping the lettuce too coarsely so it does not mix well with the smaller ingredients","Dressing the bowl too far ahead which wilts the romaine quickly","Using pre-sliced deli meat in thick strips instead of small diced pieces"]','["Italian","no-cook","lunch","meal prep","low carb"]','["gluten-free","low-carb"]','Lunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cottage Cheese Cookie Dough','cottage-cheese-cookie-dough','High-protein edible cookie dough made with blended cottage cheese for a creamy no-bake treat. It tastes indulgent but is packed with protein and lower in sugar.','Creamy protein-packed edible cookie dough made with blended cottage cheese.','American','Easy',10,0,10,6,210,14,22,7,1,'[{"amount":1.5,"unit":"cups","item":"full fat cottage cheese","group":"base"},{"amount":0.25,"unit":"cup","item":"almond flour","group":"base"},{"amount":3,"unit":"tbsp","item":"maple syrup","group":"sweetener"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"flavoring"},{"amount":0.25,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"cup","item":"mini chocolate chips","group":"mix-ins"},{"amount":2,"unit":"tbsp","item":"peanut butter","group":"flavoring"},{"amount":0.5,"unit":"tsp","item":"cinnamon","group":"seasoning"}]','[{"title":"Blend the Cottage Cheese","text":"Add cottage cheese to a blender or food processor and blend on high for about 60 seconds until completely smooth with no lumps. Scrape down the sides as needed.","timer":60},{"title":"Add Flavoring Ingredients","text":"To the blended cottage cheese add maple syrup, vanilla extract, peanut butter, salt, and cinnamon. Blend again for 20 to 30 seconds until everything is fully incorporated and smooth.","timer":30},{"title":"Fold in Dry Ingredients","text":"Transfer the mixture to a mixing bowl. Stir in the almond flour until fully combined. The almond flour helps create a dough-like texture and absorbs excess moisture.","timer":60},{"title":"Add Chocolate Chips","text":"Fold in the mini chocolate chips using a spatula. Reserve a few chips to sprinkle on top for presentation. Taste and adjust sweetness by adding more maple syrup if desired.","timer":30},{"title":"Chill and Serve","text":"Transfer the cookie dough to a serving bowl or airtight container. Refrigerate for at least 20 minutes to firm up. Serve chilled with a spoon or alongside graham crackers for dipping.","timer":1200}]','[{"original":"maple syrup","swap":"honey or agave syrup in equal amounts"},{"original":"almond flour","swap":"oat flour for a nut-free version"},{"original":"peanut butter","swap":"almond butter or sunflower seed butter"}]','["Not blending the cottage cheese long enough which leaves a grainy texture","Skipping the chilling step which makes the dough too soft and loose","Using low fat cottage cheese which makes the final texture watery and thin"]','["high protein","no-bake","snack","dessert","healthy"]','["vegetarian","gluten-free"]','Snack','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Ricotta Pasta','lemon-ricotta-pasta','Silky lemon ricotta sauce coats tender pasta in this bright and creamy weeknight dinner. It comes together in under 30 minutes with pantry staples.','Creamy lemon ricotta sauce tossed with pasta and fresh herbs for an easy weeknight meal.','Italian','Easy',10,20,30,4,480,18,68,15,3,'[{"amount":12,"unit":"oz","item":"rigatoni or penne pasta","group":"base"},{"amount":1,"unit":"cup","item":"whole milk ricotta cheese","group":"sauce"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"sauce"},{"amount":1,"unit":"whole","item":"lemon, zested and juiced","group":"sauce"},{"amount":0.5,"unit":"cup","item":"pasta cooking water, reserved","group":"sauce"},{"amount":0.25,"unit":"cup","item":"grated Parmesan cheese","group":"topping"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"sauce"},{"amount":0.25,"unit":"cup","item":"fresh basil leaves, torn","group":"garnish"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of heavily salted water to a boil. Cook pasta according to package directions until al dente. Before draining reserve at least half a cup of starchy pasta cooking water.","timer":1200},{"title":"Saute the Garlic","text":"While the pasta cooks heat olive oil in a large skillet over medium heat. Add minced garlic and cook for 1 to 2 minutes until fragrant but do not let it brown.","timer":120},{"title":"Build the Ricotta Sauce","text":"Reduce heat to low and add ricotta, lemon zest, and lemon juice to the skillet. Stir together and add 3 tablespoons of reserved pasta water to thin the sauce to a creamy consistency.","timer":120},{"title":"Toss Pasta in Sauce","text":"Add the drained pasta directly to the skillet with the ricotta sauce. Toss over low heat adding more pasta water a splash at a time until the sauce clings to every piece of pasta.","timer":120},{"title":"Finish and Serve","text":"Remove from heat and stir in half the Parmesan. Divide into bowls and top with remaining Parmesan, torn basil, and a crack of black pepper. Serve immediately.","timer":60}]','[{"original":"whole milk ricotta","swap":"cream cheese thinned with a splash of milk"},{"original":"rigatoni","swap":"any short pasta such as farfalle or fusilli"},{"original":"fresh basil","swap":"fresh parsley or baby arugula for a peppery bite"}]','["Forgetting to save pasta water which is essential for making the sauce creamy and smooth","Adding ricotta over high heat which causes it to seize and become grainy","Under-seasoning the pasta water so the final dish tastes bland"]','["pasta","lemon","ricotta","weeknight dinner","vegetarian"]','["vegetarian"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Salmon Bites','honey-garlic-salmon-bites','Tender salmon chunks glazed in a sticky sweet honey garlic sauce and pan-seared until caramelized. These bites are ready in 15 minutes and work perfectly over rice or salad.','Quick pan-seared salmon cubes glazed in a sticky honey garlic sauce.','Asian-American','Easy',10,10,20,4,350,34,18,15,0,'[{"amount":1.5,"unit":"lbs","item":"salmon fillets, skin removed and cut into 1 inch cubes","group":"main"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"sauce"},{"amount":3,"unit":"tbsp","item":"honey","group":"sauce"},{"amount":2,"unit":"tbsp","item":"low sodium soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"sauce"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":1,"unit":"tsp","item":"cornstarch","group":"sauce"},{"amount":2,"unit":"stalks","item":"green onions, sliced for garnish","group":"garnish"},{"amount":1,"unit":"tsp","item":"sesame seeds","group":"garnish"}]','[{"title":"Prep the Salmon","text":"Pat salmon cubes completely dry with paper towels. Season lightly with salt and black pepper on all sides. Dry salmon is essential for getting a good sear and caramelized exterior.","timer":180},{"title":"Mix the Sauce","text":"In a small bowl whisk together honey, soy sauce, minced garlic, sesame oil, and cornstarch until fully combined and the cornstarch is dissolved with no lumps.","timer":60},{"title":"Sear the Salmon","text":"Heat olive oil in a large nonstick skillet over medium-high heat. Add salmon cubes in a single layer and do not move them for 2 minutes to build a golden crust. Flip and sear the other side for 1 minute.","timer":180},{"title":"Add the Glaze","text":"Pour the honey garlic sauce over the seared salmon bites. Toss gently to coat and cook for 1 to 2 more minutes, stirring occasionally, until the sauce thickens and caramelizes around each piece.","timer":120},{"title":"Garnish and Serve","text":"Remove from heat and transfer to a serving plate. Sprinkle with sliced green onions and sesame seeds. Serve immediately over steamed white rice or alongside roasted broccoli.","timer":30}]','[{"original":"honey","swap":"maple syrup for a slightly different sweetness"},{"original":"soy sauce","swap":"coconut aminos for a gluten-free option"},{"original":"salmon","swap":"shrimp or cubed chicken breast with adjusted cook times"}]','["Not patting the salmon dry which prevents proper caramelization and causes steaming","Overcrowding the pan which drops the temperature and stops the salmon from searing","Cooking the glaze too long over high heat which causes it to burn and turn bitter"]','["salmon","honey garlic","quick dinner","meal prep","seafood"]','["gluten-free","dairy-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Million Dollar Cucumber Salad','million-dollar-cucumber-salad','This crisp and refreshing cucumber salad is tossed in a tangy sesame dressing with a hint of sweetness. It comes together in minutes and tastes like a restaurant-worthy side dish.','A crisp sesame-dressed cucumber salad that is ready in under 15 minutes.','Asian-Inspired','Easy',10,0,10,4,120,2,10,8,1,'[{"amount":4,"unit":"medium","item":"English cucumbers, thinly sliced","group":"Produce"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"Produce"},{"amount":2,"unit":"tablespoons","item":"rice vinegar","group":"Pantry"},{"amount":2,"unit":"tablespoons","item":"soy sauce","group":"Pantry"},{"amount":1,"unit":"tablespoon","item":"sesame oil","group":"Pantry"},{"amount":1,"unit":"tablespoon","item":"honey","group":"Pantry"},{"amount":1,"unit":"teaspoon","item":"red pepper flakes","group":"Pantry"},{"amount":2,"unit":"tablespoons","item":"toasted sesame seeds","group":"Pantry"},{"amount":3,"unit":"stalks","item":"green onions, thinly sliced","group":"Produce"}]','[{"title":"Salt and Drain the Cucumbers","text":"Slice the cucumbers thin and place them in a colander. Sprinkle with 1 teaspoon of salt, toss well, and let them sit for 5 minutes to draw out excess moisture. Pat dry with paper towels.","timer":300},{"title":"Make the Dressing","text":"In a large bowl, whisk together the rice vinegar, soy sauce, sesame oil, honey, minced garlic, and red pepper flakes until fully combined.","timer":0},{"title":"Toss the Salad","text":"Add the dried cucumber slices and sliced green onions to the bowl with the dressing. Toss everything together until the cucumbers are evenly coated.","timer":0},{"title":"Rest and Marinate","text":"Let the salad sit at room temperature for 5 minutes so the cucumbers can absorb the dressing flavors fully.","timer":300},{"title":"Garnish and Serve","text":"Sprinkle the toasted sesame seeds over the top just before serving. Serve immediately for the best texture and crunch.","timer":0}]','[{"original":"rice vinegar","swap":"apple cider vinegar"},{"original":"honey","swap":"maple syrup"},{"original":"soy sauce","swap":"tamari for a gluten-free option"}]','["Skipping the salting step results in watery and diluted dressing","Using regular cucumbers without peeling makes the texture too tough","Adding sesame seeds too early causes them to become soggy"]','["cucumber","salad","sesame","quick","no-cook","side dish"]','["Vegan","Gluten-Free Option","Dairy-Free"]','Salad','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Million Dollar Cucumber Salad with Cream Cheese','million-dollar-cucumber-salad-cream-cheese','This indulgent cucumber salad features a creamy herbed cream cheese dressing that makes every bite rich and satisfying. It is the ultimate crowd-pleasing side dish for potlucks and gatherings.','A creamy herb-laden cucumber salad that is luxurious enough to earn the million dollar name.','American','Easy',15,0,15,6,180,4,8,15,1,'[{"amount":3,"unit":"large","item":"English cucumbers, thinly sliced","group":"Produce"},{"amount":8,"unit":"ounces","item":"cream cheese, softened","group":"Dairy"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"Dairy"},{"amount":2,"unit":"tablespoons","item":"fresh dill, chopped","group":"Produce"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"Produce"},{"amount":1,"unit":"tablespoon","item":"white wine vinegar","group":"Pantry"},{"amount":1,"unit":"teaspoon","item":"onion powder","group":"Pantry"},{"amount":0.5,"unit":"teaspoon","item":"black pepper","group":"Pantry"},{"amount":1,"unit":"teaspoon","item":"salt","group":"Pantry"}]','[{"title":"Prepare the Cucumbers","text":"Slice the cucumbers thin and toss with salt in a colander. Allow them to drain for 10 minutes then press gently to remove excess water before using.","timer":600},{"title":"Mix the Creamy Dressing","text":"In a large bowl, beat together the softened cream cheese and sour cream until smooth. Stir in the garlic, dill, onion powder, white wine vinegar, and black pepper.","timer":0},{"title":"Combine Cucumbers and Dressing","text":"Fold the drained cucumber slices into the cream cheese mixture and stir gently until every slice is well coated in the creamy dressing.","timer":0},{"title":"Chill the Salad","text":"Cover the bowl and refrigerate the salad for at least 10 minutes before serving so the flavors meld together beautifully.","timer":600},{"title":"Serve and Garnish","text":"Transfer to a serving dish and garnish with extra fresh dill and a light sprinkle of black pepper. Serve cold.","timer":0}]','[{"original":"cream cheese","swap":"dairy-free cream cheese for a vegan version"},{"original":"sour cream","swap":"Greek yogurt for extra protein"},{"original":"fresh dill","swap":"dried dill at half the quantity"}]','["Using cold cream cheese makes the dressing lumpy and hard to mix","Not draining the cucumbers leads to a watery and thin dressing","Serving immediately without chilling results in underdeveloped flavor"]','["cucumber","cream cheese","creamy","salad","summer","potluck"]','["Vegetarian","Gluten-Free"]','Salad','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Marinated Carrot Salad with Chili Crisp','marinated-carrot-salad-chili-crisp','Tender marinated carrots are tossed with bold chili crisp oil for a spicy and tangy side salad with serious depth. This dish gets better the longer it sits making it perfect for meal prep.','A bold and spicy marinated carrot salad elevated by the rich complexity of chili crisp oil.','Asian-Inspired','Easy',10,5,40,4,140,2,16,8,4,'[{"amount":6,"unit":"large","item":"carrots, peeled and cut into matchsticks","group":"Produce"},{"amount":3,"unit":"tablespoons","item":"chili crisp oil","group":"Pantry"},{"amount":2,"unit":"tablespoons","item":"rice vinegar","group":"Pantry"},{"amount":1,"unit":"tablespoon","item":"soy sauce","group":"Pantry"},{"amount":1,"unit":"tablespoon","item":"honey","group":"Pantry"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"Produce"},{"amount":1,"unit":"teaspoon","item":"toasted sesame oil","group":"Pantry"},{"amount":2,"unit":"tablespoons","item":"fresh cilantro, chopped","group":"Produce"},{"amount":1,"unit":"tablespoon","item":"toasted sesame seeds","group":"Pantry"}]','[{"title":"Blanch the Carrots","text":"Bring a pot of water to a boil. Add the carrot matchsticks and blanch for 2 to 3 minutes until just tender but still with a slight bite. Drain and immediately transfer to an ice bath.","timer":180},{"title":"Make the Marinade","text":"In a large bowl, whisk together the chili crisp oil, rice vinegar, soy sauce, honey, garlic, and sesame oil until smooth and well combined.","timer":0},{"title":"Marinate the Carrots","text":"Drain and pat dry the cooled carrots, then add them to the marinade bowl. Toss well to coat every piece evenly with the spicy dressing.","timer":0},{"title":"Rest and Develop Flavors","text":"Let the carrots marinate at room temperature for at least 25 minutes, or refrigerate for up to 24 hours for even deeper flavor development.","timer":1500},{"title":"Garnish and Serve","text":"Just before serving, toss the carrots once more and top with fresh cilantro and toasted sesame seeds. Serve at room temperature or chilled.","timer":0}]','[{"original":"chili crisp oil","swap":"sambal oelek mixed with a neutral oil"},{"original":"rice vinegar","swap":"apple cider vinegar"},{"original":"fresh cilantro","swap":"fresh flat-leaf parsley for those who do not enjoy cilantro"}]','["Overcooking the carrots in the blanching step makes them mushy after marinating","Not using the ice bath causes the carrots to keep cooking and lose texture","Serving immediately without marinating results in underwhelming flavor"]','["carrot","chili crisp","spicy","marinated","meal prep","side dish"]','["Vegan","Dairy-Free","Gluten-Free Option"]','Salad','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Green Goddess Salad','green-goddess-salad','This vibrant green salad is loaded with fresh herbs and crisp vegetables all tossed in a creamy herby green goddess dressing. It is bright, fresh, and impossibly satisfying as a light meal or side.','A fresh and herb-packed green goddess salad with a luxuriously creamy homemade dressing.','American','Easy',15,0,15,4,210,5,12,17,4,'[{"amount":1,"unit":"large head","item":"green cabbage, finely shredded","group":"Produce"},{"amount":2,"unit":"cups","item":"fresh basil leaves","group":"Produce"},{"amount":1,"unit":"cup","item":"fresh chives, roughly chopped","group":"Produce"},{"amount":1,"unit":"cup","item":"fresh spinach leaves","group":"Produce"},{"amount":0.5,"unit":"cup","item":"Greek yogurt","group":"Dairy"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"Pantry"},{"amount":2,"unit":"tablespoons","item":"lemon juice, freshly squeezed","group":"Produce"},{"amount":1,"unit":"clove","item":"garlic","group":"Produce"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"Pantry"}]','[{"title":"Blend the Green Goddess Dressing","text":"Add the basil, chives, spinach, Greek yogurt, olive oil, lemon juice, garlic, and salt to a blender. Blend on high until completely smooth and vibrant green in color.","timer":0},{"title":"Taste and Adjust","text":"Taste the dressing and adjust seasoning with more salt, lemon juice, or herbs as needed. The dressing should be bright, tangy, and herby.","timer":0},{"title":"Prepare the Cabbage","text":"Finely shred the green cabbage using a sharp knife or mandoline. Place the shredded cabbage into a large salad bowl.","timer":0},{"title":"Dress the Salad","text":"Pour the green goddess dressing over the shredded cabbage and toss thoroughly so every strand is coated in the creamy herby dressing.","timer":0},{"title":"Serve Immediately","text":"Plate the salad and garnish with extra fresh herbs or a squeeze of lemon. Serve right away for the crispest texture.","timer":0}]','[{"original":"Greek yogurt","swap":"tahini for a dairy-free version"},{"original":"green cabbage","swap":"romaine lettuce or kale"},{"original":"fresh chives","swap":"green onions at an equal quantity"}]','["Using a food processor instead of a blender results in a chunky and uneven dressing","Dressing the salad too far in advance causes the cabbage to wilt and become soggy","Under-blending the dressing leaves fibrous herb pieces in an unpleasant texture"]','["green goddess","salad","herbs","cabbage","healthy","vegetarian"]','["Vegetarian","Gluten-Free"]','Salad','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Green Goddess Dip','green-goddess-dip','This thick and creamy green goddess dip is packed with fresh herbs and a bright lemony tang that makes it perfect for vegetable platters and chips. It comes together in under 5 minutes with a blender.','A vibrant and creamy herbed dip that works beautifully as a spread, dip, or dressing.','American','Easy',5,0,5,8,90,3,4,7,1,'[{"amount":1,"unit":"cup","item":"full-fat Greek yogurt","group":"Dairy"},{"amount":1,"unit":"cup","item":"fresh basil leaves, packed","group":"Produce"},{"amount":0.5,"unit":"cup","item":"fresh parsley leaves","group":"Produce"},{"amount":0.25,"unit":"cup","item":"fresh chives, chopped","group":"Produce"},{"amount":1,"unit":"clove","item":"garlic","group":"Produce"},{"amount":3,"unit":"tablespoons","item":"lemon juice, freshly squeezed","group":"Produce"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"Pantry"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"Pantry"},{"amount":0.25,"unit":"teaspoon","item":"black pepper","group":"Pantry"}]','[{"title":"Add Ingredients to Blender","text":"Place the Greek yogurt, basil, parsley, chives, garlic, lemon juice, olive oil, salt, and black pepper into a high-speed blender or food processor.","timer":0},{"title":"Blend Until Smooth","text":"Blend on high speed for 45 to 60 seconds until the dip is completely smooth, creamy, and a uniform bright green color throughout.","timer":60},{"title":"Taste and Adjust Seasoning","text":"Taste the dip and add more salt, lemon juice, or fresh herbs if needed. Blend again briefly after any additions to incorporate fully.","timer":0},{"title":"Chill Before Serving","text":"Transfer the dip to a serving bowl and refrigerate for at least 10 minutes so the flavors have time to come together and deepen.","timer":600},{"title":"Serve with Accompaniments","text":"Serve the chilled green goddess dip with fresh vegetables, pita chips, or crusty bread. Drizzle with a little extra olive oil and fresh herb leaves for presentation.","timer":0}]','[{"original":"Greek yogurt","swap":"avocado for an extra creamy dairy-free dip"},{"original":"fresh parsley","swap":"fresh tarragon for a more anise-forward flavor"},{"original":"lemon juice","swap":"white wine vinegar for a different brightness"}]','["Using dried herbs instead of fresh produces a dull and flat-tasting dip","Not chilling the dip before serving means the flavors do not have time to meld","Over-blending with a warm blender can cause the yogurt to thin out too much"]','["green goddess","dip","herbs","party","appetizer","healthy"]','["Vegetarian","Gluten-Free"]','Dip','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pan Fried Potstickers Guotie','pan-fried-potstickers-guotie','Crispy bottomed Chinese dumplings filled with juicy pork and cabbage. These pan fried parcels are golden on one side and tender on the other.','Golden crispy pork dumplings cooked with the classic steam fry method for the perfect texture.','Chinese','Medium',30,15,45,4,320,18,34,12,2,'[{"amount":250,"unit":"g","item":"ground pork","group":"filling"},{"amount":1.5,"unit":"cups","item":"napa cabbage finely chopped","group":"filling"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"filling"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"filling"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"filling"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"filling"},{"amount":24,"unit":"pieces","item":"round dumpling wrappers","group":"wrapper"},{"amount":2,"unit":"tbsp","item":"vegetable oil","group":"cooking"},{"amount":0.5,"unit":"cup","item":"water","group":"cooking"}]','[{"title":"Prepare the filling","text":"Salt the chopped napa cabbage and let it sit for 5 minutes then squeeze out all excess moisture. Combine the cabbage with ground pork, soy sauce, sesame oil, garlic and ginger. Mix thoroughly until the filling is uniform and sticky.","timer":300},{"title":"Fold the dumplings","text":"Place a dumpling wrapper in your palm and add one teaspoon of filling to the center. Wet the edge of the wrapper with water using your finger, fold the wrapper in half and press the center to seal. Pleat the front edge toward the back edge to create 4 to 5 folds. Press firmly so no air pockets remain.","timer":0},{"title":"Pan fry the bottoms","text":"Heat vegetable oil in a large nonstick skillet over medium high heat. Arrange dumplings flat side down in a single layer without touching each other. Fry undisturbed for 2 to 3 minutes until the bottoms are deep golden brown and crispy.","timer":180},{"title":"Steam to finish","text":"Carefully pour the water into the skillet and immediately cover with a tight fitting lid. The water will splatter so stand back. Steam the dumplings for 6 to 7 minutes until all the water has evaporated and the wrappers are cooked through.","timer":420},{"title":"Serve crispy side up","text":"Remove the lid and let any remaining moisture evaporate for 1 minute. Slide a spatula under the dumplings and flip them onto a plate so the crispy golden bottom faces up. Serve immediately with soy sauce and chili oil for dipping.","timer":60}]','[{"original":"ground pork","swap":"ground chicken or shrimp"},{"original":"napa cabbage","swap":"green cabbage or bok choy"},{"original":"round dumpling wrappers","swap":"homemade dough or gyoza wrappers"}]','["Not squeezing enough water from the cabbage which makes the filling soggy and causes wrappers to tear","Adding too much filling which prevents a proper seal and causes dumplings to burst during cooking","Lifting the lid during steaming which releases steam and results in unevenly cooked dumplings"]','["dumplings","chinese","pork","pan fried","party food","dim sum"]','["dairy-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lebanese Garlic Sauce Toum','lebanese-garlic-sauce-toum','A fluffy cloud like garlic sauce made with just four ingredients blended into a thick white emulsion. Toum is the essential condiment for shawarma, grilled meats and roasted vegetables.','Intensely garlicky Lebanese white sauce that is thick, airy and completely dairy free.','Lebanese','Medium',20,0,20,16,95,0,2,10,0,'[{"amount":1,"unit":"cup","item":"garlic cloves peeled","group":"sauce"},{"amount":1,"unit":"tsp","item":"kosher salt","group":"sauce"},{"amount":3,"unit":"cups","item":"neutral oil such as sunflower or canola","group":"sauce"},{"amount":0.33,"unit":"cup","item":"fresh lemon juice","group":"sauce"},{"amount":3,"unit":"tbsp","item":"ice water","group":"sauce"}]','[{"title":"Process the garlic","text":"Remove the green germ from the center of each garlic clove as it causes bitterness. Place the garlic and salt in a food processor and process until the garlic is very finely minced, scraping down the sides frequently. The garlic should form an almost paste like consistency.","timer":120},{"title":"Begin the emulsion","text":"With the food processor running, drizzle in the oil in an extremely slow thin stream, almost drop by drop at first. After adding about a quarter cup of oil, add a small splash of lemon juice. This alternating method builds a stable emulsion.","timer":180},{"title":"Build the sauce slowly","text":"Continue alternating between very slow streams of oil and small additions of lemon juice. Add a tablespoon of ice water if the mixture begins to look greasy or broken. Do not rush this process as adding oil too quickly will cause the emulsion to break and the sauce will become oily and flat.","timer":600},{"title":"Check the consistency","text":"The finished toum should be brilliant white, very thick and fluffy like whipped cream. It should hold stiff peaks when you lift a spoon. If it is too thin continue processing while adding a slow drizzle of oil. If it breaks, start fresh garlic in the processor and slowly add the broken sauce back in.","timer":60},{"title":"Rest and store","text":"Transfer the toum to a clean glass jar. The flavor will mellow and become more balanced after resting in the refrigerator for at least one hour. Store covered in the refrigerator for up to one month. The sauce will maintain its thick fluffy texture throughout storage.","timer":3600}]','[{"original":"sunflower oil","swap":"light olive oil but do not use extra virgin as it causes bitterness"},{"original":"fresh lemon juice","swap":"white wine vinegar for a slightly different tang"},{"original":"ice water","swap":"aquafaba for a slightly more stable emulsion"}]','["Adding the oil too quickly which breaks the emulsion and results in a greasy separated liquid instead of a fluffy sauce","Using extra virgin olive oil which makes the toum extremely bitter due to the polyphenols being overprocessed","Skipping the green germ removal from garlic cloves which makes the final sauce unnecessarily harsh and pungent"]','["garlic","lebanese","condiment","sauce","vegan","shawarma","middle eastern"]','["vegan","gluten-free","dairy-free","nut-free"]','Sauce','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Street Style Elote Corn Cups','street-style-elote-corn-cups','Mexican street corn kernels served in a cup and loaded with creamy mayo, cotija cheese, chili and lime. This is the mess free way to enjoy the bold flavors of elote.','Smoky charred corn kernels topped with tangy creamy sauce and salty cotija cheese in a convenient cup.','Mexican','Easy',10,10,20,4,280,8,32,15,3,'[{"amount":4,"unit":"cups","item":"fresh or frozen corn kernels","group":"base"},{"amount":3,"unit":"tbsp","item":"mayonnaise","group":"sauce"},{"amount":2,"unit":"tbsp","item":"Mexican crema or sour cream","group":"sauce"},{"amount":0.5,"unit":"cup","item":"cotija cheese crumbled","group":"toppings"},{"amount":1,"unit":"tsp","item":"chili powder","group":"toppings"},{"amount":0.5,"unit":"tsp","item":"smoked paprika","group":"toppings"},{"amount":2,"unit":"whole","item":"limes juiced and zested","group":"toppings"},{"amount":2,"unit":"tbsp","item":"fresh cilantro chopped","group":"toppings"},{"amount":1,"unit":"tbsp","item":"butter","group":"cooking"}]','[{"title":"Char the corn","text":"Melt butter in a large cast iron or heavy skillet over high heat until it begins to brown. Add the corn kernels in a single layer and do not stir for 2 minutes allowing them to develop a deep char. Toss and char for another 2 minutes. The charring adds essential smoky flavor that defines this dish.","timer":240},{"title":"Season the corn","text":"Add half the chili powder and smoked paprika directly to the hot corn and toss to coat evenly. Cook for one more minute so the spices bloom in the heat. Remove from heat and squeeze half the lime juice over the corn, tossing to combine.","timer":60},{"title":"Mix the creamy sauce","text":"In a small bowl whisk together the mayonnaise, Mexican crema, lime zest and a pinch of salt. Taste and adjust with lime juice. The sauce should be tangy and rich. This can be made ahead and refrigerated for up to three days.","timer":120},{"title":"Assemble the cups","text":"Divide the hot charred corn evenly among four cups or small bowls. Drizzle a generous amount of the creamy sauce over each cup. Do not be shy with the sauce as it is the heart of this dish.","timer":0},{"title":"Add toppings and serve","text":"Top each cup with a heavy sprinkle of crumbled cotija cheese, the remaining chili powder and smoked paprika. Finish with fresh cilantro and an extra squeeze of lime juice. Serve immediately while the corn is still warm and the contrast between the hot corn and cool creamy sauce is at its best.","timer":0}]','[{"original":"cotija cheese","swap":"feta cheese or parmesan for a similar salty crumbly texture"},{"original":"Mexican crema","swap":"full fat sour cream or plain Greek yogurt"},{"original":"mayonnaise","swap":"vegan mayo for a completely plant based version"}]','["Stirring the corn too frequently which steams instead of chars and results in pale soggy kernels without the essential smoky flavor","Using a nonstick pan which cannot reach high enough temperatures to properly char the corn kernels","Assembling the cups too far in advance which causes the creamy sauce to make the corn soggy and lose its texture"]','["corn","mexican","street food","elote","summer","quick","vegetarian"]','["vegetarian","gluten-free","nut-free"]','Snack','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Tacos al Carbon','classic-beef-tacos-al-carbon','Smoky grilled beef tacos seasoned with a bold blend of spices and served in warm corn tortillas. Every bite delivers charred edges, tender meat and fresh bright toppings.','Juicy grilled spiced beef tacos with fresh salsa and lime served in warm corn tortillas.','Mexican','Easy',15,12,27,4,390,28,28,18,4,'[{"amount":500,"unit":"g","item":"skirt steak or flank steak","group":"protein"},{"amount":1,"unit":"tsp","item":"cumin","group":"spice mix"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"spice mix"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"spice mix"},{"amount":0.5,"unit":"tsp","item":"chili powder","group":"spice mix"},{"amount":8,"unit":"pieces","item":"small corn tortillas","group":"base"},{"amount":0.5,"unit":"cup","item":"white onion finely diced","group":"toppings"},{"amount":0.5,"unit":"cup","item":"fresh cilantro chopped","group":"toppings"},{"amount":2,"unit":"whole","item":"limes cut into wedges","group":"toppings"}]','[{"title":"Season the steak","text":"Pat the steak completely dry with paper towels. Combine cumin, garlic powder, smoked paprika, chili powder and a generous amount of salt and pepper. Rub the spice mixture all over the steak on both sides and let it sit at room temperature for 10 minutes so the seasoning penetrates the meat.","timer":600},{"title":"Grill to char","text":"Heat a grill or cast iron skillet over very high heat until smoking. Cook the steak for 4 to 5 minutes per side for medium rare, pressing lightly to ensure good contact with the cooking surface. The exterior should have dark charred edges while the interior stays juicy and slightly pink.","timer":540},{"title":"Rest the meat","text":"Transfer the steak to a cutting board and let it rest uncovered for 5 minutes. This step is critical because cutting too early causes all the flavorful juices to run out and leaves you with dry meat. Do not skip the resting period.","timer":300},{"title":"Slice and warm tortillas","text":"Slice the rested steak against the grain into thin strips then chop into small bite sized pieces. While the steak rests warm the corn tortillas directly over a gas flame or in a dry skillet for 30 seconds per side until soft and slightly charred.","timer":60},{"title":"Build and serve","text":"Double up the tortillas for structural support and fill each taco with a generous portion of chopped steak. Top with diced white onion and fresh cilantro. Squeeze lime juice over the top just before eating. Serve with your favorite salsa on the side.","timer":0}]','[{"original":"skirt steak","swap":"flank steak or ribeye for similar tenderness and flavor"},{"original":"corn tortillas","swap":"flour tortillas for a softer more pliable wrap"},{"original":"fresh cilantro","swap":"fresh flat leaf parsley if you do not enjoy cilantro"}]','["Not patting the steak dry before seasoning which creates steam instead of a sear and prevents charred edges from forming","Slicing the steak with the grain instead of against it which makes the meat extremely chewy and tough","Overcrowding the pan with too many pieces of steak which drops the temperature and causes the meat to steam rather than sear"]','["tacos","beef","grilled","mexican","weeknight","street food"]','["gluten-free","dairy-free","nut-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Homemade Shakshuka with Feta','homemade-shakshuka-with-feta','Eggs poached directly in a rich spiced tomato and pepper sauce and finished with creamy crumbled feta. This one pan North African dish is equally perfect for breakfast, lunch or dinner.','Spiced tomato sauce with soft poached eggs and salty feta all cooked in one skillet.','North African','Easy',10,25,35,4,245,14,18,13,5,'[{"amount":2,"unit":"tbsp","item":"olive oil","group":"base"},{"amount":1,"unit":"whole","item":"yellow onion diced","group":"base"},{"amount":1,"unit":"whole","item":"red bell pepper diced","group":"base"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"base"},{"amount":1,"unit":"tsp","item":"cumin","group":"spices"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"spices"},{"amount":800,"unit":"g","item":"crushed canned tomatoes","group":"sauce"},{"amount":6,"unit":"whole","item":"large eggs","group":"protein"},{"amount":80,"unit":"g","item":"feta cheese crumbled","group":"topping"}]','[{"title":"Build the base","text":"Heat olive oil in a large deep skillet over medium heat. Add the diced onion and bell pepper and cook for 7 to 8 minutes until soft and starting to caramelize. Add the minced garlic and cook for one more minute until fragrant and golden.","timer":480},{"title":"Bloom the spices","text":"Add the cumin and smoked paprika directly to the softened vegetables and stir for 30 seconds until the spices are deeply fragrant and coat everything evenly. Blooming spices in the oil at this stage dramatically intensifies their flavor in the final sauce.","timer":30},{"title":"Simmer the sauce","text":"Pour in the crushed tomatoes and stir to combine everything. Season generously with salt and pepper. Bring the sauce to a simmer and cook uncovered for 10 minutes until it thickens slightly and the flavors meld together. Taste and adjust seasoning.","timer":600},{"title":"Poach the eggs","text":"Use a spoon to create 6 shallow wells in the tomato sauce. Crack one egg into each well carefully so the yolk remains intact. Cover the skillet with a lid and cook over medium low heat for 5 to 7 minutes. Cook for 5 minutes for runny yolks or 7 minutes for fully set yolks.","timer":420},{"title":"Finish and serve","text":"Remove the skillet from heat and immediately scatter crumbled feta cheese over the top. Garnish with fresh parsley or cilantro if desired. Serve directly from the pan with crusty bread or warm pita for scooping up the sauce and eggs.","timer":0}]','[{"original":"feta cheese","swap":"goat cheese or ricotta for a creamier milder topping"},{"original":"crushed canned tomatoes","swap":"fresh ripe tomatoes blended or chopped during peak tomato season"},{"original":"red bell pepper","swap":"green bell pepper or roasted poblano pepper for more depth"}]','["Cooking the eggs over too high heat which causes rubbery whites and overcooked yolks before the whites are fully set","Not simmering the tomato sauce long enough before adding the eggs which results in a thin watery sauce that does not hold the eggs properly","Removing the lid too early during egg poaching which lets steam escape and results in unevenly cooked whites with raw spots"]','["eggs","tomato","one pan","north african","breakfast","brunch","vegetarian"]','["vegetarian","gluten-free","nut-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Cuban Picadillo','classic-cuban-picadillo','A savory Cuban ground beef dish simmered with olives, raisins, and warm spices. It is traditionally served over white rice for a complete and satisfying meal.','Sweet and savory Cuban ground beef with olives and raisins served over rice.','Cuban','Easy',15,30,45,4,420,28,18,26,3,'[{"amount":1.5,"unit":"lbs","item":"ground beef","group":"main"},{"amount":1,"unit":"whole","item":"yellow onion, diced","group":"aromatics"},{"amount":4,"unit":"cloves","item":"garlic, minced","group":"aromatics"},{"amount":1,"unit":"whole","item":"green bell pepper, diced","group":"aromatics"},{"amount":1,"unit":"can","item":"crushed tomatoes (14 oz)","group":"sauce"},{"amount":0.5,"unit":"cup","item":"green olives, sliced","group":"mix-ins"},{"amount":0.33,"unit":"cup","item":"raisins","group":"mix-ins"},{"amount":1,"unit":"tsp","item":"ground cumin","group":"spices"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"spices"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"}]','[{"title":"Saute the Aromatics","text":"Heat olive oil in a large skillet over medium heat. Add the diced onion and green bell pepper and cook for 5 minutes until softened. Add the minced garlic and cook for 1 more minute.","timer":360},{"title":"Brown the Beef","text":"Add the ground beef to the skillet and break it apart with a wooden spoon. Cook until no pink remains, about 8 minutes. Drain any excess fat from the pan.","timer":480},{"title":"Add Spices and Tomatoes","text":"Stir in the cumin and oregano and cook for 1 minute to bloom the spices. Pour in the crushed tomatoes and stir everything together well.","timer":60},{"title":"Simmer with Mix-ins","text":"Add the sliced green olives and raisins to the skillet. Reduce heat to low and simmer uncovered for 15 minutes, stirring occasionally, until the sauce thickens.","timer":900},{"title":"Season and Serve","text":"Taste and season with salt and pepper as needed. Serve hot over white rice and garnish with fresh parsley if desired.","timer":0}]','[{"original":"ground beef","swap":"ground turkey or ground pork"},{"original":"raisins","swap":"dried cranberries or chopped dried apricots"},{"original":"green olives","swap":"capers for a brinier flavor"}]','["Do not skip draining the fat after browning the beef or the dish will be greasy","Do not rush the simmering step as reducing the sauce is key to building deep flavor","Do not omit the raisins as the sweet contrast is essential to authentic picadillo"]','["ground beef","cuban","rice dish","weeknight dinner","one pan"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Bolognese Stuffed Peppers','bolognese-stuffed-peppers','Tender bell peppers filled with a rich and meaty Bolognese sauce mixed with rice and topped with melted cheese. This dish combines Italian comfort food with the fun of an edible bowl.','Bell peppers packed with hearty Bolognese sauce, rice, and melted mozzarella cheese.','Italian','Medium',20,50,70,4,510,32,38,22,5,'[{"amount":4,"unit":"whole","item":"large bell peppers, tops cut off and seeded","group":"main"},{"amount":1,"unit":"lb","item":"ground beef","group":"filling"},{"amount":1,"unit":"cup","item":"cooked white rice","group":"filling"},{"amount":1,"unit":"can","item":"crushed tomatoes (14 oz)","group":"sauce"},{"amount":1,"unit":"whole","item":"yellow onion, finely diced","group":"aromatics"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"aromatics"},{"amount":0.5,"unit":"cup","item":"whole milk","group":"sauce"},{"amount":1,"unit":"cup","item":"shredded mozzarella cheese","group":"topping"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"spices"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"}]','[{"title":"Prepare the Peppers","text":"Preheat your oven to 375 degrees F. Cut the tops off the bell peppers and remove the seeds and membranes. Lightly brush the outside with olive oil and place them upright in a baking dish.","timer":0},{"title":"Cook the Bolognese Filling","text":"Heat olive oil in a skillet over medium heat. Saute onion for 4 minutes then add garlic and cook 1 minute more. Add ground beef and cook until browned, about 8 minutes. Drain excess fat.","timer":780},{"title":"Build the Sauce","text":"Pour in the crushed tomatoes and whole milk, then stir in the Italian seasoning. Simmer for 10 minutes until the sauce thickens. Remove from heat and stir in the cooked rice.","timer":600},{"title":"Stuff and Bake","text":"Spoon the Bolognese and rice mixture generously into each prepared pepper. Top each pepper with an even layer of shredded mozzarella cheese. Bake in the preheated oven for 30 minutes.","timer":1800},{"title":"Broil and Rest","text":"Switch the oven to broil and cook for 2 to 3 minutes until the cheese is golden and bubbly. Remove from oven and let rest for 5 minutes before serving.","timer":180}]','[{"original":"ground beef","swap":"ground pork or a pork and beef blend"},{"original":"white rice","swap":"cooked orzo or finely chopped cauliflower rice"},{"original":"whole milk","swap":"heavy cream for a richer sauce"}]','["Do not overfill the peppers or the filling will spill out and burn on the pan","Do not skip pre-cooking the filling as raw meat will not cook through properly inside the pepper","Do not use undercooked rice as it will remain hard and unpleasant in the final dish"]','["stuffed peppers","bolognese","italian","baked","comfort food"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Slow Cooker Shepherds Pie','slow-cooker-shepherds-pie','A hearty and classic Shepherds Pie made effortlessly in the slow cooker with savory lamb, vegetables, and a creamy mashed potato topping. This hands-off method delivers deep, rich flavor without standing over the stove.','Slow cooker lamb and vegetable stew topped with fluffy creamy mashed potatoes.','British','Medium',25,360,385,6,480,30,42,20,6,'[{"amount":1.5,"unit":"lbs","item":"ground lamb","group":"main"},{"amount":1,"unit":"cup","item":"frozen peas and carrots","group":"vegetables"},{"amount":1,"unit":"whole","item":"yellow onion, diced","group":"aromatics"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"tomato paste","group":"sauce"},{"amount":1,"unit":"cup","item":"beef broth","group":"sauce"},{"amount":2,"unit":"lbs","item":"russet potatoes, peeled and cubed","group":"topping"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"topping"},{"amount":0.5,"unit":"cup","item":"whole milk","group":"topping"},{"amount":1,"unit":"tbsp","item":"Worcestershire sauce","group":"sauce"}]','[{"title":"Brown the Lamb","text":"In a skillet over medium-high heat, brown the ground lamb until cooked through, about 8 minutes. Drain excess fat. Add the diced onion and garlic and cook for 3 more minutes.","timer":660},{"title":"Load the Slow Cooker","text":"Transfer the lamb and onion mixture to the slow cooker. Add the frozen peas and carrots, beef broth, tomato paste, and Worcestershire sauce. Stir everything together and season with salt and pepper. Cover and cook on low for 6 hours.","timer":21600},{"title":"Make the Mashed Potatoes","text":"About 30 minutes before serving, boil the cubed potatoes in salted water until fork-tender, about 15 minutes. Drain and mash with butter and warm milk until smooth and creamy. Season well with salt.","timer":900},{"title":"Top and Finish","text":"Spoon the mashed potatoes evenly over the lamb mixture in the slow cooker. Spread into an even layer with a spatula. Place the lid back on and cook on high for 15 more minutes to set the topping.","timer":900},{"title":"Serve","text":"Scoop portions of the Shepherds Pie into bowls or onto plates, making sure to get both the lamb filling and the mashed potato topping in each serving. Garnish with chopped fresh parsley.","timer":0}]','[{"original":"ground lamb","swap":"ground beef for a Cottage Pie variation"},{"original":"russet potatoes","swap":"cauliflower for a lower carb mashed topping"},{"original":"beef broth","swap":"vegetable broth or chicken broth"}]','["Do not skip browning the lamb as this step adds essential depth and flavor to the dish","Do not add the mashed potato topping at the beginning or it will dissolve into the filling","Do not use cold milk when mashing potatoes as it makes the mash gluey and dense"]','["shepherds pie","slow cooker","lamb","comfort food","british","mashed potatoes"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Shrimp Pasta','garlic-butter-shrimp-pasta','Succulent shrimp tossed in a rich garlic butter white wine sauce served over linguine pasta. This elegant yet simple dish comes together in under 30 minutes for a restaurant-quality dinner at home.','Juicy shrimp in garlic butter sauce tossed with linguine for a fast weeknight pasta.','Italian-American','Easy',10,20,30,4,490,34,52,16,2,'[{"amount":1,"unit":"lb","item":"large shrimp, peeled and deveined","group":"main"},{"amount":12,"unit":"oz","item":"linguine pasta","group":"main"},{"amount":5,"unit":"cloves","item":"garlic, minced","group":"aromatics"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"fat"},{"amount":0.5,"unit":"cup","item":"dry white wine","group":"sauce"},{"amount":0.25,"unit":"cup","item":"fresh parsley, chopped","group":"garnish"},{"amount":1,"unit":"whole","item":"lemon, juiced and zested","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"spices"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"},{"amount":0.5,"unit":"cup","item":"grated Parmesan cheese","group":"topping"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of heavily salted water to a boil. Cook the linguine according to package directions until al dente. Reserve 1 cup of pasta water before draining.","timer":600},{"title":"Cook the Shrimp","text":"Heat olive oil in a large skillet over medium-high heat. Season shrimp with salt and pepper. Cook for 1 to 2 minutes per side until pink and just cooked through. Remove shrimp and set aside.","timer":240},{"title":"Build the Garlic Butter Sauce","text":"Reduce heat to medium and add butter to the same skillet. Once melted, add garlic and red pepper flakes and cook for 1 minute. Pour in the white wine and lemon juice and simmer for 3 minutes until slightly reduced.","timer":240},{"title":"Toss Everything Together","text":"Add the drained linguine to the skillet and toss to coat in the sauce. Add a splash of reserved pasta water to loosen if needed. Return the shrimp to the pan and toss gently to combine.","timer":120},{"title":"Finish and Serve","text":"Stir in the lemon zest and fresh parsley. Plate the pasta and top with grated Parmesan cheese. Serve immediately with extra lemon wedges on the side.","timer":0}]','[{"original":"dry white wine","swap":"chicken broth with a splash of extra lemon juice"},{"original":"linguine","swap":"spaghetti or fettuccine"},{"original":"large shrimp","swap":"sea scallops or chunks of firm white fish"}]','["Do not overcook the shrimp as they become rubbery and tough very quickly","Do not add the pasta to the sauce without reserved pasta water on hand to adjust consistency","Do not use pre-grated Parmesan from a can as it does not melt smoothly into the dish"]','["shrimp","pasta","garlic butter","quick","weeknight","seafood"]','["pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Sriracha Baked Chicken Thighs','honey-sriracha-baked-chicken-thighs','Juicy bone-in chicken thighs glazed with a sweet and spicy honey Sriracha sauce and baked until the skin is perfectly caramelized. This bold dish pairs beautifully with steamed rice or roasted vegetables.','Sweet and spicy glazed chicken thighs baked to crispy caramelized perfection.','Asian-American','Easy',10,40,50,4,440,36,22,22,1,'[{"amount":4,"unit":"whole","item":"bone-in skin-on chicken thighs","group":"main"},{"amount":3,"unit":"tbsp","item":"honey","group":"sauce"},{"amount":2,"unit":"tbsp","item":"Sriracha sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"aromatics"},{"amount":1,"unit":"tbsp","item":"fresh ginger, grated","group":"aromatics"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"fat"},{"amount":1,"unit":"tbsp","item":"sesame seeds","group":"garnish"},{"amount":2,"unit":"stalks","item":"green onion, sliced","group":"garnish"}]','[{"title":"Preheat and Prepare","text":"Preheat your oven to 400 degrees F. Pat the chicken thighs dry with paper towels and season both sides generously with salt and pepper. Place them skin-side up in a lightly oiled baking dish.","timer":0},{"title":"Mix the Glaze","text":"In a small bowl, whisk together the honey, Sriracha, soy sauce, minced garlic, grated ginger, rice vinegar, and sesame oil until fully combined. Taste and adjust heat level as desired.","timer":0},{"title":"Glaze and Bake","text":"Spoon half of the honey Sriracha glaze generously over the top of each chicken thigh. Reserve the remaining glaze. Bake in the preheated oven for 25 minutes.","timer":1500},{"title":"Re-Glaze and Finish Baking","text":"Remove the chicken from the oven and brush the remaining glaze over the top of each piece. Return to the oven and bake for another 15 minutes until the skin is caramelized and the internal temperature reaches 165 degrees F.","timer":900},{"title":"Rest and Serve","text":"Let the chicken thighs rest for 5 minutes before serving. Sprinkle with sesame seeds and sliced green onion. Serve over steamed jasmine rice with extra sauce spooned from the pan.","timer":300}]','[{"original":"Sriracha sauce","swap":"sambal oelek or gochujang for a different heat profile"},{"original":"honey","swap":"maple syrup for a slightly earthier sweetness"},{"original":"bone-in chicken thighs","swap":"boneless chicken thighs, reducing cook time by 10 minutes"}]','["Do not skip patting the chicken dry as moisture on the skin prevents proper caramelization","Do not apply all the glaze at once as a second coat during baking creates a better lacquered finish","Do not cut into the chicken immediately after baking as resting allows the juices to redistribute"]','["chicken","honey sriracha","baked","spicy","asian-inspired","weeknight"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Smoky BBQ Pork Ribs','smoky-bbq-pork-ribs','Fall-off-the-bone pork ribs coated in a rich smoky spice rub and finished with tangy BBQ sauce. These ribs are slow-cooked to tender perfection with a caramelized glaze.','Slow-baked smoky pork ribs with a bold spice rub and sticky BBQ glaze.','American','Medium',20,180,200,4,720,52,28,44,1,'[{"amount":2,"unit":"kg","item":"pork baby back ribs","group":"main"},{"amount":2,"unit":"tbsp","item":"smoked paprika","group":"spice rub"},{"amount":1,"unit":"tbsp","item":"brown sugar","group":"spice rub"},{"amount":1,"unit":"tbsp","item":"garlic powder","group":"spice rub"},{"amount":1,"unit":"tsp","item":"cayenne pepper","group":"spice rub"},{"amount":1,"unit":"tsp","item":"black pepper","group":"spice rub"},{"amount":1,"unit":"tsp","item":"salt","group":"spice rub"},{"amount":240,"unit":"ml","item":"BBQ sauce","group":"glaze"},{"amount":2,"unit":"tbsp","item":"apple cider vinegar","group":"glaze"}]','[{"title":"Prepare the Spice Rub","text":"Mix smoked paprika, brown sugar, garlic powder, cayenne pepper, black pepper, and salt in a small bowl. Remove the membrane from the back of the ribs by sliding a knife under it and pulling it off completely.","timer":0},{"title":"Season the Ribs","text":"Coat all sides of the ribs generously with the spice rub, pressing it firmly into the meat. Wrap the ribs tightly in foil and let them rest for at least 30 minutes to absorb the flavors.","timer":1800},{"title":"Slow Bake the Ribs","text":"Preheat the oven to 150 degrees Celsius. Place the foil-wrapped ribs on a baking tray and cook for 2.5 hours. The low and slow heat breaks down the collagen making the ribs extremely tender.","timer":9000},{"title":"Glaze with BBQ Sauce","text":"Mix the BBQ sauce with apple cider vinegar. Carefully unwrap the ribs and brush the glaze generously over both sides. Return them to the oven uncovered at 200 degrees Celsius for 20 minutes until caramelized.","timer":1200},{"title":"Rest and Serve","text":"Remove the ribs from the oven and let them rest for 10 minutes before slicing between the bones. Serve with remaining BBQ sauce on the side and your favorite sides.","timer":600}]','[{"original":"baby back ribs","swap":"spare ribs for a meatier cut with slightly longer cooking time"},{"original":"smoked paprika","swap":"regular paprika plus a few drops of liquid smoke"},{"original":"BBQ sauce","swap":"hoisin sauce mixed with a splash of worcestershire for an Asian twist"}]','["Skipping the membrane removal causes chewy and tough ribs that do not absorb seasoning well","Cooking at too high a temperature makes the ribs dry before they become tender","Applying the BBQ glaze too early causes it to burn before the ribs are fully cooked"]','["BBQ","pork","ribs","smoky","slow-cooked","grilling","summer"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Savory Lamb Stew','savory-lamb-stew','A hearty and warming lamb stew loaded with root vegetables and rich aromatic broth. Slow-simmered until the lamb is meltingly tender and the sauce is deeply flavorful.','Rich slow-simmered lamb stew with root vegetables and fragrant herbs.','Mediterranean','Medium',25,120,145,6,580,42,32,28,5,'[{"amount":1.2,"unit":"kg","item":"lamb shoulder cut into chunks","group":"main"},{"amount":3,"unit":"medium","item":"carrots chopped","group":"vegetables"},{"amount":3,"unit":"medium","item":"potatoes cubed","group":"vegetables"},{"amount":2,"unit":"medium","item":"onions diced","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":400,"unit":"ml","item":"beef or lamb stock","group":"liquid"},{"amount":2,"unit":"tbsp","item":"tomato paste","group":"base"},{"amount":2,"unit":"tsp","item":"fresh rosemary chopped","group":"herbs"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"cooking"}]','[{"title":"Brown the Lamb","text":"Heat olive oil in a large heavy pot over high heat. Season the lamb chunks with salt and pepper and brown them in batches without overcrowding the pan. This step builds the deep base flavor of the stew.","timer":600},{"title":"Saute the Aromatics","text":"Lower the heat to medium and add onions and garlic to the same pot. Cook for 5 minutes until softened. Stir in the tomato paste and cook for another 2 minutes to caramelize it slightly.","timer":420},{"title":"Build the Stew","text":"Return the browned lamb to the pot and pour in the stock. Add the rosemary and stir everything together. Bring to a boil then reduce heat to a gentle simmer and cover the pot.","timer":300},{"title":"Add Vegetables and Simmer","text":"After 45 minutes of simmering add the carrots and potatoes. Continue cooking covered for another 45 minutes until the lamb is completely tender and the vegetables are soft. Check seasoning and adjust.","timer":5400},{"title":"Finish and Serve","text":"Remove the lid and let the stew simmer uncovered for 10 minutes to thicken the sauce. Ladle into bowls and garnish with fresh parsley. Serve with crusty bread or over mashed potatoes.","timer":600}]','[{"original":"lamb shoulder","swap":"lamb leg or beef chuck for a similar hearty texture"},{"original":"beef or lamb stock","swap":"vegetable stock with a splash of worcestershire sauce for added depth"},{"original":"rosemary","swap":"thyme or a combination of dried oregano and bay leaves"}]','["Not browning the lamb in batches causes steaming instead of searing which loses flavor","Adding the vegetables too early turns them to mush before the lamb is tender","Cooking at too high a simmer makes the lamb tough and dries out the stew"]','["lamb","stew","comfort food","slow-cooked","hearty","winter","one-pot"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Herb Pork Tenderloin','garlic-herb-pork-tenderloin','Juicy oven-roasted pork tenderloin encrusted with garlic and fresh herbs for an elegant yet simple meal. The quick cooking time keeps the meat perfectly moist and full of flavor.','Tender oven-roasted pork with a fragrant garlic and herb crust ready in under an hour.','American','Easy',15,30,45,4,320,46,4,13,1,'[{"amount":700,"unit":"g","item":"pork tenderloin","group":"main"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"fresh rosemary chopped","group":"herbs"},{"amount":2,"unit":"tbsp","item":"fresh thyme leaves","group":"herbs"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":1,"unit":"tbsp","item":"dijon mustard","group":"coating"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Prepare the Herb Paste","text":"Combine minced garlic, rosemary, thyme, olive oil, dijon mustard, salt, and black pepper in a small bowl. Mix well to form a thick paste that will coat the tenderloin evenly.","timer":0},{"title":"Coat the Tenderloin","text":"Pat the pork tenderloin dry with paper towels to ensure proper browning. Rub the herb paste all over the surface of the meat pressing it firmly so it adheres. Let the coated tenderloin rest at room temperature for 10 minutes.","timer":600},{"title":"Sear the Pork","text":"Preheat oven to 200 degrees Celsius. Heat an oven-safe skillet over high heat and sear the tenderloin for 2 minutes on each side until a golden crust forms. Do not move the meat while it is searing.","timer":240},{"title":"Roast in the Oven","text":"Transfer the skillet directly to the preheated oven and roast for 20 to 25 minutes until the internal temperature reaches 63 degrees Celsius. The herb crust will become fragrant and slightly caramelized.","timer":1500},{"title":"Rest and Slice","text":"Remove the tenderloin from the oven and let it rest uncovered on a cutting board for 10 minutes. Resting allows the juices to redistribute throughout the meat. Slice into medallions and serve immediately.","timer":600}]','[{"original":"fresh rosemary","swap":"dried rosemary using half the amount as dried herbs are more concentrated"},{"original":"dijon mustard","swap":"whole grain mustard or a teaspoon of honey for a slightly sweeter crust"},{"original":"pork tenderloin","swap":"chicken breast though reduce cooking time to avoid drying out"}]','["Skipping the resting period causes all the juices to run out when slicing leaving dry meat","Overcooking the tenderloin past 70 degrees Celsius results in dry and tough texture","Not patting the meat dry before searing prevents proper browning and crust formation"]','["pork","tenderloin","garlic","herbs","roasted","quick","weeknight dinner"]','["gluten-free","dairy-free","low-carb"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Burger','classic-beef-burger','A juicy homemade beef burger with perfectly seasoned patties and all the classic toppings. Grilled or pan-seared to a golden crust with a tender and flavorful center.','Juicy seasoned beef burgers with classic toppings ready in under 30 minutes.','American','Easy',10,15,25,4,620,38,42,32,2,'[{"amount":600,"unit":"g","item":"ground beef 80 percent lean","group":"main"},{"amount":4,"unit":"whole","item":"burger buns","group":"bread"},{"amount":4,"unit":"slices","item":"cheddar cheese","group":"toppings"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"onion powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"worcestershire sauce","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"vegetable oil","group":"cooking"}]','[{"title":"Season and Form Patties","text":"Combine ground beef with garlic powder, onion powder, worcestershire sauce, salt, and pepper in a bowl. Mix gently and do not overwork the meat. Divide into 4 equal portions and shape into patties slightly wider than the buns as they will shrink during cooking.","timer":0},{"title":"Create a Dimple","text":"Press a shallow dimple into the center of each patty with your thumb. This prevents the burgers from puffing up into a dome shape during cooking and ensures even flat patties.","timer":0},{"title":"Cook the Patties","text":"Heat oil in a skillet or grill pan over high heat. Cook the patties for 3 to 4 minutes per side without pressing them down. Pressing squeezes out the juices and makes the burgers dry.","timer":480},{"title":"Add Cheese and Toast Buns","text":"Place a slice of cheddar on each patty in the last minute of cooking and cover the pan to melt the cheese. At the same time toast the cut sides of the buns in a separate pan with a little butter until golden.","timer":60},{"title":"Assemble and Serve","text":"Let the patties rest for 2 minutes then assemble the burgers with your preferred toppings such as lettuce, tomato, onion, and condiments. Serve immediately while the patties are hot and the buns are warm.","timer":120}]','[{"original":"ground beef","swap":"ground turkey or chicken for a leaner patty with adjusted seasoning"},{"original":"cheddar cheese","swap":"Swiss, pepper jack, or provolone for different flavor profiles"},{"original":"burger buns","swap":"portobello mushroom caps or lettuce wraps for a low-carb option"}]','["Overworking the ground beef mixture makes the patties dense and tough instead of tender","Pressing down on the patties while cooking squeezes out the juices resulting in dry burgers","Cooking on heat that is too low causes the patties to steam rather than develop a proper crust"]','["burger","beef","grilling","classic","American","quick","comfort food"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Chicken Thighs','honey-garlic-chicken-thighs','Succulent chicken thighs glazed in a sticky sweet and savory honey garlic sauce with a beautiful caramelized finish. This simple one-pan recipe delivers bold flavors with minimal effort.','Sticky honey garlic chicken thighs cooked in one pan with a rich caramelized glaze.','Asian-American','Easy',10,30,40,4,480,36,22,26,0,'[{"amount":8,"unit":"pieces","item":"bone-in skin-on chicken thighs","group":"main"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":3,"unit":"tbsp","item":"honey","group":"sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"apple cider vinegar","group":"sauce"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"aromatics"}]','[{"title":"Season the Chicken","text":"Pat the chicken thighs completely dry with paper towels and season generously with salt and pepper on both sides. Drying the skin is essential for achieving a crispy result when searing.","timer":0},{"title":"Sear the Chicken Skin Side Down","text":"Heat olive oil in a large oven-safe skillet over medium-high heat. Place the chicken thighs skin side down and cook without moving them for 8 to 10 minutes until the skin is deeply golden and crispy.","timer":600},{"title":"Make the Honey Garlic Sauce","text":"Flip the chicken thighs and reduce heat to medium. Push them to the edges of the pan and add garlic and ginger to the center. Cook for 1 minute then stir in honey, soy sauce, and apple cider vinegar.","timer":60},{"title":"Roast in the Oven","text":"Spoon the sauce over the chicken and transfer the skillet to an oven preheated to 190 degrees Celsius. Roast for 15 to 18 minutes until the internal temperature reaches 74 degrees Celsius and the glaze thickens.","timer":1080},{"title":"Rest and Serve","text":"Remove from the oven and let the chicken rest for 5 minutes. Spoon extra sauce from the pan over the thighs before serving. Serve over steamed rice or with roasted vegetables.","timer":300}]','[{"original":"bone-in skin-on chicken thighs","swap":"boneless thighs or chicken breasts though reduce cooking time to prevent drying out"},{"original":"honey","swap":"maple syrup or agave nectar for a different natural sweetness"},{"original":"soy sauce","swap":"tamari or coconut aminos for a gluten-free alternative"}]','["Not drying the chicken skin before searing results in soggy skin that does not crisp properly","Moving the chicken while searing prevents the skin from releasing naturally and tears the crust","Adding the honey sauce too early over direct high heat causes it to burn before the chicken is cooked"]','["chicken","honey garlic","one-pan","Asian-American","weeknight","sticky glaze","easy"]','["gluten-free option","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Peanut Noodles with Shrimp','spicy-peanut-noodles-with-shrimp','Bold peanut sauce coats silky noodles and tender shrimp in this quick weeknight dinner. A perfect balance of heat, salt, and richness.','Saucy peanut noodles tossed with juicy shrimp and a fiery kick.','Asian Fusion','Easy',15,15,30,4,520,32,58,18,4,'[{"amount":8,"unit":"oz","item":"lo mein noodles","group":"noodles"},{"amount":1,"unit":"lb","item":"large shrimp, peeled and deveined","group":"protein"},{"amount":0.33,"unit":"cup","item":"creamy peanut butter","group":"sauce"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"sriracha","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"sauce"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"aromatics"},{"amount":1,"unit":"tbsp","item":"fresh ginger, grated","group":"aromatics"},{"amount":2,"unit":"stalks","item":"green onions, sliced","group":"garnish"}]','[{"title":"Cook the Noodles","text":"Bring a large pot of salted water to a boil. Cook lo mein noodles according to package directions until al dente. Reserve half a cup of pasta water before draining, then rinse noodles under cold water to stop cooking.","timer":480},{"title":"Make the Peanut Sauce","text":"In a bowl, whisk together peanut butter, soy sauce, sriracha, sesame oil, minced garlic, and grated ginger. Add two to four tablespoons of reserved pasta water and whisk until smooth and pourable.","timer":120},{"title":"Cook the Shrimp","text":"Heat a large skillet or wok over high heat with a drizzle of neutral oil. Add shrimp in a single layer and cook for one to two minutes per side until pink and opaque. Do not overcrowd the pan or the shrimp will steam instead of sear.","timer":180},{"title":"Toss Everything Together","text":"Reduce heat to medium and add the drained noodles to the skillet with the shrimp. Pour the peanut sauce over the top and toss vigorously to coat everything evenly. Add more pasta water a tablespoon at a time if the sauce feels too thick.","timer":120},{"title":"Garnish and Serve","text":"Divide noodles into bowls and top with sliced green onions. Optionally add crushed peanuts, lime wedges, or extra sriracha for serving. Serve immediately while warm.","timer":60}]','[{"original":"lo mein noodles","swap":"spaghetti or rice noodles"},{"original":"shrimp","swap":"thinly sliced chicken breast or tofu"},{"original":"sriracha","swap":"chili garlic sauce or red pepper flakes"}]','["Overcooking the shrimp until rubbery by leaving them in the pan too long","Skipping the pasta water which is essential for loosening the peanut sauce","Using noodles that are too thick which causes the sauce to clump rather than coat"]','["spicy","peanut","noodles","shrimp","weeknight","quick","asian"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cedar Plank Salmon','cedar-plank-salmon','Grilling salmon on a soaked cedar plank infuses every bite with a gentle smoky woodsy aroma. The plank insulates the fish for perfectly moist and flavorful results.','Smoky cedar-infused grilled salmon with a sweet herb glaze.','American','Medium',20,20,40,4,410,45,8,22,1,'[{"amount":2,"unit":"lbs","item":"salmon fillet, skin on","group":"protein"},{"amount":1,"unit":"piece","item":"untreated cedar grilling plank","group":"equipment"},{"amount":2,"unit":"tbsp","item":"brown sugar","group":"glaze"},{"amount":2,"unit":"tbsp","item":"Dijon mustard","group":"glaze"},{"amount":1,"unit":"tbsp","item":"soy sauce","group":"glaze"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"glaze"},{"amount":1,"unit":"tbsp","item":"fresh dill, chopped","group":"herbs"},{"amount":1,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"whole","item":"lemon, sliced thin","group":"garnish"}]','[{"title":"Soak the Cedar Plank","text":"Fully submerge the cedar plank in water for at least one hour before grilling. Use a heavy pot or bowl to weigh it down so it stays fully submerged. A longer soak of up to two hours produces even more steam and reduces charring.","timer":3600},{"title":"Prepare the Glaze and Salmon","text":"In a small bowl mix brown sugar, Dijon mustard, soy sauce, and minced garlic until combined. Pat the salmon dry with paper towels and season the flesh side with black pepper. Spread the glaze evenly over the top of the fillet.","timer":300},{"title":"Preheat the Grill","text":"Heat your grill to medium-high heat, around 400 to 425 degrees Fahrenheit. Place the soaked cedar plank directly on the grill grates and close the lid. Heat the plank for three to four minutes until it begins to smoke and crackle.","timer":240},{"title":"Grill the Salmon","text":"Place the glazed salmon skin side down onto the hot cedar plank. Close the lid and grill for 14 to 18 minutes depending on thickness. The salmon is done when it flakes easily with a fork and reaches an internal temperature of 145 degrees Fahrenheit. Do not flip the salmon.","timer":1020},{"title":"Rest and Serve","text":"Carefully remove the plank from the grill using heat-resistant gloves. Let the salmon rest on the plank for three minutes before serving. Top with fresh dill and lemon slices and serve directly from the plank for dramatic presentation.","timer":180}]','[{"original":"cedar plank","swap":"aluminum foil pouch with liquid smoke added"},{"original":"fresh dill","swap":"fresh thyme or rosemary"},{"original":"brown sugar","swap":"maple syrup or honey"}]','["Not soaking the plank long enough which causes it to catch fire during grilling","Opening the grill lid repeatedly which drops the temperature and dries out the fish","Using a chemically treated or painted wood plank which releases harmful compounds when burned"]','["salmon","grilling","cedar","smoky","summer","seafood"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Salmon Patties','classic-salmon-patties','Crispy golden salmon patties made from pantry staples come together in under 30 minutes. They are tender inside with a satisfying crunch on the outside.','Crispy pan-fried salmon patties that are quick, budget-friendly, and delicious.','American','Easy',10,12,22,4,310,28,14,16,1,'[{"amount":14.75,"unit":"oz","item":"canned salmon, drained and flaked","group":"protein"},{"amount":0.5,"unit":"cup","item":"breadcrumbs","group":"binder"},{"amount":1,"unit":"large","item":"egg, beaten","group":"binder"},{"amount":3,"unit":"tbsp","item":"mayonnaise","group":"binder"},{"amount":2,"unit":"tbsp","item":"Dijon mustard","group":"flavoring"},{"amount":0.25,"unit":"cup","item":"celery, finely diced","group":"vegetables"},{"amount":2,"unit":"tbsp","item":"fresh parsley, chopped","group":"herbs"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"neutral oil for frying","group":"cooking"}]','[{"title":"Mix the Salmon Mixture","text":"In a large bowl combine drained and flaked salmon, breadcrumbs, beaten egg, mayonnaise, Dijon mustard, diced celery, parsley, and garlic powder. Mix gently with a fork until just combined. Do not overmix or the patties will become dense and tough.","timer":180},{"title":"Form the Patties","text":"Divide the mixture into eight equal portions and gently shape each into a patty about half an inch thick. Place them on a plate and refrigerate for five minutes to help them hold their shape during cooking.","timer":300},{"title":"Heat the Pan","text":"Heat a large skillet over medium-high heat and add neutral oil. Swirl the pan to coat the bottom evenly. The oil is ready when a small breadcrumb dropped in sizzles immediately.","timer":120},{"title":"Pan Fry the Patties","text":"Add patties to the hot skillet in a single layer without overcrowding. Cook for three to four minutes on the first side without moving them until a deep golden crust forms. Flip once and cook another two to three minutes on the second side.","timer":420},{"title":"Drain and Serve","text":"Transfer cooked patties to a paper towel-lined plate to drain any excess oil. Serve warm with tartar sauce, lemon wedges, or alongside a simple green salad.","timer":60}]','[{"original":"canned salmon","swap":"canned tuna or leftover cooked salmon"},{"original":"breadcrumbs","swap":"crushed crackers or panko"},{"original":"mayonnaise","swap":"Greek yogurt for a lighter version"}]','["Skipping the chilling step which causes patties to fall apart when flipped","Using too high heat which burns the outside before the inside is heated through","Not draining the canned salmon well enough which makes the mixture too wet to hold together"]','["salmon","patties","canned salmon","quick","budget","pan-fried"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Glazed Salmon','honey-garlic-glazed-salmon','This sticky honey garlic glaze caramelizes beautifully on pan-seared salmon fillets creating an irresistible sweet and savory crust. Ready in under 20 minutes with minimal cleanup.','Sweet sticky honey garlic salmon seared to perfection in one pan.','American','Easy',5,12,17,4,380,42,18,14,0,'[{"amount":4,"unit":"pieces","item":"salmon fillets, 6 oz each","group":"protein"},{"amount":3,"unit":"tbsp","item":"honey","group":"glaze"},{"amount":4,"unit":"cloves","item":"garlic, minced","group":"glaze"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"glaze"},{"amount":1,"unit":"tbsp","item":"butter","group":"cooking"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":1,"unit":"tsp","item":"red pepper flakes","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"whole","item":"lemon, juiced","group":"finishing"}]','[{"title":"Prepare the Salmon","text":"Pat the salmon fillets completely dry with paper towels. Season both sides with black pepper and red pepper flakes. Drying the fish thoroughly is critical for achieving a proper sear and preventing steaming in the pan.","timer":120},{"title":"Mix the Glaze","text":"In a small bowl whisk together honey, minced garlic, and soy sauce until fully combined. Set aside near the stove so it is ready when needed. The mixture will look thin at this stage but thickens beautifully when it hits the hot pan.","timer":60},{"title":"Sear the Salmon","text":"Heat olive oil and butter in a large oven-safe skillet over medium-high heat. Once the butter is foamy add the salmon fillets flesh side down. Sear without moving for four to five minutes until a golden crust forms.","timer":300},{"title":"Add the Glaze","text":"Flip the salmon fillets skin side down. Pour the honey garlic mixture directly over the fillets. Cook for another three to four minutes spooning the glaze over the top repeatedly as it bubbles and thickens. Do not walk away as the honey can burn quickly.","timer":240},{"title":"Finish and Plate","text":"Squeeze fresh lemon juice over the salmon and remove from heat. Let rest in the pan for two minutes before plating. Spoon any remaining glaze from the pan over the fillets before serving.","timer":120}]','[{"original":"honey","swap":"maple syrup or agave nectar"},{"original":"soy sauce","swap":"coconut aminos for a lower sodium option"},{"original":"butter","swap":"ghee or additional olive oil for dairy-free version"}]','["Not drying the salmon fillets before searing which results in steaming instead of a golden crust","Moving the salmon too early before a crust has formed causing it to tear and stick","Cooking the glaze on heat that is too high which burns the honey before the salmon is cooked through"]','["salmon","honey garlic","quick","weeknight","glazed","one pan"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Teriyaki Salmon Bowl','teriyaki-salmon-bowl','Flaky teriyaki-glazed salmon sits over steamed rice with crisp vegetables for a complete and satisfying meal. Homemade teriyaki sauce takes only minutes and beats anything from a bottle.','A nourishing bowl of teriyaki salmon over rice with fresh vegetables.','Japanese','Easy',10,20,30,4,545,40,62,13,3,'[{"amount":4,"unit":"pieces","item":"salmon fillets, 6 oz each","group":"protein"},{"amount":2,"unit":"cups","item":"jasmine rice, uncooked","group":"base"},{"amount":0.25,"unit":"cup","item":"soy sauce","group":"teriyaki sauce"},{"amount":2,"unit":"tbsp","item":"mirin","group":"teriyaki sauce"},{"amount":2,"unit":"tbsp","item":"brown sugar","group":"teriyaki sauce"},{"amount":1,"unit":"tsp","item":"sesame oil","group":"teriyaki sauce"},{"amount":1,"unit":"cup","item":"shelled edamame, thawed","group":"vegetables"},{"amount":1,"unit":"large","item":"cucumber, sliced thin","group":"vegetables"},{"amount":1,"unit":"tbsp","item":"sesame seeds for garnish","group":"garnish"}]','[{"title":"Cook the Rice","text":"Rinse jasmine rice under cold water until the water runs clear. Cook according to package directions using a rice cooker or stovetop method. Fluff with a fork when done and keep covered to stay warm.","timer":1200},{"title":"Make the Teriyaki Sauce","text":"In a small saucepan combine soy sauce, mirin, brown sugar, and sesame oil over medium heat. Stir and bring to a gentle simmer. Cook for three to four minutes until the sugar dissolves and the sauce thickens slightly. Remove from heat and set aside.","timer":240},{"title":"Cook the Salmon","text":"Heat a non-stick skillet over medium-high heat with a small amount of oil. Add the salmon fillets skin side up and cook for three minutes. Flip to skin side down and cook another three minutes until almost cooked through.","timer":360},{"title":"Glaze the Salmon","text":"Pour half the teriyaki sauce over the salmon fillets in the pan. Cook for one to two more minutes basting constantly until the glaze is sticky and caramelized. The internal temperature should reach 145 degrees Fahrenheit.","timer":120},{"title":"Assemble the Bowls","text":"Divide steamed rice among four bowls. Place one salmon fillet over the rice in each bowl. Arrange cucumber slices and edamame alongside the salmon. Drizzle with remaining teriyaki sauce and sprinkle with sesame seeds before serving.","timer":120}]','[{"original":"mirin","swap":"dry sherry or rice vinegar with an extra teaspoon of sugar"},{"original":"jasmine rice","swap":"brown rice or cauliflower rice for lower carbs"},{"original":"edamame","swap":"shelled peas or steamed broccoli florets"}]','["Burning the teriyaki sauce by cooking it on heat that is too high which makes it bitter","Skipping the rice rinse step which results in sticky gummy rice in the bowl","Overcooking the salmon until dry because the glaze makes it look underdone even when finished"]','["salmon","teriyaki","rice bowl","japanese","meal prep","healthy"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Blackened Fish Tacos','blackened-fish-tacos','Crispy blackened fish nestled in warm tortillas with crunchy slaw and creamy chipotle sauce. Bold Cajun spices create an irresistible char that makes every bite unforgettable.','Spicy blackened fish tacos with tangy slaw and smoky chipotle crema ready in under 30 minutes.','Mexican-American','Easy',15,10,25,4,420,32,38,16,4,'[{"amount":1.5,"unit":"lbs","item":"tilapia fillets","group":"fish"},{"amount":2,"unit":"tbsp","item":"Cajun seasoning","group":"spices"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"spices"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":8,"unit":"pieces","item":"small flour tortillas","group":"base"},{"amount":2,"unit":"cups","item":"shredded cabbage","group":"slaw"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"sauce"},{"amount":2,"unit":"tsp","item":"chipotle in adobo sauce","group":"sauce"},{"amount":1,"unit":"whole","item":"lime","group":"garnish"},{"amount":0.25,"unit":"cup","item":"fresh cilantro","group":"garnish"}]','[{"title":"Season the Fish","text":"Pat tilapia fillets completely dry with paper towels. Combine Cajun seasoning and smoked paprika in a small bowl. Coat both sides of each fillet generously with the spice mixture pressing firmly so it adheres.","timer":0},{"title":"Make Chipotle Crema","text":"In a small bowl whisk together sour cream and chipotle in adobo sauce until smooth. Add a squeeze of lime juice and a pinch of salt. Set aside in the refrigerator until ready to serve.","timer":0},{"title":"Cook the Fish","text":"Heat olive oil in a cast iron skillet over high heat until it begins to smoke. Add the seasoned fillets and cook without moving them for 3 to 4 minutes per side until a dark blackened crust forms and fish flakes easily.","timer":480},{"title":"Warm Tortillas and Prep Slaw","text":"While the fish rests warm tortillas directly over a gas flame or in a dry skillet for 30 seconds per side. Toss shredded cabbage with a squeeze of lime juice and a pinch of salt to make a quick slaw.","timer":60},{"title":"Assemble and Serve","text":"Break the cooked fish into large chunks and divide among the warm tortillas. Top with chipotle crema, lime slaw, and fresh cilantro. Serve immediately with extra lime wedges on the side.","timer":0}]','[{"original":"tilapia","swap":"mahi mahi or catfish"},{"original":"sour cream","swap":"Greek yogurt"},{"original":"flour tortillas","swap":"corn tortillas for gluten free"}]','["Not drying the fish before seasoning which prevents a proper blackened crust from forming","Using too low heat which steams the fish instead of creating the signature char","Moving the fish too early in the pan which causes it to break apart before the crust sets"]','["tacos","fish","blackened","spicy","quick","weeknight"]','["pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Herb Baked Cod','lemon-herb-baked-cod','Tender flaky cod baked with a bright lemon herb crust that is simple yet deeply flavorful. Fresh parsley, garlic, and zesty lemon transform humble cod into an elegant weeknight dinner.','Buttery lemon herb baked cod that is flaky, light, and ready in just 25 minutes.','American','Easy',10,15,25,4,280,36,8,11,1,'[{"amount":1.5,"unit":"lbs","item":"cod fillets","group":"fish"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"fat"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"whole","item":"lemon zested and juiced","group":"citrus"},{"amount":0.25,"unit":"cup","item":"fresh parsley chopped","group":"herbs"},{"amount":1,"unit":"tsp","item":"fresh thyme leaves","group":"herbs"},{"amount":0.33,"unit":"cup","item":"panko breadcrumbs","group":"crust"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Preheat and Prepare","text":"Preheat oven to 400 degrees Fahrenheit. Line a baking sheet with parchment paper and lightly brush with olive oil. Pat cod fillets dry and place them on the prepared baking sheet with space between each piece.","timer":0},{"title":"Make Herb Butter","text":"Melt butter in a small saucepan over medium low heat. Add minced garlic and cook for 1 minute until fragrant but do not let it brown. Remove from heat and stir in lemon zest, parsley, and thyme.","timer":60},{"title":"Prepare Breadcrumb Topping","text":"In a small bowl combine panko breadcrumbs with 1 tablespoon of the herb butter mixture and a pinch of salt. Stir until the breadcrumbs are evenly coated and slightly clumpy.","timer":0},{"title":"Bake the Cod","text":"Spoon the remaining herb butter evenly over each cod fillet. Top each piece with a generous layer of the seasoned panko mixture pressing lightly to adhere. Bake for 12 to 15 minutes until the crust is golden and the fish flakes easily with a fork.","timer":900},{"title":"Finish and Serve","text":"Remove from the oven and squeeze fresh lemon juice over each fillet immediately. Let rest for 2 minutes before plating. Garnish with additional fresh parsley and serve with roasted vegetables or a light salad.","timer":120}]','[{"original":"cod","swap":"haddock or halibut"},{"original":"panko breadcrumbs","swap":"crushed crackers for a gluten free option"},{"original":"fresh thyme","swap":"dried thyme using half the amount"}]','["Skipping drying the fish which creates steam and makes the breadcrumb topping soggy","Overbaking the cod past the point where it becomes rubbery and dry","Using cold butter which does not blend evenly with the herbs and garlic"]','["baked","cod","lemon","herb","healthy","light","quick"]','["pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Miso Glazed Sea Bass','miso-glazed-sea-bass','Silky sea bass fillets lacquered in a sweet and savory miso glaze then broiled to caramelized perfection. This Japanese-inspired dish delivers restaurant quality results with minimal effort.','Umami rich miso glazed sea bass with a gorgeous caramelized crust inspired by Japanese cuisine.','Japanese','Medium',10,12,22,4,380,34,18,17,1,'[{"amount":1.5,"unit":"lbs","item":"sea bass fillets skin on","group":"fish"},{"amount":3,"unit":"tbsp","item":"white miso paste","group":"glaze"},{"amount":2,"unit":"tbsp","item":"mirin","group":"glaze"},{"amount":1,"unit":"tbsp","item":"sake","group":"glaze"},{"amount":1,"unit":"tbsp","item":"soy sauce","group":"glaze"},{"amount":1,"unit":"tbsp","item":"honey","group":"glaze"},{"amount":1,"unit":"tsp","item":"sesame oil","group":"finishing"},{"amount":1,"unit":"tbsp","item":"sesame seeds","group":"garnish"},{"amount":2,"unit":"stalks","item":"green onions thinly sliced","group":"garnish"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"glaze"}]','[{"title":"Prepare the Miso Marinade","text":"In a small bowl whisk together white miso paste, mirin, sake, soy sauce, honey, sesame oil, and grated ginger until completely smooth. Taste and adjust sweetness or saltiness as needed.","timer":0},{"title":"Marinate the Fish","text":"Place sea bass fillets in a shallow dish and coat both sides evenly with the miso marinade. Cover and refrigerate for at least 30 minutes or up to 24 hours for deeper flavor. Do not marinate longer than 24 hours as the miso will begin to cure the fish.","timer":1800},{"title":"Prepare for Broiling","text":"Preheat your broiler to high and position the rack 6 inches from the heating element. Line a baking sheet with aluminum foil and lightly grease it. Remove the fish from the marinade and gently wipe off any excess glaze to prevent burning.","timer":0},{"title":"Broil the Sea Bass","text":"Place the fillets skin side down on the prepared baking sheet. Broil for 8 to 10 minutes until the glaze is deeply caramelized and bubbly and the fish is cooked through. Watch carefully as the glaze can burn quickly due to the natural sugars.","timer":600},{"title":"Garnish and Serve","text":"Remove from the oven and drizzle with a few drops of sesame oil. Sprinkle generously with sesame seeds and sliced green onions. Serve immediately over steamed white rice with pickled ginger on the side.","timer":0}]','[{"original":"sea bass","swap":"black cod or salmon"},{"original":"sake","swap":"dry sherry or additional mirin"},{"original":"white miso","swap":"yellow miso for a slightly stronger flavor"}]','["Not wiping off excess marinade before broiling which causes the glaze to burn black instead of caramelize","Using the oven instead of the broiler which does not create the proper caramelized crust","Marinating the fish for too long which breaks down the delicate texture of the sea bass"]','["miso","sea bass","Japanese","glazed","broiled","umami","elegant"]','["pescatarian","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Shrimp Pasta','garlic-butter-shrimp-pasta','Plump juicy shrimp tossed with al dente linguine in a rich garlic butter white wine sauce. This classic Italian-American dish comes together in under 30 minutes and tastes indulgent without being heavy.','Silky garlic butter shrimp pasta with white wine and fresh herbs ready in 30 minutes.','Italian-American','Easy',10,20,30,4,510,38,52,18,3,'[{"amount":1,"unit":"lb","item":"large shrimp peeled and deveined","group":"protein"},{"amount":12,"unit":"oz","item":"linguine pasta","group":"base"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"fat"},{"amount":5,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":0.5,"unit":"cup","item":"dry white wine","group":"liquid"},{"amount":0.25,"unit":"cup","item":"fresh parsley chopped","group":"herbs"},{"amount":1,"unit":"whole","item":"lemon juiced","group":"citrus"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"spices"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"cup","item":"reserved pasta water","group":"liquid"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of heavily salted water to a boil. Cook linguine according to package directions until al dente. Before draining reserve at least half a cup of starchy pasta water then drain and set the pasta aside.","timer":600},{"title":"Cook the Shrimp","text":"Season shrimp with salt and pepper. Melt 2 tablespoons of butter in a large skillet over medium high heat. Add shrimp in a single layer and cook for 1 to 2 minutes per side until pink and curled. Remove shrimp and set aside on a plate.","timer":240},{"title":"Build the Sauce","text":"In the same skillet reduce heat to medium and add remaining butter. Add minced garlic and red pepper flakes and cook for 1 minute stirring constantly. Pour in white wine and let it reduce by half scraping up any browned bits from the pan.","timer":180},{"title":"Combine Everything","text":"Add the drained pasta to the skillet and toss to coat in the sauce. Add reserved pasta water a splash at a time until the sauce clings to the noodles. Return shrimp to the pan and toss everything together over low heat for 1 minute.","timer":60},{"title":"Finish and Serve","text":"Remove from heat and squeeze fresh lemon juice over the pasta. Add chopped parsley and toss one final time. Divide among bowls and serve immediately with crusty bread for soaking up the extra sauce.","timer":0}]','[{"original":"white wine","swap":"chicken broth for an alcohol free version"},{"original":"linguine","swap":"spaghetti or fettuccine"},{"original":"fresh parsley","swap":"fresh basil for a sweeter herbal note"}]','["Overcooking the shrimp until they become rubbery which happens very quickly so watch closely","Forgetting to reserve pasta water which is essential for creating a silky cohesive sauce","Cooking the garlic over too high heat which makes it bitter and can ruin the entire dish"]','["pasta","shrimp","garlic butter","seafood","quick","weeknight","Italian"]','["pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Salmon Rice Bowl','crispy-salmon-rice-bowl','Golden crispy skinned salmon served over fluffy jasmine rice with fresh vegetables and a tangy sesame soy dressing. This nourishing bowl is packed with omega 3s and bold Asian inspired flavors.','Crispy salmon rice bowls with sesame soy drizzle and fresh vegetables for a healthy satisfying meal.','Asian-American','Easy',15,15,30,2,620,42,58,22,5,'[{"amount":2,"unit":"fillets","item":"salmon skin on each 6 oz","group":"protein"},{"amount":1.5,"unit":"cups","item":"cooked jasmine rice","group":"base"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"dressing"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"dressing"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"dressing"},{"amount":1,"unit":"tsp","item":"honey","group":"dressing"},{"amount":1,"unit":"cup","item":"edamame shelled","group":"vegetables"},{"amount":1,"unit":"whole","item":"avocado sliced","group":"vegetables"},{"amount":1,"unit":"tbsp","item":"sesame seeds","group":"garnish"},{"amount":2,"unit":"tbsp","item":"neutral oil for cooking","group":"cooking"}]','[{"title":"Make the Sesame Dressing","text":"In a small bowl whisk together soy sauce, sesame oil, rice vinegar, and honey until the honey is fully dissolved. Taste and adjust the balance of sweet and salty to your preference. Set aside until serving time.","timer":0},{"title":"Prepare the Salmon","text":"Pat salmon fillets completely dry on all sides especially the skin. Season generously with salt and pepper on both sides. Dry skin is the most important step for achieving a crispy crust so do not skip this.","timer":0},{"title":"Sear the Salmon","text":"Heat neutral oil in a nonstick or stainless steel skillet over medium high heat until shimmering. Place salmon skin side down and press gently with a spatula for 30 seconds. Cook undisturbed for 5 to 6 minutes until the skin is deeply golden and crisp. Flip and cook for 2 more minutes.","timer":480},{"title":"Warm the Edamame","text":"While the salmon cooks place edamame in a small bowl with a splash of water and microwave for 90 seconds until heated through. Season with a pinch of salt and a few drops of sesame oil and toss to combine.","timer":90},{"title":"Assemble the Bowls","text":"Divide cooked jasmine rice between two bowls. Place a salmon fillet skin side up on top of each bowl. Arrange edamame and sliced avocado alongside the fish. Drizzle generously with the sesame soy dressing and finish with sesame seeds.","timer":0}]','[{"original":"jasmine rice","swap":"brown rice or cauliflower rice for lower carbs"},{"original":"edamame","swap":"frozen peas or shelled fava beans"},{"original":"avocado","swap":"thinly sliced cucumber for a lighter option"}]','["Not drying the salmon skin thoroughly which results in steaming instead of crisping","Moving the salmon too soon while it is cooking which tears the skin and prevents even browning","Using too low heat which makes the salmon stick to the pan and the skin soft rather than crispy"]','["salmon","rice bowl","healthy","Asian","crispy","meal prep","omega 3"]','["pescatarian","dairy-free","gluten-free option"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Vodka Sauce Pasta','creamy-vodka-sauce-pasta','A rich and silky pasta dish featuring a tomato cream sauce with a subtle kick from vodka. This classic Italian American recipe is perfect for weeknight dinners or special occasions.','Penne tossed in a luxurious tomato vodka cream sauce ready in under 40 minutes.','Italian American','Easy',10,25,35,4,620,18,72,28,4,'[{"amount":400,"unit":"g","item":"penne pasta","group":"pasta"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"small","item":"yellow onion finely diced","group":"sauce"},{"amount":80,"unit":"ml","item":"vodka","group":"sauce"},{"amount":400,"unit":"g","item":"crushed San Marzano tomatoes","group":"sauce"},{"amount":180,"unit":"ml","item":"heavy cream","group":"sauce"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"sauce"},{"amount":60,"unit":"g","item":"Parmesan cheese grated","group":"topping"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of salted water to a boil. Cook penne according to package instructions until al dente. Reserve 120 ml of pasta water before draining.","timer":600},{"title":"Saute the Aromatics","text":"Heat olive oil in a large skillet over medium heat. Add diced onion and cook for 5 minutes until softened. Add minced garlic and red pepper flakes and cook for 1 more minute until fragrant.","timer":360},{"title":"Add Vodka and Tomatoes","text":"Pour in the vodka and let it cook off for 2 to 3 minutes while stirring. Add the crushed tomatoes, season with salt, and simmer over medium low heat for 10 minutes to deepen the flavor.","timer":780},{"title":"Finish with Cream","text":"Reduce heat to low and stir in the heavy cream. Simmer gently for 3 to 4 minutes until the sauce thickens and turns a deep orange color. Adjust seasoning as needed.","timer":240},{"title":"Combine and Serve","text":"Toss the drained pasta into the sauce, adding reserved pasta water a little at a time to reach desired consistency. Serve immediately topped with grated Parmesan cheese.","timer":60}]','[{"original":"heavy cream","swap":"full fat coconut cream for a dairy free version"},{"original":"vodka","swap":"chicken broth with a splash of white wine vinegar"},{"original":"penne pasta","swap":"rigatoni or fusilli for similar texture"}]','["Not cooking the vodka long enough which leaves a harsh alcohol taste in the sauce","Adding cream to a sauce that is too hot which causes it to curdle and separate","Skipping the pasta water which is essential for binding the sauce to the noodles"]','["pasta","vodka sauce","creamy","Italian American","weeknight dinner","tomato cream"]','["vegetarian"]','Pasta','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Baked Ziti with Ricotta','baked-ziti-ricotta','A hearty baked pasta casserole layered with creamy ricotta, zesty marinara, and bubbling mozzarella. This crowd pleasing comfort dish is perfect for family dinners and meal prep.','Classic baked ziti loaded with ricotta and melted mozzarella for the ultimate pasta bake.','Italian American','Medium',20,45,65,6,710,34,78,29,5,'[{"amount":450,"unit":"g","item":"ziti pasta","group":"pasta"},{"amount":450,"unit":"g","item":"whole milk ricotta cheese","group":"cheese"},{"amount":300,"unit":"g","item":"shredded mozzarella cheese divided","group":"cheese"},{"amount":60,"unit":"g","item":"Parmesan cheese grated","group":"cheese"},{"amount":700,"unit":"ml","item":"marinara sauce","group":"sauce"},{"amount":2,"unit":"large","item":"eggs","group":"binder"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"seasoning"},{"amount":1,"unit":"tsp","item":"dried Italian seasoning","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Cook the Ziti","text":"Preheat oven to 190 degrees Celsius. Cook ziti in salted boiling water for 2 minutes less than the package directions so it is very al dente. Drain and set aside. It will finish cooking in the oven.","timer":480},{"title":"Make the Ricotta Mixture","text":"In a large bowl combine ricotta cheese, eggs, minced garlic, Italian seasoning, salt, pepper, half of the mozzarella, and half of the Parmesan. Stir until fully combined into a smooth mixture.","timer":180},{"title":"Combine Pasta and Sauce","text":"Add the drained pasta to the ricotta mixture and toss well to coat every piece. Pour in 500 ml of the marinara sauce and stir again until everything is evenly mixed.","timer":120},{"title":"Assemble the Bake","text":"Spread a thin layer of remaining marinara on the bottom of a 9x13 inch baking dish. Pour in the pasta mixture and spread evenly. Top with remaining marinara, mozzarella, and Parmesan cheese.","timer":120},{"title":"Bake Until Golden","text":"Cover the dish with foil and bake for 30 minutes. Remove foil and bake for an additional 15 minutes until the top is golden and bubbling. Let rest for 10 minutes before serving.","timer":2700}]','[{"original":"ziti pasta","swap":"penne or rigatoni work equally well in this bake"},{"original":"whole milk ricotta","swap":"cottage cheese blended smooth for a lighter option"},{"original":"marinara sauce","swap":"homemade tomato sauce or a jarred arrabbiata for extra heat"}]','["Cooking the pasta fully before baking which results in an overcooked mushy texture","Not covering with foil during the first bake phase which dries out the top layer","Skipping the resting period after baking which causes the layers to fall apart when serving"]','["baked pasta","ricotta","casserole","comfort food","Italian American","meal prep","family dinner"]','["vegetarian"]','Baked Pasta','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Penne alla Vodka','penne-alla-vodka','A restaurant quality Italian classic featuring penne in a velvety tomato and cream sauce brightened by vodka. Simple ingredients come together in this bold and satisfying pasta.','Authentic penne alla vodka with a smooth tomato cream sauce made in one pan.','Italian','Easy',8,22,30,4,590,16,68,25,3,'[{"amount":400,"unit":"g","item":"penne rigate","group":"pasta"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"sauce"},{"amount":5,"unit":"cloves","item":"garlic thinly sliced","group":"sauce"},{"amount":75,"unit":"ml","item":"vodka","group":"sauce"},{"amount":400,"unit":"g","item":"whole peeled tomatoes hand crushed","group":"sauce"},{"amount":150,"unit":"ml","item":"heavy cream","group":"sauce"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"seasoning"},{"amount":50,"unit":"g","item":"Parmesan cheese freshly grated","group":"topping"},{"amount":10,"unit":"g","item":"fresh basil leaves torn","group":"topping"}]','[{"title":"Boil the Penne","text":"Cook penne rigate in generously salted boiling water until al dente. Save at least 150 ml of starchy pasta water before draining. The pasta water is key to a glossy silky sauce.","timer":600},{"title":"Build the Base","text":"In a wide skillet melt butter with olive oil over medium heat. Add sliced garlic and red pepper flakes. Cook for 2 to 3 minutes stirring constantly until garlic is golden but do not let it burn.","timer":180},{"title":"Deglaze with Vodka","text":"Add the vodka to the pan and let it bubble vigorously. Stir and cook for 3 minutes until the sharp alcohol smell fades and the liquid reduces by half. This step removes bitterness from the sauce.","timer":180},{"title":"Simmer the Tomato Sauce","text":"Add the hand crushed whole peeled tomatoes with their juices. Season with salt and simmer over medium heat for 10 minutes until the sauce thickens slightly. Stir in the heavy cream and cook for 2 more minutes.","timer":720},{"title":"Toss and Plate","text":"Add drained penne directly to the sauce and toss over low heat adding pasta water as needed to loosen the sauce. Remove from heat, stir in Parmesan, top with torn basil, and serve immediately.","timer":90}]','[{"original":"heavy cream","swap":"half and half for a lighter sauce with less richness"},{"original":"vodka","swap":"dry white wine for a different but equally delicious depth of flavor"},{"original":"unsalted butter","swap":"vegan butter to make the dish dairy adjacent without losing creaminess"}]','["Using low quality canned tomatoes which results in a bland and acidic sauce","Burning the garlic by using heat that is too high which turns the entire sauce bitter","Adding the cream too early over high heat which breaks the emulsion and makes the sauce greasy"]','["penne","vodka sauce","Italian","quick dinner","tomato cream","one pan","restaurant style"]','["vegetarian"]','Pasta','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Spaghetti Carbonara','classic-spaghetti-carbonara','An authentic Roman pasta dish made with eggs, Pecorino Romano, guanciale, and black pepper with no cream involved. This silky and indulgent pasta relies on technique alone to achieve its luxurious texture.','True Roman carbonara with a glossy egg and cheese sauce clinging to every strand of spaghetti.','Italian','Medium',10,20,30,4,650,28,70,30,3,'[{"amount":400,"unit":"g","item":"spaghetti","group":"pasta"},{"amount":150,"unit":"g","item":"guanciale diced","group":"protein"},{"amount":4,"unit":"large","item":"egg yolks","group":"sauce"},{"amount":1,"unit":"large","item":"whole egg","group":"sauce"},{"amount":80,"unit":"g","item":"Pecorino Romano finely grated","group":"cheese"},{"amount":30,"unit":"g","item":"Parmesan cheese finely grated","group":"cheese"},{"amount":1.5,"unit":"tsp","item":"freshly cracked black pepper","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Prepare the Egg Mixture","text":"In a bowl whisk together egg yolks, the whole egg, grated Pecorino Romano, and grated Parmesan until a thick pale paste forms. Season generously with freshly cracked black pepper and set aside.","timer":120},{"title":"Render the Guanciale","text":"Place diced guanciale in a cold skillet and turn heat to medium. Cook slowly for 8 to 10 minutes until the fat renders out and the pieces are golden and crispy. Remove pan from heat and set aside.","timer":600},{"title":"Cook the Spaghetti","text":"Cook spaghetti in salted boiling water until al dente. Reserve at least 200 ml of hot starchy pasta water before draining. This water is the only liquid used to create the sauce.","timer":600},{"title":"Temper the Egg Sauce","text":"Add drained spaghetti to the pan with guanciale over very low heat. Remove pan from direct heat. Add 60 ml of hot pasta water to the egg mixture while whisking to temper it. Pour over pasta and toss vigorously.","timer":120},{"title":"Finish and Serve","text":"Continue tossing while adding more pasta water a splash at a time until the sauce is glossy and coats every strand. The residual heat cooks the eggs gently. Plate immediately with extra cheese and black pepper.","timer":60}]','[{"original":"guanciale","swap":"pancetta or thick cut bacon as a more accessible alternative"},{"original":"Pecorino Romano","swap":"all Parmesan for a milder and less salty flavor profile"},{"original":"spaghetti","swap":"rigatoni or mezze maniche which are the traditional Roman alternatives"}]','["Cooking the eggs over too high heat which turns the sauce into scrambled eggs instead of a silky coating","Not reserving enough pasta water which leaves the sauce too thick and clumpy","Adding cream to the recipe which is not authentic and changes the fundamental texture of the dish"]','["carbonara","Roman pasta","Italian","egg sauce","guanciale","weeknight","authentic"]','[]','Pasta','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mushroom Spinach Stuffed Shells','mushroom-spinach-stuffed-shells','Jumbo pasta shells packed with a savory mixture of sauteed mushrooms, wilted spinach, and creamy ricotta then baked in marinara sauce. This vegetarian bake is hearty enough to satisfy meat lovers too.','Jumbo shells filled with a rich mushroom ricotta mixture and baked in a bubbling marinara sauce.','Italian American','Medium',25,40,65,5,540,26,62,21,6,'[{"amount":20,"unit":"pieces","item":"jumbo pasta shells","group":"pasta"},{"amount":350,"unit":"g","item":"whole milk ricotta cheese","group":"filling"},{"amount":200,"unit":"g","item":"cremini mushrooms finely chopped","group":"filling"},{"amount":150,"unit":"g","item":"fresh baby spinach","group":"filling"},{"amount":180,"unit":"g","item":"shredded mozzarella divided","group":"cheese"},{"amount":600,"unit":"ml","item":"marinara sauce","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":1,"unit":"large","item":"egg","group":"binder"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"seasoning"}]','[{"title":"Cook the Shells","text":"Preheat oven to 185 degrees Celsius. Cook jumbo shells in salted boiling water for 2 minutes less than package instructions. Drain carefully and lay them out on a lightly oiled baking sheet so they do not stick together.","timer":540},{"title":"Saute the Filling","text":"Heat olive oil in a skillet over medium high heat. Add mushrooms and cook for 6 minutes until golden and most of their moisture has evaporated. Add garlic and spinach and cook for 2 minutes until spinach wilts. Season with salt and oregano.","timer":480},{"title":"Make the Ricotta Filling","text":"Let the mushroom and spinach mixture cool for 5 minutes. Transfer to a large bowl and mix in ricotta, egg, and half of the mozzarella. Stir well until fully combined into a cohesive filling.","timer":300},{"title":"Stuff and Arrange","text":"Spread 300 ml of marinara sauce across the bottom of a 9x13 inch baking dish. Use a spoon to fill each shell generously with the ricotta mixture. Arrange stuffed shells open side up in the dish in a single layer.","timer":600},{"title":"Bake Until Bubbly","text":"Pour the remaining marinara over the shells and top with the rest of the mozzarella. Cover with foil and bake for 25 minutes. Remove foil and bake for 15 more minutes until cheese is golden and sauce is bubbling.","timer":2400}]','[{"original":"cremini mushrooms","swap":"a mix of shiitake and portobello mushrooms for deeper umami flavor"},{"original":"whole milk ricotta","swap":"firm tofu blended smooth with nutritional yeast for a vegan filling"},{"original":"mozzarella","swap":"provolone or fontina for a more complex and nutty cheese flavor"}]','["Not removing enough moisture from the mushrooms which makes the filling watery and causes the shells to become soggy","Overcooking the shells before baking which causes them to tear and fall apart during stuffing","Skipping the foil during the first bake phase which dries out the filling before the cheese melts properly"]','["stuffed shells","vegetarian","baked pasta","mushroom","spinach","ricotta","comfort food","Italian American"]','["vegetarian"]','Baked Pasta','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Fettuccine Alfredo','fettuccine-alfredo','A rich and creamy Italian pasta dish made with butter and Parmesan cheese. It is simple to prepare and incredibly satisfying.','Silky fettuccine tossed in a buttery Parmesan cream sauce.','Italian','Easy',5,15,20,4,620,22,68,30,3,'[{"amount":400,"unit":"g","item":"fettuccine pasta","group":"pasta"},{"amount":115,"unit":"g","item":"unsalted butter","group":"sauce"},{"amount":240,"unit":"ml","item":"heavy cream","group":"sauce"},{"amount":150,"unit":"g","item":"freshly grated Parmesan cheese","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic","group":"sauce"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh parsley","group":"garnish"}]','[{"title":"Cook the pasta","text":"Bring a large pot of salted water to a boil. Cook fettuccine according to package directions until al dente. Reserve 240ml of pasta water before draining.","timer":600},{"title":"Saute garlic","text":"Melt butter in a large skillet over medium heat. Add minced garlic and cook for 1 minute until fragrant. Do not let the garlic brown.","timer":60},{"title":"Build the sauce","text":"Pour in the heavy cream and stir to combine with the butter. Simmer on medium-low heat for 3 to 4 minutes until the sauce thickens slightly.","timer":240},{"title":"Add cheese","text":"Remove the pan from heat and stir in the grated Parmesan cheese gradually. Stir constantly until fully melted and the sauce is smooth. Add pasta water a little at a time if the sauce is too thick.","timer":120},{"title":"Toss and serve","text":"Add the drained fettuccine to the sauce and toss well to coat every strand. Season with salt and pepper, garnish with fresh parsley, and serve immediately.","timer":60}]','[{"original":"heavy cream","swap":"half and half for a lighter sauce"},{"original":"fettuccine","swap":"linguine or tagliatelle"},{"original":"fresh parsley","swap":"fresh basil or chives"}]','["Adding cheese to a pan that is too hot causes it to clump and become grainy","Skipping the pasta water makes the sauce too thick and difficult to toss","Overcooking the pasta makes it mushy and unable to hold the sauce properly"]','["pasta","creamy","Italian","comfort food","quick"]','["vegetarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cacio e Pepe','cacio-e-pepe','A classic Roman pasta dish made with just three core ingredients: pasta, Pecorino Romano, and black pepper. The technique is simple but requires attention to create the perfect creamy sauce.','Roman pasta tossed in a peppery Pecorino Romano sauce with no cream required.','Italian','Medium',5,15,20,4,520,20,70,18,3,'[{"amount":400,"unit":"g","item":"spaghetti or tonnarelli","group":"pasta"},{"amount":120,"unit":"g","item":"finely grated Pecorino Romano","group":"sauce"},{"amount":40,"unit":"g","item":"finely grated Parmesan cheese","group":"sauce"},{"amount":2,"unit":"tsp","item":"whole black peppercorns","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"coarse salt","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":480,"unit":"ml","item":"reserved pasta water","group":"sauce"},{"amount":1,"unit":"tsp","item":"olive oil","group":"sauce"}]','[{"title":"Toast and grind pepper","text":"Toast whole black peppercorns in a dry skillet over medium heat for 1 to 2 minutes until fragrant. Crush them coarsely using a mortar and pestle or the bottom of a heavy pan.","timer":120},{"title":"Cook the pasta","text":"Boil pasta in well-salted water until just al dente. Reserve at least 480ml of the starchy pasta cooking water before draining the pasta.","timer":600},{"title":"Bloom the pepper","text":"In a large skillet, melt butter with olive oil over medium heat. Add the crushed pepper and toast for 1 minute. Add 120ml of pasta water and let it simmer.","timer":60},{"title":"Create the cheese paste","text":"In a bowl, mix the grated Pecorino Romano and Parmesan with 3 to 4 tablespoons of warm pasta water to form a smooth paste. This step prevents the cheese from clumping.","timer":60},{"title":"Combine and emulsify","text":"Add the drained pasta to the pepper skillet and toss. Remove from heat and add the cheese paste, tossing vigorously and adding pasta water gradually until a creamy sauce forms. Serve immediately.","timer":90}]','[{"original":"Pecorino Romano","swap":"all Parmesan for a milder flavor"},{"original":"spaghetti","swap":"rigatoni or bucatini"},{"original":"whole black peppercorns","swap":"pre-ground black pepper in a pinch"}]','["Adding cold cheese directly to a hot pan causes it to clump into a stringy mess","Using too little pasta water results in a dry and sticky dish instead of a creamy one","Skipping the toasting step for peppercorns loses the deep aromatic flavor essential to this dish"]','["pasta","Roman","Italian","minimalist","classic"]','["vegetarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Homemade Potato Gnocchi','homemade-potato-gnocchi','Light and pillowy potato dumplings made from scratch with just a few pantry staples. They pair beautifully with any sauce from simple brown butter to rich tomato.','Soft homemade potato gnocchi that are tender inside and golden on the outside.','Italian','Medium',30,30,60,4,410,11,78,8,5,'[{"amount":900,"unit":"g","item":"russet potatoes","group":"dough"},{"amount":200,"unit":"g","item":"all-purpose flour","group":"dough"},{"amount":1,"unit":"large","item":"egg","group":"dough"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"ground nutmeg","group":"seasoning"},{"amount":60,"unit":"g","item":"unsalted butter","group":"sauce"},{"amount":6,"unit":"leaves","item":"fresh sage","group":"sauce"},{"amount":50,"unit":"g","item":"grated Parmesan cheese","group":"garnish"}]','[{"title":"Cook and rice the potatoes","text":"Boil potatoes whole in salted water until fully tender, about 20 minutes. Drain and peel while still hot. Pass them through a potato ricer onto a clean work surface and allow steam to escape for 5 minutes.","timer":1500},{"title":"Form the dough","text":"Make a well in the center of the riced potatoes. Add the egg, salt, and nutmeg. Gradually incorporate the flour, mixing gently until a soft dough forms. Do not overwork the dough or the gnocchi will become dense.","timer":300},{"title":"Shape the gnocchi","text":"Divide the dough into portions and roll each into a rope about 2cm thick on a lightly floured surface. Cut into 2.5cm pieces and roll each piece over a fork or gnocchi board to create ridges.","timer":600},{"title":"Boil the gnocchi","text":"Bring a large pot of salted water to a boil. Cook gnocchi in batches. They are done when they float to the surface, about 2 to 3 minutes. Remove with a slotted spoon.","timer":180},{"title":"Finish in brown butter","text":"Melt butter in a large skillet over medium-high heat. Add sage leaves and cook until the butter turns golden brown and smells nutty. Add the boiled gnocchi and toss for 1 to 2 minutes until lightly golden. Serve topped with Parmesan.","timer":120}]','[{"original":"russet potatoes","swap":"Yukon Gold potatoes for a slightly creamier texture"},{"original":"all-purpose flour","swap":"00 flour for a more tender gnocchi"},{"original":"fresh sage","swap":"fresh thyme or rosemary in the brown butter"}]','["Using watery potatoes that have not been dried properly leads to gummy and heavy gnocchi","Adding too much flour to fix a sticky dough results in tough and chewy gnocchi","Overworking the dough develops gluten and makes the gnocchi rubbery instead of light"]','["gnocchi","Italian","potato","handmade","comfort food"]','["vegetarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Marinara Pasta','classic-marinara-pasta','A vibrant and flavorful tomato sauce tossed with spaghetti and finished with fresh basil. This is a foundational Italian recipe that every home cook should master.','Bright and garlicky tomato marinara sauce served over perfectly cooked spaghetti.','Italian','Easy',10,25,35,4,450,14,75,10,6,'[{"amount":400,"unit":"g","item":"spaghetti","group":"pasta"},{"amount":800,"unit":"g","item":"canned whole San Marzano tomatoes","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic","group":"sauce"},{"amount":3,"unit":"tbsp","item":"extra virgin olive oil","group":"sauce"},{"amount":1,"unit":"tsp","item":"red pepper flakes","group":"seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":1,"unit":"tsp","item":"sugar","group":"seasoning"},{"amount":10,"unit":"leaves","item":"fresh basil","group":"garnish"}]','[{"title":"Saute garlic","text":"Heat olive oil in a large saucepan over medium heat. Add thinly sliced garlic and red pepper flakes. Cook for 2 minutes until fragrant and lightly golden. Do not let the garlic burn.","timer":120},{"title":"Add tomatoes","text":"Pour in the canned tomatoes and crush them by hand as they go into the pan. Add salt and sugar, then stir everything together. Bring to a gentle simmer.","timer":60},{"title":"Simmer the sauce","text":"Cook the sauce uncovered on medium-low heat for 20 minutes, stirring occasionally. The sauce should thicken and deepen in color. Adjust seasoning as needed.","timer":1200},{"title":"Cook the pasta","text":"While the sauce simmers, cook spaghetti in a large pot of heavily salted boiling water until al dente. Reserve 240ml of pasta water before draining.","timer":600},{"title":"Combine and serve","text":"Add the drained spaghetti directly to the sauce and toss over medium heat for 1 to 2 minutes. Add pasta water as needed to loosen the sauce. Finish with torn fresh basil and a drizzle of olive oil.","timer":120}]','[{"original":"San Marzano tomatoes","swap":"any high quality canned crushed tomatoes"},{"original":"spaghetti","swap":"penne or rigatoni"},{"original":"fresh basil","swap":"dried oregano or fresh parsley"}]','["Burning the garlic gives the entire sauce a bitter and unpleasant flavor","Not simmering the sauce long enough leaves it watery and lacking depth","Salting the pasta water too lightly results in bland pasta that does not complement the sauce"]','["pasta","tomato","Italian","vegan","weeknight"]','["vegan","vegetarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pasta Carbonara','pasta-carbonara','A traditional Roman pasta made with eggs, Pecorino Romano, guanciale, and black pepper. No cream is used in an authentic carbonara, just technique and quality ingredients.','Authentic Roman carbonara with a silky egg and cheese sauce and crispy guanciale.','Italian','Medium',10,20,30,4,590,26,68,24,3,'[{"amount":400,"unit":"g","item":"spaghetti or rigatoni","group":"pasta"},{"amount":200,"unit":"g","item":"guanciale or pancetta","group":"protein"},{"amount":4,"unit":"large","item":"egg yolks","group":"sauce"},{"amount":1,"unit":"large","item":"whole egg","group":"sauce"},{"amount":100,"unit":"g","item":"finely grated Pecorino Romano","group":"sauce"},{"amount":50,"unit":"g","item":"finely grated Parmesan cheese","group":"sauce"},{"amount":1.5,"unit":"tsp","item":"freshly cracked black pepper","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"coarse salt","group":"seasoning"}]','[{"title":"Prepare the egg mixture","text":"Whisk together egg yolks and the whole egg in a bowl. Add the grated Pecorino Romano and Parmesan and mix until a thick paste forms. Season generously with cracked black pepper and set aside.","timer":120},{"title":"Render the guanciale","text":"Cut guanciale into small cubes or strips. Cook in a large skillet over medium heat until the fat renders and the meat becomes crispy, about 6 to 8 minutes. Remove from heat and set aside with the rendered fat.","timer":480},{"title":"Cook the pasta","text":"Boil pasta in salted water until al dente. Reserve at least 360ml of the starchy pasta cooking water before draining. This water is essential to the final sauce.","timer":600},{"title":"Temper the egg sauce","text":"Add 4 tablespoons of hot pasta water to the egg and cheese mixture and whisk quickly. This tempers the eggs so they do not scramble when added to the pasta.","timer":60},{"title":"Combine everything","text":"Add the drained pasta to the skillet with guanciale off the heat. Pour in the egg mixture and toss vigorously, adding pasta water a little at a time until a glossy and creamy sauce clings to every piece of pasta. Serve immediately.","timer":90}]','[{"original":"guanciale","swap":"pancetta or thick cut bacon"},{"original":"Pecorino Romano","swap":"all Parmesan for a less sharp flavor"},{"original":"spaghetti","swap":"rigatoni or mezze rigatoni"}]','["Adding the egg mixture to a pan that is still on high heat scrambles the eggs and ruins the sauce","Not reserving enough pasta water makes it impossible to achieve a creamy and smooth sauce","Using pre-grated cheese from a container causes a grainy sauce that does not emulsify properly"]','["pasta","Roman","Italian","eggs","classic"]','[]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Green Bean Casserole','green-bean-casserole','A classic American comfort dish featuring tender green beans baked in a rich mushroom cream sauce. Topped with crispy fried onions for the perfect crunch.','Tender green beans in creamy mushroom sauce topped with crispy onions.','American','Easy',10,35,45,8,210,5,24,11,3,'[{"amount":900,"unit":"g","item":"fresh green beans trimmed and cut","group":"main"},{"amount":2,"unit":"cans","item":"cream of mushroom soup","group":"sauce"},{"amount":240,"unit":"ml","item":"whole milk","group":"sauce"},{"amount":1,"unit":"tsp","item":"soy sauce","group":"sauce"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"sauce"},{"amount":0.25,"unit":"tsp","item":"garlic powder","group":"sauce"},{"amount":180,"unit":"g","item":"crispy fried onions","group":"topping"},{"amount":0.5,"unit":"tsp","item":"kosher salt","group":"seasoning"}]','[{"title":"Blanch the Green Beans","text":"Bring a large pot of salted water to a boil. Add green beans and cook for 5 minutes until bright green and slightly tender. Drain and immediately transfer to an ice bath to stop cooking. Drain again thoroughly.","timer":300},{"title":"Make the Sauce","text":"Preheat oven to 190 degrees C. In a large bowl whisk together cream of mushroom soup, milk, soy sauce, black pepper, and garlic powder until smooth and well combined.","timer":0},{"title":"Combine and Layer","text":"Add the blanched green beans to the sauce mixture and stir to coat evenly. Pour the mixture into a greased 9x13 baking dish and spread into an even layer.","timer":0},{"title":"Add Topping and Bake","text":"Sprinkle half the crispy fried onions over the green bean mixture. Bake uncovered for 25 minutes until the sauce is bubbling around the edges.","timer":1500},{"title":"Finish and Serve","text":"Remove from oven and top with the remaining crispy fried onions. Return to oven for 5 more minutes until onions are golden. Let rest for 5 minutes before serving.","timer":300}]','[{"original":"fresh green beans","swap":"frozen green beans thawed and drained"},{"original":"cream of mushroom soup","swap":"homemade mushroom bechamel sauce"},{"original":"whole milk","swap":"chicken broth for a lighter version"}]','["Skipping the ice bath after blanching causes mushy overcooked beans","Do not skip draining the beans thoroughly or the casserole becomes watery","Adding all the onions at the start causes them to become soggy instead of crispy"]','["casserole","side dish","thanksgiving","comfort food","baked"]','["vegetarian"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Garlic Mashed Potatoes','creamy-garlic-mashed-potatoes','Luxuriously smooth mashed potatoes infused with roasted garlic and rich butter. This crowd-pleasing side dish is the ultimate comfort food for any occasion.','Ultra creamy buttery mashed potatoes with deep roasted garlic flavor.','American','Easy',15,30,45,6,320,5,38,17,3,'[{"amount":1200,"unit":"g","item":"Yukon Gold potatoes peeled and cubed","group":"main"},{"amount":6,"unit":"cloves","item":"garlic minced","group":"flavoring"},{"amount":113,"unit":"g","item":"unsalted butter","group":"dairy"},{"amount":240,"unit":"ml","item":"heavy cream warmed","group":"dairy"},{"amount":120,"unit":"ml","item":"sour cream","group":"dairy"},{"amount":1.5,"unit":"tsp","item":"kosher salt","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"white pepper","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh chives chopped","group":"garnish"}]','[{"title":"Boil the Potatoes","text":"Place cubed potatoes in a large pot and cover with cold salted water. Bring to a boil over high heat then reduce to medium and cook for 18 to 20 minutes until fork tender. Do not overcook.","timer":1200},{"title":"Saute the Garlic","text":"While potatoes cook melt 2 tablespoons of butter in a small skillet over medium low heat. Add minced garlic and cook for 2 to 3 minutes stirring frequently until fragrant and lightly golden. Do not let it brown.","timer":180},{"title":"Drain and Dry","text":"Drain the potatoes thoroughly in a colander. Return them to the hot pot over low heat for 1 to 2 minutes shaking occasionally to evaporate any remaining moisture for fluffier mashed potatoes.","timer":120},{"title":"Mash and Mix","text":"Remove pot from heat. Mash potatoes with a potato masher or ricer until smooth. Add remaining butter sauteed garlic warmed heavy cream and sour cream. Stir with a wooden spoon until just combined and creamy.","timer":0},{"title":"Season and Serve","text":"Season with salt and white pepper tasting as you go. Transfer to a serving bowl and top with a pat of butter and fresh chives. Serve immediately while hot.","timer":0}]','[{"original":"heavy cream","swap":"whole milk for a lighter result"},{"original":"sour cream","swap":"cream cheese for extra richness"},{"original":"Yukon Gold potatoes","swap":"Russet potatoes for a fluffier texture"}]','["Overworking the potatoes with an electric mixer creates a gluey gummy texture","Using cold dairy ingredients causes the potatoes to turn stiff and lumpy","Do not skip the pot drying step or excess water will make potatoes watery"]','["mashed potatoes","side dish","comfort food","holiday","thanksgiving"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Roasted Butternut Squash','honey-roasted-butternut-squash','Caramelized butternut squash cubes roasted with honey and warm spices until golden and tender. A simple yet stunning side dish that highlights natural sweetness.','Golden caramelized butternut squash with honey and warm spices.','American','Easy',15,35,50,4,175,2,32,6,4,'[{"amount":1,"unit":"large","item":"butternut squash peeled seeded and cubed","group":"main"},{"amount":3,"unit":"tbsp","item":"honey","group":"sweetener"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"},{"amount":1,"unit":"tsp","item":"ground cinnamon","group":"spices"},{"amount":0.5,"unit":"tsp","item":"ground nutmeg","group":"spices"},{"amount":0.5,"unit":"tsp","item":"kosher salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh thyme leaves","group":"garnish"}]','[{"title":"Prep and Preheat","text":"Preheat oven to 205 degrees C. Line a large rimmed baking sheet with parchment paper. Peel and cube the butternut squash into 2 cm pieces ensuring they are uniform for even cooking.","timer":0},{"title":"Make the Glaze","text":"In a large bowl whisk together honey olive oil cinnamon nutmeg salt and black pepper until well combined and emulsified into a smooth glaze.","timer":0},{"title":"Coat the Squash","text":"Add the squash cubes to the bowl with the glaze and toss thoroughly until every piece is evenly coated. Spread in a single layer on the prepared baking sheet without overlapping.","timer":0},{"title":"Roast Until Caramelized","text":"Roast in the preheated oven for 25 minutes. Remove from oven flip each piece and return to oven for an additional 10 minutes until edges are deeply caramelized and golden.","timer":2100},{"title":"Garnish and Serve","text":"Remove from oven and immediately scatter fresh thyme leaves over the hot squash. Drizzle with an extra teaspoon of honey if desired. Transfer to a serving platter and serve warm.","timer":0}]','[{"original":"honey","swap":"maple syrup for a vegan alternative"},{"original":"butternut squash","swap":"acorn squash or sweet potatoes"},{"original":"fresh thyme","swap":"fresh rosemary or sage for different herb notes"}]','["Overcrowding the baking sheet causes steaming instead of caramelizing","Do not skip flipping halfway through or one side will burn while the other stays pale","Cutting uneven sized pieces causes some to burn before others are cooked through"]','["roasted","side dish","fall","thanksgiving","squash","holiday"]','["vegetarian","gluten-free","dairy-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Stew','classic-beef-stew','A hearty slow-cooked beef stew with tender chunks of beef and root vegetables in a rich savory broth. Perfect for cold nights when you need something deeply satisfying.','Tender beef and vegetables slow cooked in a rich deeply flavored broth.','American','Medium',20,120,140,6,420,38,28,16,4,'[{"amount":900,"unit":"g","item":"beef chuck cut into 4 cm cubes","group":"protein"},{"amount":3,"unit":"medium","item":"carrots peeled and sliced","group":"vegetables"},{"amount":4,"unit":"medium","item":"Yukon Gold potatoes cubed","group":"vegetables"},{"amount":1,"unit":"large","item":"yellow onion diced","group":"aromatics"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":480,"unit":"ml","item":"beef broth","group":"liquid"},{"amount":2,"unit":"tbsp","item":"tomato paste","group":"flavoring"},{"amount":2,"unit":"tbsp","item":"all purpose flour","group":"thickener"},{"amount":1,"unit":"tsp","item":"fresh thyme leaves","group":"herbs"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"}]','[{"title":"Sear the Beef","text":"Pat beef cubes completely dry with paper towels and season generously with salt and pepper. Heat olive oil in a large Dutch oven over high heat. Sear beef in batches for 3 to 4 minutes per side until deeply browned on all sides. Do not crowd the pan.","timer":480},{"title":"Build the Base","text":"Reduce heat to medium. Add onion to the same pot and cook for 4 minutes until softened. Add garlic and tomato paste and cook for 1 more minute stirring constantly. Sprinkle flour over the mixture and stir for 1 minute.","timer":360},{"title":"Deglaze and Combine","text":"Pour in beef broth while scraping up all the browned bits from the bottom of the pot. These bits add tremendous flavor to the final stew. Return the seared beef to the pot and add thyme.","timer":0},{"title":"Slow Cook","text":"Bring stew to a gentle boil then reduce heat to low. Cover and simmer for 1 hour stirring occasionally. Add carrots and potatoes and continue cooking covered for another 30 minutes until beef and vegetables are completely tender.","timer":5400},{"title":"Season and Serve","text":"Taste and adjust seasoning with salt and pepper. If the stew is too thin remove the lid and simmer for an additional 10 minutes to reduce. Ladle into bowls and serve with crusty bread.","timer":0}]','[{"original":"beef chuck","swap":"lamb shoulder for a different but equally rich flavor"},{"original":"beef broth","swap":"red wine mixed with broth for deeper complexity"},{"original":"all purpose flour","swap":"cornstarch slurry for a gluten free thickener"}]','["Do not skip searing the meat as browning creates essential flavor through the Maillard reaction","Boiling the stew too vigorously makes the beef tough and stringy instead of tender","Adding potatoes too early causes them to fall apart and disintegrate into the broth"]','["stew","beef","comfort food","winter","slow cooked","hearty"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Herb Roasted Chicken','lemon-herb-roasted-chicken','A perfectly roasted whole chicken with crispy golden skin infused with lemon and fresh herbs. Simple techniques deliver incredibly juicy and flavorful results every single time.','Juicy roasted chicken with crispy skin bright lemon and fragrant fresh herbs.','American','Medium',20,90,110,4,480,52,4,28,1,'[{"amount":1.8,"unit":"kg","item":"whole chicken patted dry","group":"protein"},{"amount":1,"unit":"whole","item":"lemon halved","group":"flavoring"},{"amount":56,"unit":"g","item":"unsalted butter softened","group":"fat"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"fresh rosemary chopped","group":"herbs"},{"amount":2,"unit":"tbsp","item":"fresh thyme leaves","group":"herbs"},{"amount":1.5,"unit":"tsp","item":"kosher salt","group":"seasoning"},{"amount":0.75,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"medium","item":"yellow onion quartered","group":"aromatics"}]','[{"title":"Prepare the Herb Butter","text":"Preheat oven to 220 degrees C. In a small bowl combine softened butter minced garlic chopped rosemary thyme salt and pepper. Mix until fully combined into a smooth herb butter paste.","timer":0},{"title":"Season the Chicken","text":"Pat the chicken completely dry inside and out with paper towels. Loosen the skin over the breast and thighs with your fingers. Push half the herb butter under the skin and rub the remaining butter all over the outside.","timer":0},{"title":"Stuff and Truss","text":"Squeeze lemon juice over the outside of the chicken. Place the squeezed lemon halves onion quarters and any remaining herb sprigs inside the cavity. Tie the legs together with kitchen twine and tuck wing tips under the body.","timer":0},{"title":"Roast the Chicken","text":"Place chicken breast side up in a roasting pan or cast iron skillet. Roast at 220 degrees C for 20 minutes to brown the skin. Reduce heat to 190 degrees C and continue roasting for 60 to 70 minutes until internal temperature reaches 74 degrees C.","timer":5400},{"title":"Rest and Serve","text":"Remove chicken from oven and let it rest uncovered for 15 minutes before carving. Do not skip the resting period as this redistributes the juices throughout the meat. Carve and serve with pan drippings.","timer":900}]','[{"original":"fresh rosemary and thyme","swap":"dried herbs using one third the amount"},{"original":"unsalted butter","swap":"olive oil for a dairy free option with slightly less richness"},{"original":"whole chicken","swap":"bone in skin on chicken thighs reducing cook time to 45 minutes"}]','["Do not skip patting the chicken dry as moisture on the skin prevents crisping","Skipping the resting period causes all the juices to run out when carved","Opening the oven door repeatedly causes temperature drops that lead to uneven cooking"]','["roasted chicken","dinner","holiday","lemon","herbs","whole chicken"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Air Fryer Brussels Sprouts Balsamic','air-fryer-brussels-sprouts-balsamic','Crispy Brussels sprouts glazed with tangy balsamic vinegar and a touch of honey. This quick air fryer method delivers perfectly caramelized edges every time.','Crispy balsamic glazed Brussels sprouts made fast in the air fryer.','American','Easy',10,15,25,4,120,4,16,5,4,'[{"amount":1,"unit":"lb","item":"Brussels sprouts trimmed and halved","group":"main"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"main"},{"amount":3,"unit":"tbsp","item":"balsamic vinegar","group":"glaze"},{"amount":1,"unit":"tbsp","item":"honey","group":"glaze"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"main"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"red pepper flakes","group":"seasoning"}]','[{"title":"Prep the Brussels Sprouts","text":"Trim the ends off the Brussels sprouts and slice them in half lengthwise. Pat them completely dry with paper towels to ensure maximum crispiness.","timer":0},{"title":"Season and Coat","text":"In a large bowl toss the Brussels sprouts with olive oil minced garlic salt black pepper and red pepper flakes. Make sure every piece is well coated.","timer":0},{"title":"Air Fry First Round","text":"Place Brussels sprouts cut side down in a single layer in the air fryer basket. Cook at 375 degrees F for 10 minutes shaking the basket halfway through.","timer":600},{"title":"Add the Glaze","text":"Whisk together balsamic vinegar and honey in a small bowl. Drizzle the glaze over the Brussels sprouts in the basket and toss to coat evenly.","timer":0},{"title":"Finish and Serve","text":"Return the basket to the air fryer and cook at 400 degrees F for an additional 5 minutes until the glaze is caramelized and the edges are crispy. Serve immediately.","timer":300}]','[{"original":"honey","swap":"maple syrup for a vegan option"},{"original":"balsamic vinegar","swap":"red wine vinegar with a pinch of sugar"},{"original":"olive oil","swap":"avocado oil for higher smoke point"}]','["Overcrowding the air fryer basket which leads to steaming instead of crisping","Not drying the Brussels sprouts before cooking which prevents browning","Adding the glaze too early which causes it to burn before the sprouts are cooked through"]','["air fryer","Brussels sprouts","balsamic","vegetable side","quick","crispy"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Roasted Broccoli Parmesan','roasted-broccoli-parmesan','Golden oven roasted broccoli topped with a generous layer of salty Parmesan cheese. The high heat brings out a nutty depth of flavor that makes this dish irresistible.','Oven roasted broccoli with crispy Parmesan that the whole family will love.','Italian-American','Easy',8,22,30,4,145,8,10,9,3,'[{"amount":1.5,"unit":"lb","item":"broccoli florets","group":"main"},{"amount":3,"unit":"tbsp","item":"olive oil","group":"main"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"main"},{"amount":0.5,"unit":"cup","item":"grated Parmesan cheese","group":"topping"},{"amount":1,"unit":"tsp","item":"lemon zest","group":"topping"},{"amount":1,"unit":"tbsp","item":"lemon juice","group":"topping"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"}]','[{"title":"Preheat and Prep","text":"Preheat your oven to 425 degrees F and line a large baking sheet with parchment paper. Cut broccoli into evenly sized florets so they roast at the same rate.","timer":0},{"title":"Season the Broccoli","text":"Spread broccoli florets on the baking sheet. Drizzle with olive oil add minced garlic salt and pepper then toss well. Arrange in a single layer with cut sides facing down.","timer":0},{"title":"First Roast","text":"Roast the broccoli in the preheated oven for 18 minutes until the edges are browned and slightly crispy. Do not stir during this time to allow proper caramelization.","timer":1080},{"title":"Add Parmesan","text":"Remove the pan from the oven and sprinkle grated Parmesan cheese evenly over the broccoli. Return to the oven and roast for another 4 minutes until the cheese is melted and golden.","timer":240},{"title":"Finish and Serve","text":"Remove from oven and immediately drizzle with fresh lemon juice and scatter lemon zest over the top. Serve hot directly from the pan for best results.","timer":0}]','[{"original":"Parmesan cheese","swap":"Pecorino Romano for a sharper flavor"},{"original":"broccoli","swap":"cauliflower florets work equally well"},{"original":"lemon zest","swap":"orange zest for a slightly sweeter citrus note"}]','["Crowding the pan which traps steam and results in soft soggy broccoli","Using wet broccoli that has not been dried after washing which prevents browning","Adding Parmesan too early which causes it to burn before the broccoli is fully roasted"]','["roasted","broccoli","Parmesan","oven","vegetable side","Italian"]','["vegetarian","gluten-free","keto"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamed Spinach Bake','creamed-spinach-bake','Rich and velvety creamed spinach baked until bubbling with a golden breadcrumb topping. This comforting classic is the perfect side dish for any dinner occasion.','A rich bubbling baked creamed spinach with a crispy golden breadcrumb crust.','American','Medium',15,30,45,6,210,7,12,15,3,'[{"amount":20,"unit":"oz","item":"frozen chopped spinach thawed and squeezed dry","group":"main"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":1,"unit":"medium","item":"yellow onion finely diced","group":"main"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"main"},{"amount":3,"unit":"tbsp","item":"all purpose flour","group":"sauce"},{"amount":1.5,"unit":"cup","item":"whole milk","group":"sauce"},{"amount":0.5,"unit":"cup","item":"grated Parmesan cheese","group":"topping"},{"amount":0.5,"unit":"cup","item":"panko breadcrumbs","group":"topping"},{"amount":0.5,"unit":"tsp","item":"ground nutmeg","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"}]','[{"title":"Prepare the Spinach","text":"Preheat oven to 375 degrees F. Squeeze every bit of moisture from the thawed spinach using a clean kitchen towel. This step is critical and should not be skipped as excess water will ruin the sauce.","timer":0},{"title":"Build the Sauce","text":"Melt butter in a large oven safe skillet over medium heat. Add diced onion and cook for 5 minutes until soft. Add garlic and cook 1 minute more then whisk in flour and cook for 2 minutes to remove the raw flour taste.","timer":480},{"title":"Finish the Cream Sauce","text":"Slowly pour in the milk while whisking constantly to prevent lumps. Cook over medium heat stirring frequently for about 4 minutes until the sauce thickens. Season with salt and nutmeg.","timer":240},{"title":"Combine and Top","text":"Fold the dry squeezed spinach into the cream sauce until fully combined. Smooth the top and scatter Parmesan cheese and panko breadcrumbs evenly over the surface.","timer":0},{"title":"Bake Until Golden","text":"Transfer the skillet to the preheated oven and bake for 20 minutes until the top is golden brown and the edges are bubbling. Let rest for 5 minutes before serving.","timer":1200}]','[{"original":"frozen spinach","swap":"fresh spinach wilted and chopped works great"},{"original":"whole milk","swap":"half and half for an even richer sauce"},{"original":"panko breadcrumbs","swap":"crushed crackers or regular breadcrumbs"}]','["Not squeezing enough moisture from the spinach which makes the sauce watery and thin","Adding all the milk at once instead of gradually which creates a lumpy sauce","Skipping the flour cook time which leaves an unpleasant raw starchy flavor in the finished dish"]','["creamed spinach","baked","comfort food","spinach","casserole","holiday side"]','["vegetarian"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Green Beans','garlic-butter-green-beans','Tender crisp green beans tossed in a simple garlic butter sauce and finished with lemon. This five ingredient side dish comes together in under 20 minutes.','Quick garlic butter green beans with lemon that are ready in under 20 minutes.','American','Easy',5,12,17,4,95,2,8,7,3,'[{"amount":1,"unit":"lb","item":"fresh green beans trimmed","group":"main"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tbsp","item":"lemon juice","group":"finishing"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"red pepper flakes","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"finishing"}]','[{"title":"Blanch the Green Beans","text":"Bring a large pot of salted water to a boil. Add green beans and cook for 3 minutes until bright green and just barely tender. Transfer immediately to a bowl of ice water to stop the cooking.","timer":180},{"title":"Drain and Dry","text":"Drain the green beans from the ice water and pat them thoroughly dry with paper towels. Dry beans will sear properly in the pan rather than steam.","timer":0},{"title":"Make the Garlic Butter","text":"Melt butter in a large skillet over medium high heat. Add minced garlic and red pepper flakes and cook for 1 minute stirring constantly. Do not let the garlic burn as it will turn bitter.","timer":60},{"title":"Saute the Green Beans","text":"Add the dried green beans to the skillet and toss to coat in the garlic butter. Cook for 5 minutes tossing occasionally until the beans are lightly blistered and heated through. Season with salt and pepper.","timer":300},{"title":"Finish and Serve","text":"Remove from heat and squeeze fresh lemon juice over the green beans. Toss once more and transfer to a serving platter. Garnish with fresh chopped parsley and serve immediately.","timer":0}]','[{"original":"fresh green beans","swap":"frozen green beans thawed and dried"},{"original":"unsalted butter","swap":"olive oil for a dairy free version"},{"original":"fresh parsley","swap":"fresh dill or chives for a different flavor profile"}]','["Skipping the ice bath which causes the green beans to overcook and turn dull and mushy","Not drying the beans after blanching which causes them to steam instead of saute","Burning the garlic by using heat that is too high which makes the entire dish taste bitter"]','["green beans","garlic butter","quick","stovetop","vegetable side","easy"]','["vegetarian","gluten-free","keto"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Glazed Roasted Carrots','honey-glazed-roasted-carrots','Sweet tender carrots roasted with honey butter and fresh thyme until caramelized and glossy. A beautiful and effortless side dish that pairs with almost any main course.','Caramelized honey butter roasted carrots with thyme that look as good as they taste.','American','Easy',10,25,35,4,130,1,22,5,3,'[{"amount":1.5,"unit":"lb","item":"carrots peeled and cut into sticks","group":"main"},{"amount":2,"unit":"tbsp","item":"unsalted butter melted","group":"glaze"},{"amount":2,"unit":"tbsp","item":"honey","group":"glaze"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"main"},{"amount":4,"unit":"sprigs","item":"fresh thyme","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"fresh parsley chopped","group":"finishing"}]','[{"title":"Preheat and Cut","text":"Preheat the oven to 400 degrees F. Peel the carrots and cut them into uniform sticks about 3 inches long and half an inch thick. Uniform size ensures even roasting.","timer":0},{"title":"Make the Glaze","text":"In a small bowl whisk together melted butter honey olive oil salt and pepper until well combined. This glaze will caramelize beautifully in the oven.","timer":0},{"title":"Coat and Arrange","text":"Place carrot sticks in a single layer on a parchment lined baking sheet. Pour the honey butter glaze over the carrots and toss to coat evenly. Tuck fresh thyme sprigs among the carrots.","timer":0},{"title":"Roast the Carrots","text":"Roast in the preheated oven for 20 minutes then flip the carrots and roast for an additional 5 minutes until tender and caramelized on the edges. The glaze should be sticky and golden.","timer":1500},{"title":"Garnish and Serve","text":"Remove the thyme sprigs from the pan. Transfer carrots to a serving platter and drizzle any pan juices over the top. Garnish with fresh chopped parsley and serve warm.","timer":0}]','[{"original":"honey","swap":"pure maple syrup for a different natural sweetness"},{"original":"fresh thyme","swap":"fresh rosemary sprigs for a more piney herb flavor"},{"original":"butter","swap":"coconut oil for a dairy free and slightly tropical version"}]','["Cutting carrots into uneven sizes which causes some to burn while others remain undercooked","Overcrowding the baking sheet which causes steaming and prevents proper caramelization","Not flipping the carrots halfway through which results in uneven browning and a less glossy glaze"]','["carrots","honey glazed","roasted","thyme","vegetable side","holiday"]','["vegetarian","gluten-free"]','Side Dish','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Fudgy Brownies','classic-fudgy-brownies','Dense, rich brownies packed with deep chocolate flavor and a perfectly crackly top. These brownies deliver maximum fudginess in every single bite.','Irresistibly fudgy chocolate brownies baked to perfection in under an hour.','American','Easy',15,25,40,16,210,3,28,11,1,'[{"amount":115,"unit":"g","item":"unsalted butter","group":"wet"},{"amount":200,"unit":"g","item":"dark chocolate chips","group":"wet"},{"amount":200,"unit":"g","item":"granulated sugar","group":"dry"},{"amount":2,"unit":"large","item":"eggs","group":"wet"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"wet"},{"amount":90,"unit":"g","item":"all purpose flour","group":"dry"},{"amount":30,"unit":"g","item":"unsweetened cocoa powder","group":"dry"},{"amount":0.5,"unit":"tsp","item":"salt","group":"dry"}]','[{"title":"Melt Butter and Chocolate","text":"Preheat oven to 175C. In a medium saucepan over low heat, melt butter and chocolate together, stirring constantly until smooth. Remove from heat and let cool for 5 minutes.","timer":300},{"title":"Mix Wet Ingredients","text":"Whisk sugar into the cooled chocolate mixture until combined. Add eggs one at a time, whisking well after each addition. Stir in vanilla extract.","timer":180},{"title":"Fold in Dry Ingredients","text":"Sift flour, cocoa powder, and salt into the chocolate mixture. Fold gently with a spatula until just combined. Do not overmix or the brownies will become cakey.","timer":120},{"title":"Bake","text":"Pour batter into a greased 20cm square baking pan lined with parchment paper. Spread evenly and bake for 22 to 25 minutes until the edges are set but the center still has a slight jiggle.","timer":1500},{"title":"Cool and Slice","text":"Allow brownies to cool completely in the pan for at least 1 hour before slicing into 16 squares. Cooling is essential for achieving that perfect fudgy texture.","timer":3600}]','[{"original":"dark chocolate chips","swap":"semi-sweet chocolate bar chopped into pieces"},{"original":"unsalted butter","swap":"coconut oil for a dairy-free version"},{"original":"all purpose flour","swap":"almond flour for a gluten-free option"}]','["Overbaking the brownies which turns them cakey instead of fudgy","Cutting brownies while still warm which causes them to fall apart","Overmixing the batter after adding flour which develops too much gluten"]','["brownies","chocolate","dessert","baking","fudgy","easy"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Strawberry Rhubarb Pie','strawberry-rhubarb-pie','A classic double-crust pie bursting with sweet strawberries and tart rhubarb in a perfectly thickened filling. The flaky golden crust makes every slice absolutely irresistible.','Sweet and tart strawberry rhubarb pie with a buttery flaky double crust.','American','Medium',45,55,100,8,340,4,52,14,3,'[{"amount":400,"unit":"g","item":"fresh strawberries hulled and sliced","group":"filling"},{"amount":350,"unit":"g","item":"rhubarb stalks chopped into 2cm pieces","group":"filling"},{"amount":200,"unit":"g","item":"granulated sugar","group":"filling"},{"amount":40,"unit":"g","item":"cornstarch","group":"filling"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"filling"},{"amount":2,"unit":"sheets","item":"store bought pie crust or homemade shortcrust pastry","group":"crust"},{"amount":1,"unit":"large","item":"egg beaten for egg wash","group":"crust"},{"amount":1,"unit":"tbsp","item":"coarse sugar for topping","group":"crust"}]','[{"title":"Prepare the Filling","text":"In a large bowl, combine strawberries, rhubarb, sugar, cornstarch, and vanilla extract. Toss until fruit is evenly coated. Let mixture sit for 15 minutes to draw out juices and activate the cornstarch.","timer":900},{"title":"Line the Pie Dish","text":"Preheat oven to 200C. Roll out one sheet of pie crust and carefully press it into a 23cm pie dish. Trim edges leaving a 2cm overhang. Refrigerate while preparing the top crust.","timer":300},{"title":"Fill and Top the Pie","text":"Pour the fruit filling into the chilled crust. Roll out the second crust sheet and place it over the filling. Trim, fold edges under, and crimp decoratively. Cut several slits in the top to allow steam to escape.","timer":300},{"title":"Apply Egg Wash and Bake","text":"Brush the top crust evenly with beaten egg wash and sprinkle with coarse sugar. Place pie on a baking sheet and bake at 200C for 20 minutes, then reduce heat to 175C and bake for another 35 minutes until golden and bubbling.","timer":3300},{"title":"Cool Before Serving","text":"Allow the pie to cool on a wire rack for at least 3 hours before slicing. This allows the filling to set properly so it does not run when cut. Serve with vanilla ice cream if desired.","timer":10800}]','[{"original":"rhubarb","swap":"tart green apple for a milder flavor"},{"original":"cornstarch","swap":"tapioca starch for an equally clear and glossy filling"},{"original":"store bought pie crust","swap":"homemade butter pastry for extra flakiness"}]','["Not allowing the pie to cool long enough which results in a runny filling","Skipping the steam vents on the top crust which causes the filling to overflow","Using frozen fruit without draining excess liquid which makes the filling too watery"]','["pie","strawberry","rhubarb","summer","baking","fruit dessert"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Tunnel of Fudge Cake','tunnel-of-fudge-cake','A legendary Bundt cake with a moist chocolate exterior that hides a luscious gooey fudge tunnel inside. This showstopping cake is rich, indulgent, and surprisingly simple to make.','A stunning Bundt cake with a hidden fudge center and deep chocolate flavor throughout.','American','Medium',20,60,80,12,520,7,58,30,3,'[{"amount":230,"unit":"g","item":"unsalted butter softened","group":"wet"},{"amount":400,"unit":"g","item":"powdered sugar","group":"dry"},{"amount":6,"unit":"large","item":"eggs","group":"wet"},{"amount":220,"unit":"g","item":"all purpose flour","group":"dry"},{"amount":80,"unit":"g","item":"unsweetened cocoa powder","group":"dry"},{"amount":200,"unit":"g","item":"chopped walnuts","group":"mix-ins"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"wet"},{"amount":0.5,"unit":"tsp","item":"salt","group":"dry"}]','[{"title":"Cream Butter and Sugar","text":"Preheat oven to 175C. In a large bowl, beat softened butter with an electric mixer until fluffy. Gradually add powdered sugar and continue beating for 3 to 4 minutes until light and creamy.","timer":240},{"title":"Add Eggs and Vanilla","text":"Add eggs two at a time, beating well after each addition. Mix in vanilla extract. The batter will look slightly curdled at this stage which is completely normal.","timer":180},{"title":"Fold in Dry Ingredients","text":"Sift together flour, cocoa powder, and salt. Fold the dry ingredients into the batter using a spatula until just combined. Gently fold in the chopped walnuts. The walnuts are essential for creating the fudge tunnel and should not be skipped.","timer":180},{"title":"Bake the Cake","text":"Generously grease and flour a 12-cup Bundt pan. Pour batter in evenly and bake for 58 to 62 minutes. Do not use a toothpick to test doneness as the center should remain gooey. The cake is done when the edges pull slightly from the pan.","timer":3720},{"title":"Cool and Unmold","text":"Cool the cake in the pan on a wire rack for 1 hour. Then invert onto a serving plate and allow to cool completely for another 2 hours before dusting with powdered sugar and slicing to reveal the fudge tunnel.","timer":10800}]','[{"original":"walnuts","swap":"pecans for a slightly sweeter nutty flavor"},{"original":"unsalted butter","swap":"plant-based butter for a dairy-free version"},{"original":"all purpose flour","swap":"a 1 to 1 gluten-free baking flour blend"}]','["Testing the center with a toothpick and overbaking to get a clean result which destroys the fudge tunnel","Not greasing the Bundt pan thoroughly which causes the cake to stick and break apart","Removing the cake from the pan too soon before it has cooled and set properly"]','["cake","chocolate","bundt","fudge","showstopper","baking"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Blueberry Loaf Cake','lemon-blueberry-loaf-cake','A tender, moist loaf cake bursting with fresh blueberries and bright lemon zest in every slice. Finished with a tangy lemon glaze, this cake is perfect for brunch or afternoon tea.','A bright and moist lemon blueberry loaf topped with a zesty lemon drizzle glaze.','American','Easy',15,55,70,10,265,4,38,11,1,'[{"amount":190,"unit":"g","item":"all purpose flour","group":"dry"},{"amount":150,"unit":"g","item":"granulated sugar","group":"dry"},{"amount":1.5,"unit":"tsp","item":"baking powder","group":"dry"},{"amount":2,"unit":"large","item":"eggs","group":"wet"},{"amount":120,"unit":"ml","item":"whole milk","group":"wet"},{"amount":80,"unit":"ml","item":"vegetable oil","group":"wet"},{"amount":2,"unit":"tbsp","item":"fresh lemon zest","group":"flavor"},{"amount":180,"unit":"g","item":"fresh blueberries","group":"mix-ins"},{"amount":80,"unit":"g","item":"powdered sugar for glaze","group":"glaze"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice for glaze","group":"glaze"}]','[{"title":"Mix Dry Ingredients","text":"Preheat oven to 175C and grease a 23x13cm loaf pan. In a large bowl, whisk together flour, sugar, and baking powder. Reserve 1 tablespoon of flour in a small bowl and toss blueberries in it to prevent sinking.","timer":120},{"title":"Combine Wet Ingredients","text":"In a separate bowl, whisk together eggs, milk, vegetable oil, and lemon zest until well combined. Pour wet ingredients into the dry ingredients and stir gently until just combined. Do not overmix.","timer":120},{"title":"Fold in Blueberries","text":"Gently fold the flour-coated blueberries into the batter using a rubber spatula. Use slow folding motions to keep the blueberries whole and avoid streaking the batter purple.","timer":60},{"title":"Bake the Loaf","text":"Pour batter into the prepared loaf pan and smooth the top. Bake for 50 to 55 minutes until a toothpick inserted into the center comes out clean with just a few moist crumbs. If the top browns too quickly, tent loosely with foil.","timer":3300},{"title":"Glaze and Serve","text":"Allow the loaf to cool in the pan for 15 minutes, then transfer to a wire rack. Whisk together powdered sugar and lemon juice until smooth. Drizzle glaze over the warm loaf and let it set for 10 minutes before slicing.","timer":1500}]','[{"original":"fresh blueberries","swap":"frozen blueberries thawed and patted dry"},{"original":"whole milk","swap":"oat milk or almond milk for a dairy-free version"},{"original":"vegetable oil","swap":"melted unsalted butter for a richer flavor"}]','["Not tossing blueberries in flour before adding them which causes them to sink to the bottom","Overmixing the batter after combining wet and dry ingredients which makes the loaf dense and tough","Removing the loaf from the pan too early before it has had time to set and cool"]','["loaf cake","lemon","blueberry","brunch","easy baking","tea cake"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Vanilla Bean Creme Brulee','classic-vanilla-bean-creme-brulee','Silky smooth vanilla custard baked low and slow, then finished with a perfectly caramelized sugar crust that shatters beautifully with a spoon. This elegant French dessert is simpler than it looks.','Creamy vanilla custard with a crisp caramelized sugar top for a classic French finish.','French','Medium',20,45,65,6,380,5,28,28,0,'[{"amount":600,"unit":"ml","item":"heavy cream","group":"custard"},{"amount":1,"unit":"whole","item":"vanilla bean split and scraped","group":"custard"},{"amount":6,"unit":"large","item":"egg yolks","group":"custard"},{"amount":100,"unit":"g","item":"granulated sugar","group":"custard"},{"amount":1,"unit":"pinch","item":"salt","group":"custard"},{"amount":6,"unit":"tbsp","item":"superfine sugar for brulee topping","group":"topping"}]','[{"title":"Infuse the Cream","text":"Preheat oven to 150C. In a saucepan, combine heavy cream, vanilla bean pod, and scraped seeds. Heat over medium until just beginning to simmer, then remove from heat. Let the vanilla infuse for 15 minutes, then discard the pod.","timer":900},{"title":"Prepare the Custard","text":"In a large bowl, whisk egg yolks, granulated sugar, and salt together until pale and slightly thickened, about 2 minutes. Slowly pour the warm cream into the egg mixture in a thin stream, whisking constantly to prevent scrambling.","timer":180},{"title":"Strain and Fill Ramekins","text":"Strain the custard through a fine mesh sieve into a large pouring jug. Skim any foam from the surface. Place 6 ramekins in a deep baking dish and divide the custard evenly among them.","timer":180},{"title":"Bake in Water Bath","text":"Pour hot water into the baking dish until it reaches halfway up the sides of the ramekins. Carefully transfer to the oven and bake for 40 to 45 minutes until the edges are set but the centers still wobble gently. Remove ramekins and refrigerate for at least 4 hours.","timer":2700},{"title":"Brulee the Sugar Top","text":"Sprinkle 1 tablespoon of superfine sugar evenly over each chilled custard. Use a kitchen torch to caramelize the sugar in circular motions until it turns deep amber and forms a hard glassy surface. Serve immediately.","timer":300}]','[{"original":"vanilla bean","swap":"1 teaspoon of pure vanilla extract added after heating the cream"},{"original":"heavy cream","swap":"full fat coconut cream for a dairy-free variation"},{"original":"superfine sugar for brulee","swap":"regular granulated sugar processed briefly in a blender"}]','["Pouring hot cream too quickly into egg yolks which scrambles the eggs and ruins the custard","Overbaking the custard until it is fully set with no wobble which results in a grainy texture","Applying too thick a layer of sugar on top which prevents even caramelization and burns before melting through"]','["creme brulee","custard","french dessert","vanilla","elegant","make ahead"]','["vegetarian","gluten-free"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Swedish Cardamom Buns','swedish-cardamom-buns','Soft and fragrant buns filled with butter, sugar, and freshly ground cardamom. These are a classic Swedish fika treat enjoyed with coffee.','Fluffy twisted buns infused with warm cardamom and sweet butter filling.','Swedish','Medium',30,15,165,12,280,6,42,9,2,'[{"amount":3,"unit":"cups","item":"all-purpose flour","group":"dough"},{"amount":1,"unit":"packet","item":"active dry yeast","group":"dough"},{"amount":1,"unit":"cup","item":"whole milk, warmed","group":"dough"},{"amount":0.25,"unit":"cup","item":"granulated sugar","group":"dough"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"dough"},{"amount":4,"unit":"tablespoons","item":"unsalted butter, softened","group":"filling"},{"amount":0.25,"unit":"cup","item":"brown sugar","group":"filling"},{"amount":2,"unit":"teaspoons","item":"ground cardamom","group":"filling"},{"amount":1,"unit":"large","item":"egg, beaten for wash","group":"topping"},{"amount":2,"unit":"tablespoons","item":"pearl sugar","group":"topping"}]','[{"title":"Activate the yeast","text":"Combine warm milk and sugar in a large bowl. Sprinkle yeast over the top and let sit until foamy. This confirms the yeast is active and ready to use.","timer":600},{"title":"Make the dough","text":"Add flour and salt to the yeast mixture and mix until a shaggy dough forms. Knead on a floured surface for 8 minutes until smooth and elastic. Place in a greased bowl, cover, and let rise until doubled.","timer":3600},{"title":"Prepare the filling","text":"Mix softened butter, brown sugar, and cardamom together in a small bowl until a smooth paste forms. Set aside at room temperature so it remains spreadable.","timer":0},{"title":"Shape the buns","text":"Roll dough into a large rectangle on a floured surface. Spread the cardamom filling evenly across the surface. Fold dough in half and cut into strips, then twist each strip and coil into a bun shape. Place on a lined baking sheet and let rise for 30 minutes.","timer":1800},{"title":"Bake the buns","text":"Brush each bun with beaten egg wash and sprinkle with pearl sugar. Bake at 400 degrees Fahrenheit for 12 to 15 minutes until golden brown. Cool slightly before serving.","timer":900}]','[{"original":"whole milk","swap":"oat milk for a dairy-free version"},{"original":"pearl sugar","swap":"coarse turbinado sugar"},{"original":"ground cardamom","swap":"ground cinnamon for a classic cinnamon bun flavor"}]','["Using milk that is too hot which kills the yeast and prevents the dough from rising","Not kneading the dough long enough resulting in dense buns","Skipping the second rise which leads to buns with poor texture and volume"]','["buns","cardamom","fika","baking","swedish","breakfast","pastry"]','["vegetarian"]','Bread and Pastry','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Matcha Tiramisu','matcha-tiramisu','A Japanese twist on the Italian classic using earthy matcha instead of espresso. Layers of matcha-soaked ladyfingers and creamy mascarpone create a stunning dessert.','Creamy no-bake matcha tiramisu with silky mascarpone and green tea soaked ladyfingers.','Japanese-Italian Fusion','Easy',25,0,265,8,340,7,30,22,1,'[{"amount":2,"unit":"tablespoons","item":"ceremonial grade matcha powder","group":"matcha soak"},{"amount":1.5,"unit":"cups","item":"hot water","group":"matcha soak"},{"amount":2,"unit":"tablespoons","item":"granulated sugar","group":"matcha soak"},{"amount":16,"unit":"pieces","item":"ladyfinger biscuits","group":"base"},{"amount":2,"unit":"cups","item":"mascarpone cheese","group":"cream"},{"amount":1,"unit":"cup","item":"heavy whipping cream","group":"cream"},{"amount":0.5,"unit":"cup","item":"powdered sugar","group":"cream"},{"amount":1,"unit":"teaspoon","item":"vanilla extract","group":"cream"},{"amount":1,"unit":"tablespoon","item":"matcha powder for dusting","group":"topping"}]','[{"title":"Prepare the matcha soak","text":"Sift matcha powder into a bowl and pour hot water over it. Whisk vigorously until no lumps remain, then stir in sugar. Let it cool to room temperature before using.","timer":600},{"title":"Make the mascarpone cream","text":"Whip heavy cream in a cold bowl until soft peaks form. In a separate bowl, beat mascarpone, powdered sugar, and vanilla until smooth. Gently fold whipped cream into the mascarpone mixture until fully combined.","timer":300},{"title":"Dip the ladyfingers","text":"Quickly dip each ladyfinger into the cooled matcha soak for just 2 seconds per side. Do not soak them too long or they will fall apart. Lay them in a single layer in a serving dish.","timer":60},{"title":"Layer the tiramisu","text":"Spread half the mascarpone cream over the first layer of ladyfingers. Add a second layer of dipped ladyfingers and top with the remaining cream. Smooth the surface evenly with a spatula.","timer":0},{"title":"Chill and serve","text":"Cover the dish and refrigerate for at least 4 hours or overnight for best results. Before serving, sift matcha powder generously over the top for a beautiful green finish.","timer":14400}]','[{"original":"mascarpone cheese","swap":"cream cheese blended with a little heavy cream"},{"original":"ladyfinger biscuits","swap":"sponge cake cut into strips"},{"original":"ceremonial grade matcha","swap":"culinary grade matcha for a more budget-friendly option"}]','["Soaking ladyfingers too long causing them to become completely soggy and fall apart","Not chilling the tiramisu long enough which results in a loose and runny texture","Using cold mascarpone straight from the fridge making it difficult to blend smoothly"]','["matcha","tiramisu","no-bake","japanese","fusion","dessert","make-ahead"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Chiffon Cake','lemon-chiffon-cake','A light and airy cake made with fresh lemon zest and juice for a bright citrus flavor. The chiffon method produces an incredibly tender and cloud-like crumb.','Light and fluffy lemon chiffon cake with a delicate crumb and fresh citrus brightness.','American','Medium',25,55,140,10,260,5,38,10,1,'[{"amount":2,"unit":"cups","item":"cake flour","group":"dry"},{"amount":1.5,"unit":"cups","item":"granulated sugar","group":"dry"},{"amount":1,"unit":"tablespoon","item":"baking powder","group":"dry"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"dry"},{"amount":0.5,"unit":"cup","item":"vegetable oil","group":"wet"},{"amount":6,"unit":"large","item":"eggs, separated","group":"wet"},{"amount":0.75,"unit":"cup","item":"fresh lemon juice","group":"wet"},{"amount":2,"unit":"tablespoons","item":"fresh lemon zest","group":"wet"},{"amount":0.5,"unit":"teaspoon","item":"cream of tartar","group":"meringue"}]','[{"title":"Preheat and prepare the pan","text":"Preheat oven to 325 degrees Fahrenheit. Use an ungreased 10-inch tube pan. Do not grease it as the batter needs to cling to the sides to rise properly.","timer":0},{"title":"Mix the wet and dry ingredients","text":"Whisk cake flour, sugar, baking powder, and salt in a large bowl. Make a well in the center and add oil, egg yolks, lemon juice, and lemon zest. Mix until the batter is very smooth.","timer":300},{"title":"Whip the egg whites","text":"In a clean bowl, beat egg whites with cream of tartar until stiff peaks form. The whites should be glossy and hold their shape firmly when the whisk is lifted.","timer":300},{"title":"Fold and combine","text":"Gently fold the egg whites into the batter in three additions using a rubber spatula. Use wide sweeping motions and do not overmix so as to preserve the air in the whites. Pour batter into the tube pan.","timer":0},{"title":"Bake and cool inverted","text":"Bake for 50 to 55 minutes until a skewer comes out clean. Immediately invert the pan onto its legs or over a bottle neck and allow to cool completely upside down. Once cool, run a knife around the edges to release.","timer":3300}]','[{"original":"cake flour","swap":"all-purpose flour minus 2 tablespoons per cup for a similar result"},{"original":"fresh lemon juice","swap":"fresh lime juice for a lime chiffon variation"},{"original":"vegetable oil","swap":"light flavored olive oil or avocado oil"}]','["Greasing the tube pan which prevents the cake from climbing the sides and causes it to collapse","Not inverting the cake immediately after baking which causes it to deflate under its own weight","Overmixing the egg whites into the batter which deflates the foam and results in a dense cake"]','["lemon","chiffon","cake","citrus","baking","light","american"]','["vegetarian","dairy-free"]','Cake','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Tacos','classic-beef-tacos','Seasoned ground beef nestled in warm corn tortillas and topped with fresh salsa and cheese. A quick and satisfying weeknight dinner the whole family will enjoy.','Easy and flavorful ground beef tacos ready in under 30 minutes.','Mexican','Easy',10,15,25,4,390,24,28,18,3,'[{"amount":1,"unit":"pound","item":"ground beef 80 percent lean","group":"filling"},{"amount":1,"unit":"packet","item":"taco seasoning","group":"filling"},{"amount":0.33,"unit":"cup","item":"water","group":"filling"},{"amount":8,"unit":"small","item":"corn tortillas","group":"base"},{"amount":1,"unit":"cup","item":"shredded cheddar cheese","group":"toppings"},{"amount":1,"unit":"cup","item":"fresh pico de gallo","group":"toppings"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"toppings"},{"amount":1,"unit":"cup","item":"shredded romaine lettuce","group":"toppings"}]','[{"title":"Brown the beef","text":"Heat a large skillet over medium-high heat. Add ground beef and cook, breaking it apart with a spoon, until no pink remains. Drain any excess fat from the pan before proceeding.","timer":480},{"title":"Season the meat","text":"Sprinkle taco seasoning over the browned beef and stir to coat evenly. Pour in water and stir to combine. Simmer over medium heat until the liquid reduces and the meat is richly coated in seasoning.","timer":300},{"title":"Warm the tortillas","text":"Heat corn tortillas one at a time in a dry skillet over medium heat for about 30 seconds per side. Wrap them in a clean towel to keep warm and pliable while you prepare the rest.","timer":120},{"title":"Prepare the toppings","text":"Set out all toppings in small bowls for easy assembly. Make sure the pico de gallo is well drained so it does not make the tortillas soggy. Shred lettuce finely for the best texture.","timer":0},{"title":"Assemble and serve","text":"Spoon seasoned beef into each warm tortilla. Add cheese, lettuce, pico de gallo, and a dollop of sour cream. Serve immediately while the tortillas and meat are still warm.","timer":0}]','[{"original":"ground beef","swap":"ground turkey or chicken for a lighter option"},{"original":"corn tortillas","swap":"flour tortillas for a softer shell"},{"original":"taco seasoning packet","swap":"homemade blend of cumin, chili powder, garlic powder, and paprika"}]','["Not draining the fat after browning the beef which makes the filling greasy and heavy","Skipping warming the tortillas which causes them to crack and break when folded","Overloading the tacos with too many toppings making them impossible to eat without falling apart"]','["tacos","beef","mexican","weeknight","quick","family-friendly"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Miso Glazed Salmon','miso-glazed-salmon','Salmon fillets coated in a savory and slightly sweet white miso glaze and broiled to perfection. The caramelized crust pairs beautifully with the rich fish.','Broiled salmon with a caramelized miso glaze that is ready in just 20 minutes.','Japanese','Easy',10,10,130,4,320,34,12,14,0,'[{"amount":4,"unit":"fillets","item":"salmon, skin-on","group":"protein"},{"amount":3,"unit":"tablespoons","item":"white miso paste","group":"glaze"},{"amount":2,"unit":"tablespoons","item":"mirin","group":"glaze"},{"amount":1,"unit":"tablespoon","item":"sake or dry white wine","group":"glaze"},{"amount":1,"unit":"tablespoon","item":"soy sauce","group":"glaze"},{"amount":1,"unit":"teaspoon","item":"sesame oil","group":"glaze"},{"amount":1,"unit":"tablespoon","item":"honey","group":"glaze"},{"amount":2,"unit":"stalks","item":"green onions, sliced for garnish","group":"garnish"}]','[{"title":"Make the miso glaze","text":"Whisk together miso paste, mirin, sake, soy sauce, sesame oil, and honey in a small bowl until completely smooth. The glaze should be thick but spreadable. Taste and adjust sweetness if desired.","timer":0},{"title":"Marinate the salmon","text":"Pat salmon fillets dry with paper towels and place them in a shallow dish. Spread the miso glaze generously over the flesh side of each fillet. Cover and refrigerate for at least 2 hours or up to 24 hours.","timer":7200},{"title":"Prepare the broiler","text":"Preheat your broiler to high and position the oven rack about 6 inches from the heat source. Line a baking sheet with foil and lightly coat with cooking spray to prevent sticking.","timer":300},{"title":"Broil the salmon","text":"Remove excess glaze from the salmon so it does not burn too quickly. Place fillets skin-side down on the prepared baking sheet. Broil for 8 to 10 minutes until the glaze is caramelized and dark in spots and the fish flakes easily.","timer":600},{"title":"Garnish and serve","text":"Remove salmon from the oven and let it rest for 2 minutes. Garnish with sliced green onions and serve with steamed rice and a simple cucumber salad for a complete meal.","timer":120}]','[{"original":"white miso paste","swap":"red miso for a stronger and more intense flavor"},{"original":"mirin","swap":"rice vinegar with a pinch of extra sugar to balance acidity"},{"original":"salmon","swap":"black cod or sea bass which also work beautifully with miso"}]','["Not patting the salmon dry before applying the glaze which prevents it from adhering properly","Leaving too much glaze on the fish before broiling which causes it to burn and turn bitter","Skipping the marinating time which results in a much less flavorful and aromatic dish"]','["salmon","miso","japanese","broiled","seafood","healthy","weeknight"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Rice Spicy Tuna Bites','crispy-rice-spicy-tuna-bites','Golden crispy rice squares topped with creamy spicy tuna make an irresistible appetizer. These bites are a restaurant-quality treat you can make at home.','Crispy sushi rice squares topped with a creamy and spicy tuna mixture for an elegant bite-sized appetizer.','Japanese-Fusion','Medium',20,15,35,4,310,18,34,11,1,'[{"amount":2,"unit":"cups","item":"cooked sushi rice","group":"base"},{"amount":2,"unit":"tbsp","item":"rice vinegar","group":"base"},{"amount":8,"unit":"oz","item":"sushi-grade tuna, finely chopped","group":"topping"},{"amount":3,"unit":"tbsp","item":"sriracha mayo","group":"topping"},{"amount":1,"unit":"tbsp","item":"soy sauce","group":"topping"},{"amount":1,"unit":"tsp","item":"sesame oil","group":"topping"},{"amount":2,"unit":"tbsp","item":"neutral oil for frying","group":"cooking"},{"amount":2,"unit":"stalks","item":"green onion, thinly sliced","group":"garnish"},{"amount":1,"unit":"tsp","item":"black sesame seeds","group":"garnish"}]','[{"title":"Season and press the rice","text":"Mix cooked sushi rice with rice vinegar and a pinch of salt. Press the rice firmly into a parchment-lined baking dish to about 1 inch thickness. Refrigerate for at least 1 hour until firm.","timer":3600},{"title":"Prepare the spicy tuna","text":"Combine the finely chopped sushi-grade tuna with sriracha mayo, soy sauce, and sesame oil in a bowl. Mix gently until well combined. Refrigerate until ready to use.","timer":0},{"title":"Cut and fry the rice","text":"Remove the chilled rice from the dish and cut into 2-inch rectangles. Heat neutral oil in a skillet over medium-high heat and fry the rice pieces for 3 to 4 minutes per side until golden and crispy.","timer":480},{"title":"Drain and cool","text":"Transfer the crispy rice pieces to a paper towel-lined plate to drain excess oil. Allow them to cool slightly for 2 minutes so the topping does not melt on contact.","timer":120},{"title":"Top and serve","text":"Spoon a generous amount of the spicy tuna mixture onto each crispy rice piece. Garnish with sliced green onions and black sesame seeds. Serve immediately for best texture.","timer":0}]','[{"original":"sushi-grade tuna","swap":"sushi-grade salmon for a milder flavor"},{"original":"sriracha mayo","swap":"mix of regular mayo and chili garlic sauce"},{"original":"sushi rice","swap":"short-grain white rice seasoned with vinegar and sugar"}]','["Do not skip chilling the rice as it will fall apart when frying","Do not use warm rice squares or the tuna topping will warm and lose freshness","Do not overcrowd the pan when frying or the rice will steam instead of crisp"]','["appetizer","spicy","tuna","sushi","crispy","party food","Japanese"]','["dairy-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Air Fryer Pasta Chips','air-fryer-pasta-chips','Crunchy seasoned pasta chips made in the air fryer are the ultimate addictive snack. They are golden, crispy, and packed with bold Italian-inspired flavor.','Boiled pasta tossed in olive oil and seasonings then air-fried until irresistibly crunchy and golden.','Italian-American','Easy',10,15,25,4,280,9,42,9,2,'[{"amount":8,"unit":"oz","item":"farfalle or rigatoni pasta","group":"base"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"seasoning"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":3,"unit":"tbsp","item":"grated parmesan cheese","group":"topping"},{"amount":2,"unit":"tbsp","item":"marinara sauce for dipping","group":"serving"}]','[{"title":"Cook the pasta","text":"Boil the pasta in salted water according to package directions until al dente. Do not overcook the pasta as it will continue to crisp in the air fryer. Drain and pat dry thoroughly with paper towels.","timer":600},{"title":"Season the pasta","text":"Toss the dried pasta in a large bowl with olive oil, garlic powder, Italian seasoning, smoked paprika, red pepper flakes, and salt. Make sure every piece is evenly coated with the oil and spices.","timer":0},{"title":"Air fry the pasta","text":"Spread the seasoned pasta in a single layer in the air fryer basket. Air fry at 400 degrees F for 10 to 12 minutes, shaking the basket halfway through, until golden and crispy.","timer":720},{"title":"Add parmesan","text":"Remove the pasta chips from the air fryer and immediately toss with grated parmesan cheese while still hot. The heat will help the cheese stick to each chip perfectly.","timer":0},{"title":"Serve with dipping sauce","text":"Allow the pasta chips to cool for 2 minutes so they reach maximum crunch. Serve in a bowl alongside warm marinara sauce for dipping. Enjoy as a snack or party appetizer.","timer":120}]','[{"original":"farfalle pasta","swap":"rigatoni or penne for a different shape"},{"original":"parmesan cheese","swap":"nutritional yeast for a dairy-free option"},{"original":"marinara dipping sauce","swap":"ranch dressing or spicy arrabbiata sauce"}]','["Do not skip drying the pasta thoroughly or it will steam instead of crisp in the air fryer","Do not overcrowd the air fryer basket as the chips need airflow to crisp evenly","Do not overcook the pasta during boiling or the chips will become too hard and brittle"]','["snack","pasta","air fryer","crispy","vegetarian","party food","Italian"]','["vegetarian"]','Snack','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Salmon Rice Bowls','spicy-salmon-rice-bowls','Tender baked salmon glazed with a sweet and spicy sauce served over fluffy steamed rice with fresh toppings. This bowl is a satisfying and nutritious weeknight meal.','Flaky spicy glazed salmon served over rice with avocado, cucumber, and a drizzle of sriracha mayo.','Asian-Fusion','Easy',10,15,25,2,520,38,48,18,4,'[{"amount":2,"unit":"fillets","item":"salmon, about 6 oz each","group":"protein"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"marinade"},{"amount":1,"unit":"tbsp","item":"sriracha sauce","group":"marinade"},{"amount":1,"unit":"tbsp","item":"honey","group":"marinade"},{"amount":1,"unit":"tsp","item":"sesame oil","group":"marinade"},{"amount":2,"unit":"cups","item":"cooked jasmine rice","group":"base"},{"amount":1,"unit":"whole","item":"avocado, sliced","group":"toppings"},{"amount":0.5,"unit":"whole","item":"cucumber, thinly sliced","group":"toppings"},{"amount":2,"unit":"tbsp","item":"sriracha mayo for drizzling","group":"toppings"}]','[{"title":"Make the glaze","text":"Whisk together soy sauce, sriracha, honey, and sesame oil in a small bowl until smooth. This glaze will serve as both a marinade and a finishing sauce for the salmon.","timer":0},{"title":"Marinate the salmon","text":"Place salmon fillets in a shallow dish and pour half of the glaze over them. Let the salmon marinate for at least 10 minutes while you prepare the other bowl components.","timer":600},{"title":"Bake the salmon","text":"Preheat the oven to 400 degrees F. Place the marinated salmon on a lined baking sheet and bake for 12 to 14 minutes until the salmon flakes easily with a fork. Brush with remaining glaze halfway through.","timer":840},{"title":"Prepare the bowl base","text":"Divide the cooked jasmine rice evenly between two bowls. Arrange the sliced avocado and cucumber around the edges of the bowl to create a colorful and inviting presentation.","timer":0},{"title":"Assemble and serve","text":"Place one baked salmon fillet on top of each rice bowl. Drizzle generously with sriracha mayo and add any additional garnishes like sesame seeds or green onions. Serve immediately.","timer":0}]','[{"original":"salmon","swap":"tuna steaks or shrimp for a different protein"},{"original":"jasmine rice","swap":"cauliflower rice for a low-carb option"},{"original":"honey","swap":"maple syrup or brown sugar for the glaze"}]','["Do not overbake the salmon or it will become dry and lose its flaky texture","Do not skip marinating the salmon even briefly as it significantly enhances flavor","Do not add avocado too early as it will brown and lose its fresh appearance"]','["salmon","rice bowl","spicy","healthy","weeknight dinner","Asian","gluten-free option"]','["gluten-free option","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Shrimp Tacos','garlic-butter-shrimp-tacos','Juicy garlic butter shrimp piled into warm tortillas with a cool and creamy slaw creates a perfect taco night meal. These tacos come together in under 30 minutes for a fast and flavorful dinner.','Tender garlic butter shrimp tucked into soft tortillas and topped with a bright and creamy cabbage slaw.','Mexican-American','Easy',15,10,25,4,390,28,32,16,3,'[{"amount":1,"unit":"lb","item":"large shrimp, peeled and deveined","group":"protein"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"sauce"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":0.5,"unit":"tsp","item":"cumin","group":"seasoning"},{"amount":8,"unit":"small","item":"flour or corn tortillas","group":"base"},{"amount":2,"unit":"cups","item":"shredded cabbage","group":"slaw"},{"amount":3,"unit":"tbsp","item":"sour cream","group":"slaw"},{"amount":1,"unit":"whole","item":"lime, juiced","group":"slaw"}]','[{"title":"Make the slaw","text":"In a medium bowl, toss shredded cabbage with sour cream and lime juice. Season with salt and pepper to taste. Refrigerate the slaw while you prepare the shrimp so the flavors can meld together.","timer":0},{"title":"Season the shrimp","text":"Pat the shrimp dry with paper towels and toss with smoked paprika, cumin, salt, and pepper in a bowl. Dry shrimp will sear much better than wet shrimp and develop a better crust.","timer":0},{"title":"Cook the shrimp","text":"Melt butter in a large skillet over medium-high heat. Add minced garlic and cook for 30 seconds until fragrant. Add the seasoned shrimp in a single layer and cook for 2 minutes per side until pink and opaque.","timer":300},{"title":"Warm the tortillas","text":"While the shrimp rest, warm the tortillas directly over a gas flame or in a dry skillet for 30 seconds per side until slightly charred and pliable. Keep them wrapped in a towel to stay warm.","timer":120},{"title":"Assemble the tacos","text":"Place 3 to 4 shrimp on each warm tortilla. Top generously with the creamy cabbage slaw and finish with a squeeze of fresh lime juice. Serve immediately while the shrimp are still warm.","timer":0}]','[{"original":"shrimp","swap":"fish fillets like tilapia or cod cut into strips"},{"original":"sour cream","swap":"Greek yogurt for a lighter and tangier slaw"},{"original":"flour tortillas","swap":"corn tortillas for a gluten-free option"}]','["Do not overcook the shrimp as they become rubbery and tough very quickly","Do not skip patting the shrimp dry or they will steam rather than sear in the pan","Do not assemble the tacos too far ahead as the tortillas will become soggy from the slaw"]','["tacos","shrimp","seafood","quick dinner","Mexican","weeknight","garlic butter"]','["pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Miso Glazed Chicken Thighs','honey-miso-glazed-chicken-thighs','Sticky and caramelized honey miso glazed chicken thighs deliver a rich umami-packed flavor in every bite. The glaze creates a beautiful lacquered finish that makes this dish look as impressive as it tastes.','Juicy oven-roasted chicken thighs coated in a sticky sweet and savory honey miso glaze.','Asian-Fusion','Easy',10,35,45,4,420,32,18,24,1,'[{"amount":8,"unit":"pieces","item":"bone-in skin-on chicken thighs","group":"protein"},{"amount":3,"unit":"tbsp","item":"white miso paste","group":"glaze"},{"amount":2,"unit":"tbsp","item":"honey","group":"glaze"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"glaze"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"glaze"},{"amount":1,"unit":"tbsp","item":"fresh ginger, grated","group":"glaze"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"glaze"},{"amount":1,"unit":"tsp","item":"sesame oil","group":"glaze"},{"amount":1,"unit":"tbsp","item":"sesame seeds for garnish","group":"garnish"}]','[{"title":"Prepare the miso glaze","text":"Whisk together miso paste, honey, soy sauce, rice vinegar, grated ginger, garlic, and sesame oil in a bowl until completely smooth. Set aside 2 tablespoons of the glaze for serving at the end.","timer":0},{"title":"Marinate the chicken","text":"Pat the chicken thighs dry and score the skin lightly with a knife. Coat all sides of the chicken generously with the miso glaze. Marinate for at least 20 minutes or up to overnight in the refrigerator.","timer":1200},{"title":"Sear the chicken","text":"Heat an oven-safe skillet over medium-high heat. Place chicken thighs skin-side down and sear for 5 minutes until the skin is golden and caramelized. Flip and sear the other side for 2 more minutes.","timer":420},{"title":"Roast in the oven","text":"Transfer the skillet to a preheated 400 degree F oven and roast for 25 to 28 minutes until the internal temperature reaches 165 degrees F. Brush with additional glaze halfway through roasting.","timer":1680},{"title":"Rest and serve","text":"Remove the chicken from the oven and let it rest for 5 minutes before serving. Drizzle with the reserved glaze and garnish with sesame seeds and sliced green onions. Serve over steamed rice.","timer":300}]','[{"original":"white miso paste","swap":"red miso for a deeper and more intense flavor"},{"original":"honey","swap":"maple syrup or agave nectar for a different sweetness"},{"original":"bone-in chicken thighs","swap":"boneless skinless thighs for a faster cooking time"}]','["Do not skip drying the chicken skin or it will not sear properly and will turn out soggy","Do not rush the searing step as a golden crust adds important flavor to the final dish","Do not skip resting the chicken after roasting or the juices will run out when cut"]','["chicken","miso","honey glaze","Asian","oven roasted","weeknight dinner","umami"]','["dairy-free","gluten-free option"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Zuppa Toscana','zuppa-toscana','A creamy hearty Italian soup loaded with spicy sausage, tender potatoes, and fresh kale. This Olive Garden copycat is rich, satisfying, and ready in under an hour.','Creamy Italian sausage and potato soup with kale in a savory broth.','Italian','Easy',15,35,50,6,480,22,28,32,3,'[{"amount":1,"unit":"lb","item":"spicy Italian sausage","group":"protein"},{"amount":4,"unit":"slices","item":"bacon chopped","group":"protein"},{"amount":4,"unit":"medium","item":"russet potatoes sliced thin","group":"vegetables"},{"amount":3,"unit":"cups","item":"fresh kale chopped","group":"vegetables"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":4,"unit":"cups","item":"chicken broth","group":"liquid"},{"amount":2,"unit":"cups","item":"heavy cream","group":"dairy"},{"amount":1,"unit":"tsp","item":"crushed red pepper flakes","group":"spices"},{"amount":1,"unit":"tsp","item":"salt","group":"spices"}]','[{"title":"Brown the meats","text":"In a large pot over medium heat, cook the chopped bacon until crispy. Remove and set aside. In the same pot, add the spicy Italian sausage and cook until browned and crumbled, about 6 minutes. Drain excess fat leaving about 1 tablespoon in the pot.","timer":480},{"title":"Saute aromatics","text":"Add the diced onion to the pot and cook until softened, about 4 minutes. Add the minced garlic and red pepper flakes and cook for 1 more minute until fragrant.","timer":300},{"title":"Simmer the potatoes","text":"Pour in the chicken broth and bring to a boil. Add the thinly sliced potatoes and reduce heat to a gentle simmer. Cook for 15 minutes or until the potatoes are fork tender.","timer":900},{"title":"Add cream and kale","text":"Stir in the heavy cream and chopped kale. Return the cooked bacon to the pot. Simmer for 5 more minutes until the kale is wilted and the soup is heated through. Season with salt to taste.","timer":300},{"title":"Serve","text":"Ladle the soup into bowls and garnish with extra bacon crumbles and a pinch of red pepper flakes. Serve immediately with crusty bread.","timer":0}]','[{"original":"heavy cream","swap":"half and half for a lighter version"},{"original":"spicy Italian sausage","swap":"mild Italian sausage plus extra red pepper flakes"},{"original":"kale","swap":"spinach added in the last 2 minutes of cooking"}]','["Slicing potatoes too thick which leads to uneven or undercooked pieces","Adding the kale too early which makes it tough and overly bitter","Boiling the soup after adding cream which can cause it to curdle"]','["soup","Italian","creamy","sausage","comfort food","copycat"]','["gluten-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Broccoli Cheddar Soup','broccoli-cheddar-soup','A velvety smooth soup packed with tender broccoli florets and sharp cheddar cheese. This classic comfort soup is thick, cheesy, and absolutely irresistible.','Rich and creamy cheddar soup loaded with fresh broccoli florets.','American','Easy',10,30,40,4,520,18,24,38,4,'[{"amount":4,"unit":"cups","item":"fresh broccoli florets","group":"vegetables"},{"amount":1,"unit":"medium","item":"carrot shredded","group":"vegetables"},{"amount":1,"unit":"small","item":"yellow onion diced","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"fat"},{"amount":3,"unit":"tbsp","item":"all purpose flour","group":"thickener"},{"amount":2,"unit":"cups","item":"chicken or vegetable broth","group":"liquid"},{"amount":2,"unit":"cups","item":"whole milk","group":"dairy"},{"amount":2.5,"unit":"cups","item":"sharp cheddar cheese shredded","group":"dairy"},{"amount":0.5,"unit":"tsp","item":"smoked paprika","group":"spices"}]','[{"title":"Build the base","text":"Melt butter in a large pot over medium heat. Add the diced onion and cook for 4 minutes until softened. Add the minced garlic and cook for 1 more minute. Sprinkle in the flour and stir constantly for 2 minutes to cook out the raw flour taste.","timer":420},{"title":"Add liquids","text":"Slowly whisk in the chicken broth and whole milk, adding them gradually to prevent lumps. Whisk continuously until the mixture is smooth and starting to thicken, about 5 minutes.","timer":300},{"title":"Cook the vegetables","text":"Add the broccoli florets and shredded carrot to the pot. Simmer over medium low heat for 15 minutes until the broccoli is very tender. Stir in the smoked paprika.","timer":900},{"title":"Melt in the cheese","text":"Remove the pot from heat or reduce to the lowest setting. Add the shredded cheddar cheese in three batches, stirring until fully melted between each addition. Do not let the soup boil after adding the cheese.","timer":180},{"title":"Finish and serve","text":"Taste and season with salt and pepper as needed. For a smoother texture, use an immersion blender to partially blend the soup. Serve in bread bowls or regular bowls topped with extra shredded cheddar.","timer":0}]','[{"original":"whole milk","swap":"heavy cream for an even richer soup"},{"original":"sharp cheddar","swap":"Gruyere for a more nutty sophisticated flavor"},{"original":"all purpose flour","swap":"cornstarch slurry for a gluten free version"}]','["Adding the cheese while the soup is boiling which causes it to become grainy and stringy","Using pre shredded bagged cheese which contains anti caking agents that prevent smooth melting","Skipping the flour cooking step which results in a raw starchy flavor in the finished soup"]','["soup","cheesy","comfort food","vegetarian option","cheddar","broccoli"]','["vegetarian"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Chicken Noodle Soup','classic-chicken-noodle-soup','A timeless homemade chicken noodle soup with tender shredded chicken, hearty vegetables, and egg noodles in a golden broth. This soul warming bowl is the ultimate comfort food for any occasion.','Homestyle chicken noodle soup with shredded chicken and egg noodles in a savory golden broth.','American','Easy',15,40,55,6,310,28,30,8,3,'[{"amount":1.5,"unit":"lbs","item":"boneless skinless chicken breasts","group":"protein"},{"amount":3,"unit":"medium","item":"carrots sliced","group":"vegetables"},{"amount":3,"unit":"stalks","item":"celery sliced","group":"vegetables"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":6,"unit":"cups","item":"chicken broth","group":"liquid"},{"amount":2,"unit":"cups","item":"egg noodles uncooked","group":"pasta"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"},{"amount":1,"unit":"tsp","item":"dried thyme","group":"spices"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"}]','[{"title":"Saute the vegetables","text":"Heat olive oil in a large pot over medium heat. Add the diced onion, sliced carrots, and sliced celery. Cook for 6 minutes until the vegetables begin to soften. Add the minced garlic and dried thyme and cook for 1 more minute.","timer":420},{"title":"Cook the chicken","text":"Add the whole chicken breasts directly to the pot. Pour in the chicken broth and bring to a boil. Reduce heat to a steady simmer and cook the chicken for 20 minutes until fully cooked through.","timer":1200},{"title":"Shred the chicken","text":"Remove the cooked chicken breasts from the pot and place on a cutting board. Use two forks to shred the chicken into bite sized pieces. Return the shredded chicken back to the pot.","timer":180},{"title":"Add the noodles","text":"Bring the soup back to a boil and add the egg noodles. Cook according to package directions, usually 7 to 9 minutes, until the noodles are tender. Do not overcook the noodles or they will become mushy.","timer":480},{"title":"Season and serve","text":"Taste the soup and season with salt and black pepper as needed. Stir in the fresh chopped parsley. Ladle into bowls and serve hot with crusty bread or crackers on the side.","timer":0}]','[{"original":"boneless skinless chicken breasts","swap":"bone in chicken thighs for richer flavor"},{"original":"egg noodles","swap":"rotini or any short pasta shape"},{"original":"dried thyme","swap":"fresh thyme using 3 sprigs added with the broth"}]','["Adding the noodles too early which causes them to soak up all the broth and become mushy","Cooking the soup at a rolling boil the entire time which makes the chicken tough and the broth cloudy","Under seasoning the broth which results in a flat and bland finished soup"]','["soup","chicken","noodle","classic","comfort food","family friendly"]','["dairy-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Tomato Basil Soup','tomato-basil-soup','A silky smooth roasted tomato soup bursting with fresh basil and a touch of cream. This elevated classic pairs perfectly with a grilled cheese sandwich.','Velvety roasted tomato soup finished with fresh basil and a swirl of cream.','American','Easy',10,35,45,4,280,6,22,18,5,'[{"amount":28,"unit":"oz","item":"canned whole San Marzano tomatoes","group":"vegetables"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":0.5,"unit":"cup","item":"fresh basil leaves packed","group":"herbs"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"fat"},{"amount":2,"unit":"cups","item":"vegetable broth","group":"liquid"},{"amount":0.5,"unit":"cup","item":"heavy cream","group":"dairy"},{"amount":1,"unit":"tbsp","item":"tomato paste","group":"flavor"},{"amount":1,"unit":"tsp","item":"sugar","group":"flavor"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"spices"}]','[{"title":"Saute aromatics","text":"Heat olive oil in a large pot over medium heat. Add the diced onion and cook for 5 minutes until translucent. Add the minced garlic and tomato paste and cook for 2 more minutes, stirring frequently to prevent burning.","timer":420},{"title":"Build the soup","text":"Pour in the canned tomatoes with all their juices and the vegetable broth. Add the sugar and black pepper. Stir to combine and bring the mixture to a boil, then reduce to a simmer.","timer":300},{"title":"Simmer","text":"Let the soup simmer uncovered for 20 minutes to allow the flavors to meld together and the tomatoes to break down completely. Stir occasionally.","timer":1200},{"title":"Blend smooth","text":"Remove the pot from heat and add the fresh basil leaves. Use an immersion blender to blend the soup completely smooth. Alternatively transfer in batches to a blender but do not fill more than halfway with hot liquid.","timer":120},{"title":"Finish with cream","text":"Return the blended soup to low heat and stir in the heavy cream. Warm gently for 3 minutes but do not boil. Taste and adjust seasoning with salt. Serve with a drizzle of cream and fresh basil leaves on top.","timer":180}]','[{"original":"heavy cream","swap":"coconut cream for a dairy free version"},{"original":"canned whole tomatoes","swap":"2 lbs fresh roma tomatoes roasted in the oven"},{"original":"sugar","swap":"a pinch of baking soda to reduce acidity without sweetness"}]','["Filling the blender too full with hot soup which can cause the lid to blow off and cause burns","Skipping the sugar or acid balance step which leaves the soup tasting sharp and overly acidic","Boiling the soup after adding cream which causes it to separate and look unappetizing"]','["soup","tomato","vegetarian","blended","comfort food","classic"]','["vegetarian","gluten-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('French Onion Soup','french-onion-soup','A deeply rich and savory soup made with slow caramelized onions in a robust beef broth topped with crusty bread and bubbling Gruyere cheese. This French bistro classic is pure indulgence in a bowl.','Classic French soup featuring sweet caramelized onions topped with toasted bread and melted Gruyere.','French','Medium',15,75,90,4,420,16,38,20,4,'[{"amount":4,"unit":"large","item":"yellow onions thinly sliced","group":"vegetables"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"fat"},{"amount":4,"unit":"cups","item":"beef broth","group":"liquid"},{"amount":0.5,"unit":"cup","item":"dry white wine","group":"liquid"},{"amount":4,"unit":"slices","item":"French baguette toasted","group":"bread"},{"amount":1.5,"unit":"cups","item":"Gruyere cheese shredded","group":"dairy"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"tsp","item":"fresh thyme leaves","group":"herbs"},{"amount":1,"unit":"tbsp","item":"Worcestershire sauce","group":"flavor"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"spices"}]','[{"title":"Caramelize the onions","text":"Melt butter in a large heavy bottomed pot over medium low heat. Add all the sliced onions and a pinch of salt. Cook stirring every 5 minutes for 50 to 60 minutes until the onions are deep golden brown and completely caramelized. Do not rush this step by using high heat.","timer":3600},{"title":"Deglaze and build broth","text":"Add the minced garlic and cook for 1 minute. Pour in the white wine and scrape up any browned bits from the bottom of the pot. Add the beef broth, Worcestershire sauce, and fresh thyme. Season with black pepper.","timer":120},{"title":"Simmer the soup","text":"Bring the soup to a boil then reduce heat and simmer for 15 minutes to allow all the flavors to meld together. Taste and adjust seasoning with salt and pepper as needed.","timer":900},{"title":"Prepare the toppings","text":"Preheat your broiler to high. Ladle the hot soup into oven safe bowls placed on a baking sheet. Float one slice of toasted baguette on top of each bowl of soup.","timer":120},{"title":"Broil and serve","text":"Cover each piece of bread generously with shredded Gruyere cheese. Place the baking sheet under the broiler for 3 to 5 minutes until the cheese is melted, bubbly, and lightly browned on top. Serve immediately with caution as the bowls will be extremely hot.","timer":240}]','[{"original":"Gruyere cheese","swap":"Swiss cheese or a mix of provolone and mozzarella"},{"original":"dry white wine","swap":"extra beef broth with a splash of apple cider vinegar"},{"original":"beef broth","swap":"vegetable broth for a vegetarian version"}]','["Trying to speed up the caramelization process with high heat which burns the onions instead of caramelizing them","Using regular bowls that are not oven safe which can crack or shatter under the broiler","Not toasting the bread before placing it on the soup which causes it to become soggy and fall apart"]','["soup","French","onion","cheese","comfort food","bistro classic"]','[]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pozole Rojo','pozole-rojo','A rich and hearty Mexican hominy stew made with tender pork and a deep red chile broth. This traditional dish is topped with fresh garnishes for a satisfying meal.','Classic Mexican red chile and hominy stew with tender braised pork.','Mexican','Medium',30,120,150,6,480,38,42,16,7,'[{"amount":2,"unit":"lbs","item":"pork shoulder cut into chunks","group":"protein"},{"amount":2,"unit":"cans","item":"hominy drained and rinsed","group":"base"},{"amount":4,"unit":"whole","item":"dried guajillo chiles stemmed and seeded","group":"chile sauce"},{"amount":3,"unit":"whole","item":"dried ancho chiles stemmed and seeded","group":"chile sauce"},{"amount":6,"unit":"cloves","item":"garlic","group":"aromatics"},{"amount":1,"unit":"whole","item":"white onion halved","group":"aromatics"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"seasoning"},{"amount":6,"unit":"cups","item":"chicken or pork broth","group":"base"},{"amount":2,"unit":"tsp","item":"kosher salt","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"vegetable oil","group":"cooking"}]','[{"title":"Toast and Soak Chiles","text":"Heat a dry skillet over medium heat and toast the guajillo and ancho chiles for about 30 seconds per side until fragrant. Place them in a bowl of hot water and soak for 20 minutes until softened.","timer":1200},{"title":"Brown the Pork","text":"Heat vegetable oil in a large pot over high heat. Season the pork chunks with salt and sear them in batches until browned on all sides. Remove and set aside.","timer":600},{"title":"Build the Chile Sauce","text":"Blend the soaked chiles with garlic, half the onion, and 1 cup of the soaking liquid until completely smooth. Strain the sauce through a fine mesh sieve.","timer":300},{"title":"Simmer the Stew","text":"Return the pork to the pot and pour in the chile sauce and remaining broth. Add oregano and bring to a boil, then reduce heat and simmer covered for 90 minutes until pork is very tender. Add hominy in the last 30 minutes.","timer":5400},{"title":"Shred and Serve","text":"Remove the pork and shred it with two forks, then return it to the pot. Taste and adjust seasoning. Serve hot with toppings such as shredded cabbage, radishes, lime wedges, and dried oregano.","timer":300}]','[{"original":"pork shoulder","swap":"chicken thighs for a lighter version"},{"original":"guajillo chiles","swap":"New Mexico dried chiles for a milder flavor"},{"original":"hominy","swap":"canned white beans for a different texture"}]','["Skipping the toasting step which removes bitterness from the dried chiles","Not straining the chile sauce resulting in a gritty texture","Adding hominy too early which causes it to become mushy"]','["Mexican","stew","pork","hominy","chile","comfort food","slow cooked"]','["gluten-free","dairy-free"]','Soup and Stew','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lobster Bisque','lobster-bisque','A luxurious and velvety French-style cream soup made with rich lobster stock and tender lobster meat. This elegant bisque is perfect for special occasions and dinner parties.','Silky and rich cream soup packed with sweet lobster flavor.','French','Hard',40,60,100,4,520,28,18,36,2,'[{"amount":2,"unit":"whole","item":"lobster tails shells reserved","group":"protein"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"cooking"},{"amount":1,"unit":"whole","item":"medium onion finely diced","group":"aromatics"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"tomato paste","group":"base"},{"amount":0.5,"unit":"cup","item":"dry sherry","group":"liquid"},{"amount":2,"unit":"cups","item":"seafood or fish stock","group":"liquid"},{"amount":2,"unit":"cups","item":"heavy cream","group":"dairy"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"all purpose flour","group":"thickener"}]','[{"title":"Cook and Prep the Lobster","text":"Steam or boil the lobster tails for 8 minutes until cooked through. Remove the meat and cut into chunks. Reserve the shells for making stock.","timer":480},{"title":"Make the Shell Stock","text":"Simmer the reserved lobster shells in the seafood stock with a splash of water for 20 minutes. Strain and discard the shells, keeping the rich infused stock.","timer":1200},{"title":"Build the Bisque Base","text":"Melt butter in a large pot over medium heat. Saute onion and garlic until soft, about 5 minutes. Add flour and tomato paste and cook for 2 minutes, stirring constantly. Pour in the sherry and cook for 1 minute.","timer":480},{"title":"Simmer and Blend","text":"Add the lobster stock to the pot and bring to a simmer. Cook for 15 minutes, then carefully blend the soup until completely smooth. Return to the pot and stir in the heavy cream and smoked paprika.","timer":900},{"title":"Finish and Serve","text":"Gently heat the bisque over low heat without boiling. Add the reserved lobster meat and warm through for 3 minutes. Season with salt and white pepper and serve in warm bowls with a swirl of cream.","timer":300}]','[{"original":"lobster tails","swap":"large shrimp or langoustines for a budget friendly option"},{"original":"dry sherry","swap":"dry white wine or brandy"},{"original":"heavy cream","swap":"coconut cream for a dairy free version"}]','["Boiling the bisque after adding cream which causes it to curdle and separate","Skipping the shell stock step which removes the deep lobster flavor","Over blending the bisque without straining resulting in a foamy texture"]','["French","seafood","lobster","bisque","elegant","cream soup","special occasion"]','["gluten-free adaptable"]','Soup and Stew','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hungarian Mushroom Soup','hungarian-mushroom-soup','A deeply savory and smoky soup made with earthy mushrooms, sweet paprika, and tangy sour cream. This comforting Hungarian classic is thick, bold, and incredibly satisfying.','Creamy and paprika spiced Hungarian mushroom soup with sour cream.','Hungarian','Easy',15,35,50,4,310,9,22,21,3,'[{"amount":1,"unit":"lb","item":"cremini mushrooms sliced","group":"main"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"cooking"},{"amount":1,"unit":"whole","item":"large onion diced","group":"aromatics"},{"amount":2,"unit":"tbsp","item":"sweet Hungarian paprika","group":"seasoning"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"seasoning"},{"amount":3,"unit":"tbsp","item":"all purpose flour","group":"thickener"},{"amount":3,"unit":"cups","item":"vegetable broth","group":"liquid"},{"amount":1,"unit":"cup","item":"sour cream","group":"dairy"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh dill chopped","group":"herbs"}]','[{"title":"Saute Onion and Mushrooms","text":"Melt butter in a large pot over medium heat. Add the diced onion and cook for 5 minutes until translucent. Add the sliced mushrooms and cook for another 8 minutes until they release their liquid and begin to brown.","timer":780},{"title":"Add Paprika and Flour","text":"Stir in the sweet paprika, smoked paprika, and soy sauce, cooking for 1 minute to bloom the spices. Sprinkle in the flour and stir well to coat the mushrooms evenly, cooking for another 2 minutes.","timer":180},{"title":"Add Broth and Simmer","text":"Gradually pour in the vegetable broth while stirring constantly to prevent lumps. Bring the soup to a gentle boil, then reduce heat and simmer for 15 minutes until the soup thickens.","timer":900},{"title":"Temper and Add Sour Cream","text":"Remove the pot from heat. Place the sour cream in a small bowl and add a few ladles of the hot soup while whisking to temper it. Stir the tempered mixture back into the pot to prevent curdling.","timer":120},{"title":"Season and Serve","text":"Return the pot to low heat and warm gently without boiling. Stir in the fresh dill and adjust seasoning with salt and pepper. Serve with crusty bread and an extra dollop of sour cream.","timer":180}]','[{"original":"cremini mushrooms","swap":"a mix of shiitake and portobello mushrooms for deeper flavor"},{"original":"sour cream","swap":"plain Greek yogurt for a lighter result"},{"original":"vegetable broth","swap":"beef broth for a richer and more savory soup"}]','["Adding sour cream directly to boiling soup which causes it to curdle","Using generic paprika instead of authentic Hungarian sweet paprika which reduces the depth of flavor","Not cooking the flour long enough resulting in a raw starchy taste"]','["Hungarian","mushroom","vegetarian","creamy","paprika","comfort food","fall"]','["vegetarian"]','Soup and Stew','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic French Onion Soup','classic-french-onion-soup','A deeply caramelized onion soup topped with crusty bread and a golden layer of melted Gruyere cheese. This timeless French bistro classic is pure comfort in a bowl.','Slow cooked caramelized onion soup finished with melted Gruyere cheese croutons.','French','Medium',20,90,110,4,430,18,38,22,4,'[{"amount":4,"unit":"large","item":"yellow onions thinly sliced","group":"main"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"cooking"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":0.5,"unit":"cup","item":"dry white wine","group":"liquid"},{"amount":4,"unit":"cups","item":"beef broth","group":"liquid"},{"amount":1,"unit":"tbsp","item":"fresh thyme leaves","group":"herbs"},{"amount":4,"unit":"thick slices","item":"baguette toasted","group":"topping"},{"amount":1.5,"unit":"cups","item":"Gruyere cheese shredded","group":"topping"},{"amount":1,"unit":"tsp","item":"sugar","group":"seasoning"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"aromatics"}]','[{"title":"Caramelize the Onions","text":"Melt butter with olive oil in a heavy pot over medium low heat. Add all the sliced onions and sugar, then cook slowly for 60 to 70 minutes stirring every 10 minutes until deeply golden brown and caramelized. Do not rush this step.","timer":4200},{"title":"Deglaze and Build Broth","text":"Add garlic and cook for 1 minute. Pour in the white wine and scrape up all the browned bits from the bottom of the pot. Cook for 3 minutes until the wine reduces by half.","timer":240},{"title":"Simmer the Soup","text":"Add the beef broth and thyme to the pot. Bring to a boil, then reduce heat and simmer uncovered for 20 minutes. Taste and season generously with salt and black pepper.","timer":1200},{"title":"Assemble the Crocks","text":"Preheat your broiler to high. Ladle the hot soup into oven safe crocks or bowls placed on a baking sheet. Place a toasted baguette slice on top of each bowl and pile the shredded Gruyere generously over the bread.","timer":300},{"title":"Broil and Serve","text":"Place the baking sheet under the broiler for 3 to 4 minutes until the cheese is fully melted, bubbling, and golden brown in spots. Watch carefully to avoid burning. Serve immediately with caution as the bowls will be very hot.","timer":240}]','[{"original":"Gruyere cheese","swap":"Swiss or Emmental cheese for a similar melting quality"},{"original":"dry white wine","swap":"dry vermouth or additional beef broth"},{"original":"beef broth","swap":"vegetable broth to make the soup vegetarian"}]','["Rushing the caramelization process by using high heat which burns the onions instead of sweetening them","Using sweet onions instead of yellow onions which do not develop the same savory depth","Not using oven safe bowls which can crack or shatter under the broiler"]','["French","onion","cheese","soup","comfort food","winter","bistro","classic"]','["vegetarian adaptable"]','Soup and Stew','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Thai Coconut Soup','spicy-thai-coconut-soup','A fragrant and warming Thai inspired soup made with creamy coconut milk, lemongrass, and tender chicken. This bold and aromatic soup balances spice, sweetness, and tang perfectly.','Fragrant Thai coconut broth soup with lemongrass, ginger, and chicken.','Thai','Easy',15,25,40,4,390,28,14,26,2,'[{"amount":1,"unit":"lb","item":"boneless chicken breast thinly sliced","group":"protein"},{"amount":2,"unit":"cans","item":"full fat coconut milk","group":"base"},{"amount":2,"unit":"cups","item":"chicken broth","group":"base"},{"amount":2,"unit":"stalks","item":"lemongrass bruised and cut into pieces","group":"aromatics"},{"amount":1,"unit":"inch","item":"fresh galangal or ginger sliced","group":"aromatics"},{"amount":3,"unit":"tbsp","item":"fish sauce","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"seasoning"},{"amount":2,"unit":"tsp","item":"red curry paste","group":"seasoning"},{"amount":1,"unit":"cup","item":"mushrooms sliced","group":"vegetables"},{"amount":3,"unit":"whole","item":"Thai bird chiles lightly crushed","group":"aromatics"}]','[{"title":"Infuse the Broth","text":"Combine the coconut milk and chicken broth in a large pot over medium heat. Add the lemongrass, galangal, and Thai chiles. Bring to a gentle simmer and cook for 10 minutes to infuse the aromatics.","timer":600},{"title":"Add Curry Paste","text":"Stir in the red curry paste and fish sauce, mixing well into the broth. Taste the base and adjust the level of spice by adding more curry paste if desired.","timer":120},{"title":"Cook the Chicken and Mushrooms","text":"Add the sliced chicken and mushrooms to the simmering broth. Cook for 8 to 10 minutes until the chicken is fully cooked through and no longer pink.","timer":600},{"title":"Finish with Lime","text":"Remove the lemongrass and galangal pieces from the soup. Stir in the fresh lime juice and taste for balance, adjusting with more fish sauce for saltiness or lime juice for tang.","timer":120},{"title":"Garnish and Serve","text":"Ladle the soup into bowls and garnish with fresh cilantro, thinly sliced green onions, and a wedge of lime. Serve immediately with steamed jasmine rice on the side.","timer":120}]','[{"original":"chicken breast","swap":"shrimp or firm tofu for different protein options"},{"original":"fish sauce","swap":"soy sauce or tamari for a vegetarian version"},{"original":"galangal","swap":"fresh ginger which is more widely available and similar in flavor"}]','["Boiling the soup vigorously after adding coconut milk which causes it to separate and look greasy","Leaving the lemongrass in the finished soup as it is too fibrous and woody to eat","Adding lime juice too early in the cooking process which turns the flavor bitter"]','["Thai","coconut","chicken","spicy","lemongrass","Asian","quick","gluten-free"]','["gluten-free","dairy-free"]','Soup and Stew','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Korean BBQ Short Ribs','korean-bbq-short-ribs','Tender flanken-cut beef short ribs marinated in a savory-sweet soy and sesame sauce then grilled to caramelized perfection. This classic Korean dish known as galbi delivers bold umami flavor in every bite.','Sweet and savory grilled beef short ribs marinated in a classic Korean galbi sauce.','Korean','Medium',20,15,35,4,520,38,22,32,1,'[{"amount":2,"unit":"lbs","item":"flanken-cut beef short ribs","group":"main"},{"amount":0.5,"unit":"cup","item":"soy sauce","group":"marinade"},{"amount":3,"unit":"tbsp","item":"brown sugar","group":"marinade"},{"amount":2,"unit":"tbsp","item":"sesame oil","group":"marinade"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"marinade"},{"amount":1,"unit":"tbsp","item":"fresh ginger grated","group":"marinade"},{"amount":2,"unit":"stalks","item":"green onions chopped","group":"garnish"},{"amount":1,"unit":"tbsp","item":"sesame seeds","group":"garnish"},{"amount":1,"unit":"medium","item":"Asian pear grated","group":"marinade"}]','[{"title":"Prepare the Marinade","text":"In a large bowl whisk together soy sauce, brown sugar, sesame oil, minced garlic, grated ginger, and grated Asian pear until the sugar fully dissolves. The pear acts as a natural tenderizer so do not skip it.","timer":0},{"title":"Marinate the Ribs","text":"Score the short ribs lightly between the bones and submerge them fully in the marinade. Cover and refrigerate for at least 4 hours or overnight for maximum flavor penetration.","timer":14400},{"title":"Preheat the Grill","text":"Heat your grill or grill pan to high heat. Brush the grates with a little oil to prevent sticking. Remove the ribs from the marinade and let any excess drip off before cooking.","timer":300},{"title":"Grill the Ribs","text":"Place the ribs on the hot grill and cook for 3 to 4 minutes per side until deeply caramelized with char marks. Do not move them too early or they will stick and tear.","timer":480},{"title":"Rest and Serve","text":"Transfer the grilled ribs to a platter and let them rest for 3 minutes. Garnish generously with chopped green onions and sesame seeds. Serve with steamed rice and kimchi.","timer":180}]','[{"original":"Asian pear","swap":"kiwi or grated regular pear"},{"original":"flanken-cut short ribs","swap":"English-cut short ribs thinly sliced"},{"original":"brown sugar","swap":"honey or mirin"}]','["Not marinating long enough which results in bland and tough ribs","Cooking on low heat which steams the meat instead of caramelizing it","Using thick-cut ribs that do not cook through properly on the grill"]','["korean","bbq","short ribs","grilled","galbi","beef","weekend cooking"]','["dairy-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Roasted Lamb Chops with Mint Pesto','roasted-lamb-chops-mint-pesto','Juicy bone-in lamb chops seasoned with garlic and herbs then roasted to a perfect medium and served with a vibrant fresh mint pesto. This elegant dish comes together quickly and impresses at any dinner table.','Herb-crusted roasted lamb chops paired with a bright and fresh homemade mint pesto.','Mediterranean','Medium',15,20,35,4,480,42,4,31,1,'[{"amount":8,"unit":"pieces","item":"bone-in lamb loin chops","group":"main"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"seasoning"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"seasoning"},{"amount":1,"unit":"tsp","item":"dried rosemary","group":"seasoning"},{"amount":1,"unit":"cup","item":"fresh mint leaves packed","group":"pesto"},{"amount":0.25,"unit":"cup","item":"pine nuts","group":"pesto"},{"amount":0.25,"unit":"cup","item":"grated Parmesan cheese","group":"pesto"},{"amount":3,"unit":"tbsp","item":"extra virgin olive oil","group":"pesto"},{"amount":1,"unit":"tbsp","item":"fresh lemon juice","group":"pesto"}]','[{"title":"Season the Lamb","text":"Pat the lamb chops dry with paper towels. Rub them all over with minced garlic, olive oil, rosemary, salt, and pepper. Let them sit at room temperature for 15 minutes to allow the seasoning to penetrate.","timer":900},{"title":"Make the Mint Pesto","text":"Combine fresh mint leaves, pine nuts, Parmesan, lemon juice, and a pinch of salt in a food processor. Pulse while slowly drizzling in the olive oil until a smooth but slightly textured sauce forms. Taste and adjust seasoning.","timer":0},{"title":"Sear the Chops","text":"Heat an oven-safe skillet over high heat until smoking. Sear the lamb chops for 2 minutes per side until a deep golden crust forms. Do not crowd the pan or the meat will steam instead of sear.","timer":240},{"title":"Finish in the Oven","text":"Transfer the skillet to a preheated 400F oven and roast for 6 to 8 minutes for medium doneness. Use a meat thermometer to confirm an internal temperature of 135F for medium.","timer":480},{"title":"Rest and Plate","text":"Remove the lamb chops from the oven and let them rest on a cutting board for 5 minutes. Plate the chops and spoon a generous dollop of mint pesto over each one before serving.","timer":300}]','[{"original":"pine nuts","swap":"walnuts or blanched almonds"},{"original":"Parmesan cheese","swap":"Pecorino Romano for a sharper flavor"},{"original":"lamb loin chops","swap":"rack of lamb cut into individual chops"}]','["Skipping the resting period which causes the juices to run out when cut","Not patting the lamb dry before searing which prevents a proper crust from forming","Overcooking the lamb past medium which makes it tough and gamey"]','["lamb","roasted","mint pesto","mediterranean","elegant","dinner party","gluten-free"]','["gluten-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Instant Pot Carnitas','instant-pot-carnitas','Succulent and crispy Mexican pulled pork made effortlessly in the Instant Pot with citrus, cumin, and warm spices. Finished under the broiler for irresistible crispy edges that make every taco unforgettable.','Tender citrus-spiced pulled pork pressure cooked then broiled for perfectly crispy carnitas.','Mexican','Easy',15,75,90,6,430,44,6,24,1,'[{"amount":3,"unit":"lbs","item":"pork shoulder cut into large chunks","group":"main"},{"amount":1,"unit":"medium","item":"orange juiced and zested","group":"liquid"},{"amount":1,"unit":"medium","item":"lime juiced","group":"liquid"},{"amount":4,"unit":"cloves","item":"garlic smashed","group":"aromatics"},{"amount":1,"unit":"tsp","item":"ground cumin","group":"spices"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"spices"},{"amount":1,"unit":"tsp","item":"dried oregano","group":"spices"},{"amount":0.5,"unit":"cup","item":"chicken broth","group":"liquid"},{"amount":1,"unit":"tsp","item":"chili powder","group":"spices"}]','[{"title":"Season the Pork","text":"In a small bowl mix cumin, smoked paprika, oregano, chili powder, salt, and pepper. Rub the spice blend all over the pork shoulder chunks ensuring every surface is well coated for maximum flavor.","timer":0},{"title":"Load the Instant Pot","text":"Place the seasoned pork into the Instant Pot. Add the smashed garlic, orange juice, orange zest, lime juice, and chicken broth. Do not add too much liquid or the pork will boil instead of braise.","timer":0},{"title":"Pressure Cook","text":"Seal the Instant Pot lid and set it to high pressure for 60 minutes. Allow the pressure to naturally release for 15 minutes before carefully switching to quick release to vent any remaining steam.","timer":4500},{"title":"Shred and Broil","text":"Transfer the pork to a baking sheet and shred it using two forks. Spoon several tablespoons of the cooking liquid over the meat to keep it moist. Broil on high for 5 to 7 minutes until the edges become golden and crispy.","timer":420},{"title":"Serve","text":"Remove from the broiler and give the carnitas a final toss so the crispy bits mix throughout. Serve immediately in warm corn tortillas with fresh cilantro, diced white onion, and salsa.","timer":0}]','[{"original":"pork shoulder","swap":"pork butt which has a similar fat content and texture"},{"original":"chicken broth","swap":"water with a splash of apple cider vinegar"},{"original":"orange juice","swap":"pineapple juice for a slightly sweeter and tangier profile"}]','["Skipping the broiling step which is essential for achieving the signature crispy texture","Adding too much liquid which dilutes the flavor and prevents proper braising","Not naturally releasing the pressure which can result in tougher and drier meat"]','["carnitas","mexican","instant pot","pressure cooker","tacos","pork","meal prep"]','["gluten-free","dairy-free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Salmon','garlic-butter-salmon','Pan-seared salmon fillets basted in a rich garlic herb butter sauce until perfectly flaky and golden. This quick and luxurious weeknight dinner is ready in under 25 minutes.','Crispy pan-seared salmon fillets finished in a fragrant garlic herb butter sauce.','American','Easy',5,15,20,4,390,36,2,26,0,'[{"amount":4,"unit":"fillets","item":"salmon skin-on about 6oz each","group":"main"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"cooking"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice","group":"sauce"},{"amount":1,"unit":"tsp","item":"fresh thyme leaves","group":"sauce"},{"amount":2,"unit":"tbsp","item":"fresh parsley chopped","group":"garnish"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"seasoning"}]','[{"title":"Prepare the Salmon","text":"Pat the salmon fillets completely dry with paper towels and season both sides generously with salt and pepper. Dry skin is the key to achieving a perfectly crispy crust so do not skip this step.","timer":0},{"title":"Sear Skin-Side Down","text":"Heat olive oil in a large skillet over medium-high heat until shimmering. Place the salmon skin-side down and press gently with a spatula for the first 30 seconds. Cook undisturbed for 5 to 6 minutes until the skin is deeply golden and crispy.","timer":360},{"title":"Flip and Add Butter","text":"Flip the salmon fillets carefully. Immediately add butter, minced garlic, thyme, and red pepper flakes to the pan. The butter will foam and sizzle around the fish.","timer":0},{"title":"Baste Continuously","text":"Tilt the pan slightly and use a spoon to continuously baste the salmon with the melted garlic butter for 2 to 3 minutes. This infuses the fish with flavor and finishes the cooking gently.","timer":180},{"title":"Finish and Serve","text":"Squeeze fresh lemon juice over the salmon and remove from heat. Plate the fillets and spoon extra garlic butter sauce from the pan over each one. Garnish with fresh parsley and serve immediately.","timer":0}]','[{"original":"unsalted butter","swap":"ghee for a higher smoke point and nutty flavor"},{"original":"fresh thyme","swap":"fresh dill which pairs beautifully with salmon"},{"original":"salmon","swap":"halibut or sea bass fillets of similar thickness"}]','["Not drying the salmon skin which results in steaming instead of crisping","Moving the salmon too early before the skin releases naturally from the pan","Overcooking the salmon which makes it dry and causes it to fall apart"]','["salmon","seafood","garlic butter","quick dinner","weeknight","pan seared","keto"]','["gluten-free","keto"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Beef Bolognese','classic-beef-bolognese','A deeply rich and slow-simmered Italian meat sauce made with ground beef, soffritto, tomatoes, and a splash of red wine. Tossed with fresh pasta this hearty sauce is pure comfort food at its finest.','Rich slow-cooked Italian meat sauce with ground beef tomatoes and red wine served over pasta.','Italian','Medium',20,90,110,6,540,32,52,18,4,'[{"amount":1.5,"unit":"lbs","item":"ground beef 80 percent lean","group":"main"},{"amount":1,"unit":"medium","item":"yellow onion finely diced","group":"soffritto"},{"amount":2,"unit":"stalks","item":"celery finely diced","group":"soffritto"},{"amount":2,"unit":"medium","item":"carrots finely diced","group":"soffritto"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":0.5,"unit":"cup","item":"dry red wine","group":"liquid"},{"amount":28,"unit":"oz","item":"crushed San Marzano tomatoes","group":"sauce"},{"amount":1,"unit":"lb","item":"tagliatelle or pappardelle pasta","group":"pasta"},{"amount":2,"unit":"tbsp","item":"tomato paste","group":"sauce"}]','[{"title":"Cook the Soffritto","text":"Heat olive oil in a heavy Dutch oven over medium heat. Add the diced onion, celery, and carrots with a pinch of salt and cook for 10 to 12 minutes stirring often until the vegetables are completely soft and lightly golden.","timer":720},{"title":"Brown the Meat","text":"Add minced garlic and tomato paste to the soffritto and stir for 1 minute. Increase heat to medium-high and add the ground beef breaking it up finely. Cook until no pink remains and the meat begins to brown at the bottom of the pot.","timer":600},{"title":"Deglaze and Add Tomatoes","text":"Pour in the red wine and scrape up all the browned bits from the bottom of the pot. Let the wine reduce by half then add the crushed tomatoes. Stir everything together and bring to a gentle simmer.","timer":300},{"title":"Slow Simmer","text":"Reduce heat to the lowest setting and simmer the sauce uncovered for at least 60 minutes stirring every 15 minutes. The sauce should thicken considerably and the fat should rise to the surface indicating the flavors have melded properly.","timer":3600},{"title":"Cook Pasta and Combine","text":"Cook the pasta in generously salted boiling water until al dente. Reserve 1 cup of pasta water before draining. Toss the pasta directly into the Bolognese sauce adding a splash of pasta water to bring everything together. Serve topped with Parmesan.","timer":600}]','[{"original":"ground beef","swap":"a mix of ground beef and ground pork for more richness"},{"original":"dry red wine","swap":"beef broth with a splash of balsamic vinegar"},{"original":"tagliatelle","swap":"rigatoni or any ridged pasta that holds thick sauces well"}]','["Rushing the simmer time which prevents the sauce from developing its deep rich flavor","Adding too much liquid which makes the sauce thin and watery instead of thick and clinging","Not reserving pasta water which is essential for adjusting the sauce consistency at the end"]','["bolognese","italian","pasta","beef","slow cooked","comfort food","sunday dinner"]','["dairy-free option"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Orange Chicken Copycat','orange-chicken-copycat','A crispy fried chicken dish coated in a sweet and tangy orange sauce. This homemade version rivals the famous fast food classic.','Crispy fried chicken tossed in a bold homemade orange sauce ready in under an hour.','Chinese-American','Medium',20,25,45,4,520,34,48,18,1,'[{"amount":1.5,"unit":"lb","item":"boneless skinless chicken thighs cut into chunks","group":"Chicken"},{"amount":1,"unit":"cup","item":"cornstarch","group":"Breading"},{"amount":2,"unit":"large","item":"eggs beaten","group":"Breading"},{"amount":0.5,"unit":"cup","item":"fresh orange juice","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"Sauce"},{"amount":3,"unit":"tbsp","item":"sugar","group":"Sauce"},{"amount":2,"unit":"tsp","item":"orange zest","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"Sauce"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"tbsp","item":"vegetable oil for frying","group":"Cooking"}]','[{"title":"Coat the Chicken","text":"Dip each piece of chicken into the beaten eggs then toss in cornstarch until fully coated. Shake off any excess cornstarch before frying.","timer":0},{"title":"Fry the Chicken","text":"Heat oil in a deep pan to 350 degrees F. Fry chicken pieces in batches for 4 to 5 minutes until golden and cooked through. Drain on a paper towel lined plate.","timer":300},{"title":"Make the Orange Sauce","text":"In a saucepan over medium heat combine orange juice soy sauce sugar orange zest rice vinegar and garlic. Stir and bring to a simmer.","timer":180},{"title":"Thicken the Sauce","text":"Mix 1 teaspoon of cornstarch with 2 teaspoons of water and stir into the sauce. Cook for 2 more minutes until the sauce thickens and coats the back of a spoon.","timer":120},{"title":"Toss and Serve","text":"Add the fried chicken to the sauce and toss until every piece is well coated. Serve immediately over steamed rice with green onions on top.","timer":0}]','[{"original":"chicken thighs","swap":"chicken breast for a leaner option"},{"original":"fresh orange juice","swap":"store bought orange juice in a pinch"},{"original":"rice vinegar","swap":"apple cider vinegar for a similar tang"}]','["Do not overcrowd the pan when frying or the chicken will steam instead of crisp","Do not skip the cornstarch coating as it creates the essential crispy texture","Do not let the sauce over reduce or it will become too thick and sticky"]','["orange chicken","copycat","fried chicken","takeout at home","Chinese American"]','["dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Air Fryer Chicken Wings','air-fryer-chicken-wings','Ultra crispy chicken wings made in the air fryer with no oil required. They come out perfectly golden and juicy every single time.','Perfectly crispy air fryer wings with simple seasoning ready in 30 minutes.','American','Easy',10,25,35,4,390,38,4,24,0,'[{"amount":2,"unit":"lb","item":"chicken wings split into drumettes and flats","group":"Chicken"},{"amount":1,"unit":"tsp","item":"baking powder","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"onion powder","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.5,"unit":"cup","item":"hot sauce for serving","group":"Sauce"}]','[{"title":"Dry and Season the Wings","text":"Pat the chicken wings completely dry with paper towels. In a large bowl toss the wings with baking powder garlic powder smoked paprika onion powder salt and pepper until evenly coated.","timer":0},{"title":"Preheat the Air Fryer","text":"Preheat your air fryer to 400 degrees F for 5 minutes. This step ensures the wings start cooking immediately and get crispier faster.","timer":300},{"title":"Air Fry the Wings","text":"Arrange wings in a single layer in the air fryer basket. Do not overlap them. Cook at 400 degrees F for 12 minutes then flip each wing.","timer":720},{"title":"Flip and Finish Cooking","text":"After flipping continue cooking for another 10 to 13 minutes until the wings are deeply golden and the skin is visibly crispy.","timer":780},{"title":"Sauce and Serve","text":"Toss the hot wings in your favorite sauce immediately or serve them plain alongside dipping sauces. Serve right away for maximum crunch.","timer":0}]','[{"original":"smoked paprika","swap":"regular paprika or cayenne for more heat"},{"original":"hot sauce","swap":"honey garlic sauce for a sweet alternative"},{"original":"baking powder","swap":"do not substitute this as it is key to crispiness"}]','["Do not skip drying the wings as moisture prevents the skin from getting crispy","Do not overcrowd the air fryer basket or the wings will not crisp evenly","Do not skip the baking powder as it raises the pH of the skin and promotes browning"]','["air fryer","chicken wings","crispy","game day","easy"]','["gluten-free","dairy-free","low-carb"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Balsamic Glazed Chicken','balsamic-glazed-chicken','Tender pan seared chicken breasts finished in a rich sticky balsamic reduction. It is an elegant yet simple weeknight dinner.','Juicy chicken breasts coated in a sweet savory balsamic glaze ready in 30 minutes.','Italian-American','Easy',10,20,30,4,310,42,12,8,0,'[{"amount":4,"unit":"medium","item":"boneless skinless chicken breasts","group":"Chicken"},{"amount":0.5,"unit":"cup","item":"balsamic vinegar","group":"Glaze"},{"amount":2,"unit":"tbsp","item":"honey","group":"Glaze"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"tsp","item":"Dijon mustard","group":"Glaze"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"Cooking"},{"amount":0.5,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"dried Italian seasoning","group":"Seasoning"}]','[{"title":"Season the Chicken","text":"Pat the chicken breasts dry and season both sides generously with salt pepper and Italian seasoning. This builds the base flavor before the glaze is added.","timer":0},{"title":"Sear the Chicken","text":"Heat olive oil in a large skillet over medium high heat. Add the chicken and sear for 5 to 6 minutes per side until golden brown. Remove from the pan and set aside.","timer":360},{"title":"Build the Glaze","text":"In the same pan reduce heat to medium and add garlic. Cook for 30 seconds then pour in balsamic vinegar honey and Dijon mustard. Stir to combine.","timer":30},{"title":"Reduce and Glaze","text":"Let the sauce simmer for 3 to 4 minutes stirring occasionally until it thickens and coats the back of a spoon. Return the chicken to the pan and spoon the glaze over each piece.","timer":240},{"title":"Finish and Serve","text":"Cook the chicken in the glaze for 2 more minutes until fully cooked through and well coated. Serve over mashed potatoes or roasted vegetables with extra glaze drizzled on top.","timer":120}]','[{"original":"honey","swap":"maple syrup for a different kind of sweetness"},{"original":"Dijon mustard","swap":"whole grain mustard for added texture"},{"original":"chicken breasts","swap":"chicken thighs for a richer and more forgiving cut"}]','["Do not skip searing the chicken as the brown crust adds critical depth of flavor","Do not rush the glaze reduction or it will be too thin to stick to the chicken","Do not overcook the chicken or it will become dry especially with breast meat"]','["balsamic","glazed chicken","weeknight dinner","Italian inspired","pan seared"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Butter Chicken Thighs','honey-garlic-butter-chicken-thighs','Juicy bone in chicken thighs cooked in a rich honey garlic butter sauce that caramelizes beautifully. This one pan meal is incredibly flavorful and easy to clean up.','Sticky honey garlic butter chicken thighs made in one pan in under 40 minutes.','American','Easy',10,30,40,4,460,36,18,26,0,'[{"amount":4,"unit":"pieces","item":"bone in skin on chicken thighs","group":"Chicken"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":3,"unit":"tbsp","item":"honey","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"Cooking"},{"amount":0.5,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"fresh thyme leaves","group":"Garnish"}]','[{"title":"Season the Chicken","text":"Pat the chicken thighs completely dry with paper towels. Season both sides with salt and pepper. Dry skin is essential for getting a properly seared golden crust.","timer":0},{"title":"Sear Skin Side Down","text":"Heat olive oil in an oven safe skillet over medium high heat. Place chicken skin side down and cook undisturbed for 7 to 8 minutes until the skin is deep golden and crispy.","timer":480},{"title":"Flip and Add Sauce","text":"Flip the chicken and reduce heat to medium. Add butter and garlic to the pan and cook for 1 minute. Pour in honey and soy sauce and stir to combine around the chicken.","timer":60},{"title":"Bake in the Oven","text":"Transfer the skillet to a preheated 400 degree F oven. Bake for 15 to 18 minutes until the chicken reaches an internal temperature of 165 degrees F and the glaze is caramelized.","timer":1080},{"title":"Rest and Serve","text":"Remove from the oven and let the chicken rest for 5 minutes. Spoon the pan sauce over each thigh and garnish with fresh thyme. Serve with rice or steamed broccoli.","timer":300}]','[{"original":"bone in skin on thighs","swap":"boneless thighs for faster cooking"},{"original":"honey","swap":"agave syrup for a vegan sweetener option"},{"original":"soy sauce","swap":"coconut aminos for a gluten free alternative"}]','["Do not move the chicken while it sears or you will tear the skin and lose the crust","Do not skip resting the chicken or the juices will run out when you cut into it","Do not use a non oven safe pan as it will damage the pan and ruin the recipe"]','["honey garlic","chicken thighs","one pan","weeknight","butter sauce"]','["gluten-free option","dairy-free option"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Herb Roasted Chicken','lemon-herb-roasted-chicken','A classic whole roasted chicken infused with bright lemon and fresh herbs for a deeply savory result. The skin comes out crackling crisp while the meat stays incredibly juicy.','Classic herb and lemon roasted whole chicken with crispy skin and tender juicy meat.','American','Medium',15,75,90,6,410,48,3,22,0,'[{"amount":4,"unit":"lb","item":"whole chicken patted dry","group":"Chicken"},{"amount":4,"unit":"tbsp","item":"unsalted butter softened","group":"Herb Butter"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Herb Butter"},{"amount":1,"unit":"tbsp","item":"fresh rosemary chopped","group":"Herb Butter"},{"amount":1,"unit":"tbsp","item":"fresh thyme leaves","group":"Herb Butter"},{"amount":1,"unit":"large","item":"lemon halved","group":"Aromatics"},{"amount":1,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"Cooking"}]','[{"title":"Make the Herb Butter","text":"In a small bowl mix together softened butter garlic rosemary thyme salt and pepper until fully combined. This compound butter is the key to flavorful crispy skin.","timer":0},{"title":"Prep the Chicken","text":"Pat the chicken completely dry inside and out. Carefully loosen the skin over the breasts and thighs without tearing it. Rub half the herb butter directly under the skin and the other half all over the outside.","timer":0},{"title":"Stuff and Truss","text":"Stuff both lemon halves into the cavity of the chicken. Tie the legs together with kitchen twine and tuck the wing tips under. Drizzle olive oil over the top and season lightly with extra salt.","timer":0},{"title":"Roast the Chicken","text":"Place the chicken breast side up in a roasting pan. Roast at 425 degrees F for 60 to 75 minutes until the skin is deep golden and a thermometer inserted into the thickest part of the thigh reads 165 degrees F.","timer":4500},{"title":"Rest and Carve","text":"Remove the chicken from the oven and let it rest uncovered for at least 10 minutes before carving. Resting allows the juices to redistribute so every slice is perfectly moist.","timer":600}]','[{"original":"fresh rosemary","swap":"dried rosemary using half the amount"},{"original":"whole chicken","swap":"bone in chicken pieces with reduced cook time"},{"original":"unsalted butter","swap":"olive oil for a dairy free herb rub"}]','["Do not skip drying the chicken as surface moisture creates steam and prevents crispy skin","Do not carve the chicken immediately out of the oven or all the juices will escape","Do not roast at a low temperature as high heat is essential for properly rendered crispy skin"]','["roasted chicken","lemon herb","whole chicken","Sunday dinner","classic"]','["gluten-free"]','Main Course','ai');